interface RateLimiterOptions {
  maxTokens: number;
  refillRate: number;
  refillIntervalMs: number;
}

class RateLimiter {
  private readonly maxTokens: number;
  private readonly refillRate: number;
  private readonly refillIntervalMs: number;
  private tokens: number;
  private lastRefillTime: number;

  constructor(options: RateLimiterOptions) {
    if (options.maxTokens <= 0) throw new RangeError("maxTokens must be > 0");
    if (options.refillRate <= 0) throw new RangeError("refillRate must be > 0");
    if (options.refillIntervalMs <= 0) throw new RangeError("refillIntervalMs must be > 0");

    this.maxTokens = options.maxTokens;
    this.refillRate = options.refillRate;
    this.refillIntervalMs = options.refillIntervalMs;
    this.tokens = options.maxTokens;
    this.lastRefillTime = Date.now();
  }

  private refill(): void {
    const now = Date.now();
    const elapsed = now - this.lastRefillTime;
    const intervals = Math.floor(elapsed / this.refillIntervalMs);

    if (intervals > 0) {
      this.tokens = Math.min(this.maxTokens, this.tokens + intervals * this.refillRate);
      this.lastRefillTime += intervals * this.refillIntervalMs;
    }
  }

  tryConsume(tokens: number = 1): boolean {
    if (tokens <= 0) throw new RangeError("tokens must be > 0");
    if (tokens > this.maxTokens) return false;

    this.refill();

    if (this.tokens >= tokens) {
      this.tokens -= tokens;
      return true;
    }

    return false;
  }

  getTokens(): number {
    this.refill();
    return this.tokens;
  }

  reset(): void {
    this.tokens = this.maxTokens;
    this.lastRefillTime = Date.now();
  }

  waitForTokens(tokens: number = 1): Promise<void> {
    if (tokens <= 0) return Promise.reject(new RangeError("tokens must be > 0"));
    if (tokens > this.maxTokens) return Promise.reject(new RangeError("tokens exceeds maxTokens"));

    return new Promise((resolve) => {
      const attempt = (): void => {
        if (this.tryConsume(tokens)) {
          resolve();
          return;
        }

        this.refill();
        const deficit = tokens - this.tokens;
        const intervalsNeeded = Math.ceil(deficit / this.refillRate);
        const delay = Math.max(1, intervalsNeeded * this.refillIntervalMs);

        setTimeout(attempt, delay);
      };

      attempt();
    });
  }
}

export default RateLimiter;

type CronResult = {
  minute: number[];
  hour: number[];
  dayOfMonth: number[];
  month: number[];
  dayOfWeek: number[];
};

type FieldRange = { min: number; max: number };

const FIELD_RANGES: Record<keyof CronResult, FieldRange> = {
  minute: { min: 0, max: 59 },
  hour: { min: 0, max: 23 },
  dayOfMonth: { min: 1, max: 31 },
  month: { min: 1, max: 12 },
  dayOfWeek: { min: 0, max: 7 },
};

const clamp = (value: number, min: number, max: number): number =>
  Math.min(Math.max(value, min), max);

const expandRange = (start: number, end: number, step: number): number[] => {
  if (start > end) throw new RangeError(`Invalid range: ${start}-${end}`);
  const result: number[] = [];
  for (let i = start; i <= end; i += step) result.push(i);
  return result;
};

const deduplicateAndSort = (values: number[]): number[] =>
  [...new Set(values)].sort((a, b) => a - b);

const validateValue = (value: number, range: FieldRange, context: string): void => {
  if (!Number.isInteger(value) || value < range.min || value > range.max) {
    throw new RangeError(
      `Value ${value} out of range [${range.min}-${range.max}] in field "${context}"`
    );
  }
};

const parseSegment = (segment: string, range: FieldRange, fieldName: string): number[] => {
  const { min, max } = range;

  // Step value: */step or start-end/step
  if (segment.includes("/")) {
    const [rangePart, stepPart] = segment.split("/");
    const step = parseInt(stepPart, 10);
    if (isNaN(step) || step <= 0) {
      throw new SyntaxError(`Invalid step value "${stepPart}" in field "${fieldName}"`);
    }

    if (rangePart === "*") {
      return expandRange(min, max, step);
    }

    if (rangePart.includes("-")) {
      const [startStr, endStr] = rangePart.split("-");
      const start = parseInt(startStr, 10);
      const end = parseInt(endStr, 10);
      if (isNaN(start) || isNaN(end)) {
        throw new SyntaxError(`Invalid range "${rangePart}" in field "${fieldName}"`);
      }
      validateValue(start, range, fieldName);
      validateValue(end, range, fieldName);
      return expandRange(start, end, step);
    }

    throw new SyntaxError(`Invalid step expression "${segment}" in field "${fieldName}"`);
  }

  // Wildcard
  if (segment === "*") {
    return expandRange(min, max, 1);
  }

  // Range: start-end
  if (segment.includes("-")) {
    const [startStr, endStr] = segment.split("-");
    const start = parseInt(startStr, 10);
    const end = parseInt(endStr, 10);
    if (isNaN(start) || isNaN(end)) {
      throw new SyntaxError(`Invalid range "${segment}" in field "${fieldName}"`);
    }
    validateValue(start, range, fieldName);
    validateValue(end, range, fieldName);
    return expandRange(start, end, 1);
  }

  // Plain number
  const value = parseInt(segment, 10);
  if (isNaN(value)) {
    throw new SyntaxError(`Invalid value "${segment}" in field "${fieldName}"`);
  }
  validateValue(value, range, fieldName);
  return [value];
};

const parseField = (expression: string, range: FieldRange, fieldName: string): number[] => {
  const segments = expression.split(",");
  const values = segments.flatMap((segment) => parseSegment(segment.trim(), range, fieldName));
  const result = deduplicateAndSort(values);

  // Normalize dayOfWeek: treat 7 as Sunday (0)
  if (fieldName === "dayOfWeek") {
    return deduplicateAndSort(result.map((v) => (v === 7 ? 0 : v)));
  }

  return result;
};

const parseCron = (expression: string): CronResult => {
  const trimmed = expression.trim().replace(/\s+/g, " ");
  const parts = trimmed.split(" ");

  if (parts.length !== 5) {
    throw new SyntaxError(
      `Cron expression must have exactly 5 fields, got ${parts.length}: "${expression}"`
    );
  }

  const [minuteExpr, hourExpr, dayOfMonthExpr, monthExpr, dayOfWeekExpr] = parts;
  const fieldNames = Object.keys(FIELD_RANGES) as (keyof CronResult)[];
  const expressions = [minuteExpr, hourExpr, dayOfMonthExpr, monthExpr, dayOfWeekExpr];

  const result = {} as CronResult;
  for (let i = 0; i < fieldNames.length; i++) {
    const fieldName = fieldNames[i];
    result[fieldName] = parseField(expressions[i], FIELD_RANGES[fieldName], fieldName);
  }

  return result;
};

export default parseCron;

interface RateLimiterOptions {
  maxTokens: number;
  refillRate: number;
  refillIntervalMs: number;
}

export default class RateLimiter {
  private readonly maxTokens: number;
  private readonly refillRate: number;
  private readonly refillIntervalMs: number;
  private currentTokens: number;
  private lastRefillTime: number;

  constructor(options: RateLimiterOptions) {
    if (!Number.isFinite(options.maxTokens) || options.maxTokens <= 0) {
      throw new RangeError("maxTokens must be a finite positive number");
    }
    if (!Number.isFinite(options.refillRate) || options.refillRate < 0) {
      throw new RangeError("refillRate must be a finite non-negative number");
    }
    if (!Number.isFinite(options.refillIntervalMs) || options.refillIntervalMs <= 0) {
      throw new RangeError("refillIntervalMs must be a finite positive number");
    }

    this.maxTokens = options.maxTokens;
    this.refillRate = options.refillRate;
    this.refillIntervalMs = options.refillIntervalMs;
    this.currentTokens = options.maxTokens;
    this.lastRefillTime = Date.now();
  }

  private applyRefill(): void {
    const now = Date.now();
    const elapsed = now - this.lastRefillTime;

    if (elapsed < this.refillIntervalMs || this.refillRate === 0) {
      return;
    }

    const completedIntervals = Math.floor(elapsed / this.refillIntervalMs);
    const tokensToAdd = completedIntervals * this.refillRate;

    this.currentTokens = Math.min(this.maxTokens, this.currentTokens + tokensToAdd);
    // Advance lastRefillTime by whole intervals to avoid drift accumulation
    this.lastRefillTime += completedIntervals * this.refillIntervalMs;
  }

  tryConsume(tokens: number = 1): boolean {
    if (!Number.isFinite(tokens) || tokens < 0) {
      throw new RangeError("tokens must be a finite non-negative number");
    }
    if (tokens === 0) return true;
    if (tokens > this.maxTokens) return false;

    this.applyRefill();

    if (this.currentTokens >= tokens) {
      this.currentTokens -= tokens;
      return true;
    }

    return false;
  }

  getTokens(): number {
    this.applyRefill();
    return this.currentTokens;
  }

  reset(): void {
    this.currentTokens = this.maxTokens;
    this.lastRefillTime = Date.now();
  }

  waitForTokens(tokens: number = 1): Promise<void> {
    if (!Number.isFinite(tokens) || tokens < 0) {
      return Promise.reject(new RangeError("tokens must be a finite non-negative number"));
    }
    if (tokens === 0) return Promise.resolve();
    if (tokens > this.maxTokens) {
      return Promise.reject(
        new RangeError(
          `Requested ${tokens} tokens exceeds bucket capacity of ${this.maxTokens} — will never be satisfiable`
        )
      );
    }
    if (this.refillRate === 0 && this.currentTokens < tokens) {
      return Promise.reject(
        new Error(
          `Cannot wait for ${tokens} tokens: refillRate is 0 and current tokens (${this.currentTokens}) are insufficient`
        )
      );
    }

    return new Promise<void>((resolve) => {
      const attempt = (): void => {
        if (this.tryConsume(tokens)) {
          resolve();
          return;
        }

        // Recalculate after a lazy refill for an accurate scheduling estimate
        this.applyRefill();
        const deficit = tokens - this.currentTokens;
        const intervalsRequired = Math.ceil(deficit / this.refillRate);
        const msUntilNextInterval =
          this.refillIntervalMs - (Date.now() - this.lastRefillTime);
        // Wait until we expect to have accumulated enough tokens
        const waitMs = Math.max(
          1,
          msUntilNextInterval + (intervalsRequired - 1) * this.refillIntervalMs
        );

        setTimeout(attempt, waitMs);
      };

      attempt();
    });
  }
}

export class RateLimiter {
  private readonly maxTokens: number;
  private readonly refillRate: number;
  private readonly refillIntervalMs: number;
  private currentTokens: number;
  private lastRefillTime: number;
  private readonly waitQueue: Array<{ tokens: number; resolve: () => void }>;
  private refillCheckScheduled: boolean;

  constructor(options: {
    maxTokens: number;
    refillRate: number;
    refillIntervalMs: number;
  }) {
    if (!Number.isFinite(options.maxTokens) || options.maxTokens <= 0) {
      throw new RangeError("maxTokens must be a positive finite number");
    }
    if (!Number.isFinite(options.refillRate) || options.refillRate < 0) {
      throw new RangeError("refillRate must be a non-negative finite number");
    }
    if (!Number.isFinite(options.refillIntervalMs) || options.refillIntervalMs <= 0) {
      throw new RangeError("refillIntervalMs must be a positive finite number");
    }

    this.maxTokens = options.maxTokens;
    this.refillRate = options.refillRate;
    this.refillIntervalMs = options.refillIntervalMs;
    this.currentTokens = options.maxTokens;
    this.lastRefillTime = Date.now();
    this.waitQueue = [];
    this.refillCheckScheduled = false;
  }

  private applyRefill(): void {
    if (this.refillRate === 0) return;
    const now = Date.now();
    const elapsed = now - this.lastRefillTime;
    if (elapsed <= 0) return;
    const tokensToAdd = (elapsed / this.refillIntervalMs) * this.refillRate;
    this.currentTokens = Math.min(this.maxTokens, this.currentTokens + tokensToAdd);
    this.lastRefillTime = now;
  }

  tryConsume(tokens = 1): boolean {
    if (!Number.isFinite(tokens) || tokens < 0) {
      throw new RangeError("tokens must be a non-negative finite number");
    }
    // A request that can never be satisfied even at full capacity must always fail.
    if (tokens > this.maxTokens) return false;

    this.applyRefill();

    if (this.currentTokens >= tokens) {
      this.currentTokens -= tokens;
      return true;
    }
    return false;
  }

  getTokens(): number {
    this.applyRefill();
    return this.currentTokens;
  }

  reset(): void {
    this.currentTokens = this.maxTokens;
    this.lastRefillTime = Date.now();
    // Unblock any queued waiters now that the bucket is full.
    this.drainQueue();
  }

  waitForTokens(tokens = 1): Promise<void> {
    if (!Number.isFinite(tokens) || tokens < 0) {
      return Promise.reject(new RangeError("tokens must be a non-negative finite number"));
    }
    // A request exceeding maxTokens can never be fulfilled — reject eagerly rather
    // than parking a waiter that will block the queue forever.
    if (tokens > this.maxTokens) {
      return Promise.reject(
        new RangeError(
          `Requested tokens (${tokens}) exceed maxTokens (${this.maxTokens}) and can never be satisfied`
        )
      );
    }

    this.applyRefill();

    // Fast path: no competing waiters and sufficient tokens available right now.
    if (this.waitQueue.length === 0 && this.currentTokens >= tokens) {
      this.currentTokens -= tokens;
      return Promise.resolve();
    }

    // Slow path: park behind any existing waiters to preserve FIFO fairness.
    return new Promise<void>((resolve) => {
      this.waitQueue.push({ tokens, resolve });
      this.scheduleNextCheck();
    });
  }

  // Drain the front of the wait queue as long as tokens are available.
  // Operates FIFO: a large waiter at the front blocks smaller ones behind it
  // (prevents starvation of large requests by a flood of small ones).
  private drainQueue(): void {
    while (this.waitQueue.length > 0) {
      const front = this.waitQueue[0];
      if (this.currentTokens < front.tokens) break;
      this.currentTokens -= front.tokens;
      this.waitQueue.shift();
      front.resolve();
    }
  }

  private scheduleNextCheck(): void {
    // Only one pending timer at a time.
    if (this.refillCheckScheduled || this.waitQueue.length === 0) return;

    // If the refill rate is zero, tokens will never accumulate on their own;
    // the queue can only be unblocked via reset(). No timer needed.
    if (this.refillRate === 0) return;

    const front = this.waitQueue[0];
    const deficit = Math.max(0, front.tokens - this.currentTokens);
    // How long until the front waiter's deficit is covered by the refill rate.
    const msUntilReady = Math.ceil((deficit / this.refillRate) * this.refillIntervalMs);

    this.refillCheckScheduled = true;
    setTimeout(() => {
      this.refillCheckScheduled = false;
      this.applyRefill();
      this.drainQueue();
      // If the queue isn't empty yet (e.g. multiple waiters), keep scheduling.
      if (this.waitQueue.length > 0) {
        this.scheduleNextCheck();
      }
    }, msUntilReady);
  }
}

export default RateLimiter;

export interface CronExpression {
  minute: number[];
  hour: number[];
  dayOfMonth: number[];
  month: number[];
  dayOfWeek: number[];
}

const FIELD_ORDER = ["minute", "hour", "dayOfMonth", "month", "dayOfWeek"] as const;
type FieldName = (typeof FIELD_ORDER)[number];

const FIELD_RANGES: Record<FieldName, { min: number; max: number }> = {
  minute:     { min: 0,  max: 59 },
  hour:       { min: 0,  max: 23 },
  dayOfMonth: { min: 1,  max: 31 },
  month:      { min: 1,  max: 12 },
  dayOfWeek:  { min: 0,  max: 6  },
};

function parseIntStrict(value: string): number {
  const trimmed = value.trim();
  if (!/^\d+$/.test(trimmed)) {
    throw new Error(`Expected a non-negative integer, got "${value}"`);
  }
  return parseInt(trimmed, 10);
}

function assertInBounds(value: number, min: number, max: number, context: string): void {
  if (value < min || value > max) {
    throw new Error(`Value ${value} in "${context}" is out of valid range [${min}, ${max}]`);
  }
}

function expandSteppedRange(start: number, end: number, step: number): number[] {
  if (step <= 0) {
    throw new Error(`Step must be a positive integer, got ${step}`);
  }
  const values: number[] = [];
  for (let i = start; i <= end; i += step) {
    values.push(i);
  }
  return values;
}

function parseSegment(segment: string, min: number, max: number): number[] {
  const s = segment.trim();

  if (!s) {
    throw new Error("Encountered an empty segment");
  }

  // Wildcard: *
  if (s === "*") {
    return expandSteppedRange(min, max, 1);
  }

  // Step on wildcard: */N
  if (/^\*\/\d+$/.test(s)) {
    const step = parseIntStrict(s.slice(2));
    return expandSteppedRange(min, max, step);
  }

  // Range with optional step: N-M or N-M/S
  const rangeMatch = s.match(/^(\d+)-(\d+)(?:\/(\d+))?$/);
  if (rangeMatch) {
    const start = parseIntStrict(rangeMatch[1]);
    const end   = parseIntStrict(rangeMatch[2]);
    const step  = rangeMatch[3] !== undefined ? parseIntStrict(rangeMatch[3]) : 1;

    assertInBounds(start, min, max, s);
    assertInBounds(end,   min, max, s);

    if (start > end) {
      throw new Error(`Range start ${start} exceeds end ${end} in "${s}"`);
    }

    return expandSteppedRange(start, end, step);
  }

  // Plain number: N
  if (/^\d+$/.test(s)) {
    const n = parseIntStrict(s);
    assertInBounds(n, min, max, s);
    return [n];
  }

  throw new Error(`Unrecognized segment syntax: "${s}"`);
}

function parseField(field: string, min: number, max: number): number[] {
  const parts = field.split(",");

  if (parts.some((p) => p.trim() === "")) {
    throw new Error(`Malformed list (empty element) in "${field}"`);
  }

  const seen = new Set<number>();

  for (const part of parts) {
    for (const v of parseSegment(part, min, max)) {
      seen.add(v);
    }
  }

  return [...seen].sort((a, b) => a - b);
}

export default function parseCron(expression: string): CronExpression {
  if (typeof expression !== "string") {
    throw new TypeError(`Cron expression must be a string, got ${typeof expression}`);
  }

  const trimmed = expression.trim();

  if (!trimmed) {
    throw new Error("Cron expression must not be empty");
  }

  const fields = trimmed.split(/\s+/);

  if (fields.length !== 5) {
    throw new Error(
      `Cron expression must have exactly 5 fields (minute hour dayOfMonth month dayOfWeek), got ${fields.length}`
    );
  }

  const result = {} as CronExpression;

  for (let i = 0; i < FIELD_ORDER.length; i++) {
    const name = FIELD_ORDER[i];
    const { min, max } = FIELD_RANGES[name];

    try {
      result[name] = parseField(fields[i], min, max);
    } catch (err) {
      throw new Error(
        `Invalid ${name} field ("${fields[i]}"): ${(err as Error).message}`
      );
    }
  }

  return result;
}

interface CronFields {
  minute: number[];
  hour: number[];
  dayOfMonth: number[];
  month: number[];
  dayOfWeek: number[];
}

const FIELD_RANGES: Record<keyof CronFields, { min: number; max: number }> = {
  minute:     { min: 0,  max: 59 },
  hour:       { min: 0,  max: 23 },
  dayOfMonth: { min: 1,  max: 31 },
  month:      { min: 1,  max: 12 },
  dayOfWeek:  { min: 0,  max: 6  },
};

const clamp = (value: number, min: number, max: number): number => {
  if (value < min || value > max) {
    throw new RangeError(`Value ${value} is out of range [${min}, ${max}]`);
  }
  return value;
};

const range = (start: number, end: number): number[] =>
  Array.from({ length: end - start + 1 }, (_, i) => start + i);

const parseSegment = (
  segment: string,
  min: number,
  max: number
): number[] => {
  // Wildcard
  if (segment === "*") {
    return range(min, max);
  }

  // Step value: */step or start-end/step
  if (segment.includes("/")) {
    const [rangePart, stepStr] = segment.split("/");
    const step = parseInt(stepStr, 10);

    if (isNaN(step) || step <= 0) {
      throw new Error(`Invalid step value: ${stepStr}`);
    }

    const [rangeStart, rangeEnd] =
      rangePart === "*"
        ? [min, max]
        : rangePart.includes("-")
          ? rangePart.split("-").map(Number)
          : [parseInt(rangePart, 10), max];

    if (isNaN(rangeStart) || isNaN(rangeEnd)) {
      throw new Error(`Invalid range in step expression: ${segment}`);
    }

    clamp(rangeStart, min, max);
    clamp(rangeEnd, min, max);

    if (rangeStart > rangeEnd) {
      throw new RangeError(`Range start ${rangeStart} exceeds end ${rangeEnd}`);
    }

    const values: number[] = [];
    for (let i = rangeStart; i <= rangeEnd; i += step) {
      values.push(i);
    }
    return values;
  }

  // Range: start-end
  if (segment.includes("-")) {
    const parts = segment.split("-");
    if (parts.length !== 2) {
      throw new Error(`Invalid range expression: ${segment}`);
    }
    const [start, end] = parts.map(Number);
    if (isNaN(start) || isNaN(end)) {
      throw new Error(`Non-numeric range values in: ${segment}`);
    }
    clamp(start, min, max);
    clamp(end, min, max);
    if (start > end) {
      throw new RangeError(`Range start ${start} exceeds end ${end}`);
    }
    return range(start, end);
  }

  // Single number
  const value = parseInt(segment, 10);
  if (isNaN(value)) {
    throw new Error(`Invalid cron segment: ${segment}`);
  }
  clamp(value, min, max);
  return [value];
};

const parseField = (
  expression: string,
  min: number,
  max: number
): number[] => {
  const segments = expression.split(",");
  const values = new Set<number>();

  for (const segment of segments) {
    const parsed = parseSegment(segment.trim(), min, max);
    for (const v of parsed) {
      values.add(v);
    }
  }

  return Array.from(values).sort((a, b) => a - b);
};

const parseCron = (expression: string): CronFields => {
  const fields = expression.trim().split(/\s+/);

  if (fields.length !== 5) {
    throw new Error(
      `Invalid cron expression: expected 5 fields, got ${fields.length}`
    );
  }

  const [minuteExpr, hourExpr, dayOfMonthExpr, monthExpr, dayOfWeekExpr] =
    fields;

  const fieldKeys = Object.keys(FIELD_RANGES) as (keyof CronFields)[];
  const expressions = [
    minuteExpr,
    hourExpr,
    dayOfMonthExpr,
    monthExpr,
    dayOfWeekExpr,
  ];

  const result = {} as CronFields;

  for (let i = 0; i < fieldKeys.length; i++) {
    const key = fieldKeys[i];
    const { min, max } = FIELD_RANGES[key];
    result[key] = parseField(expressions[i], min, max);
  }

  return result;
};

export default parseCron;

interface RateLimiterOptions {
  maxTokens: number;
  refillRate: number;
  refillIntervalMs: number;
}

interface Waiter {
  tokens: number;
  resolve: () => void;
  reject: (err: Error) => void;
  timeoutId?: ReturnType<typeof setTimeout>;
}

class RateLimiter {
  private readonly maxTokens: number;
  private readonly refillRate: number;
  private readonly refillIntervalMs: number;
  private currentTokens: number;
  private lastRefillTime: number;
  private readonly waiters: Waiter[];

  constructor(options: RateLimiterOptions) {
    const { maxTokens, refillRate, refillIntervalMs } = options;

    if (!Number.isFinite(maxTokens) || maxTokens <= 0) {
      throw new RangeError(`maxTokens must be a positive finite number, got ${maxTokens}`);
    }
    if (!Number.isFinite(refillRate) || refillRate < 0) {
      throw new RangeError(`refillRate must be a non-negative finite number, got ${refillRate}`);
    }
    if (!Number.isFinite(refillIntervalMs) || refillIntervalMs <= 0) {
      throw new RangeError(`refillIntervalMs must be a positive finite number, got ${refillIntervalMs}`);
    }

    this.maxTokens = maxTokens;
    this.refillRate = refillRate;
    this.refillIntervalMs = refillIntervalMs;
    this.currentTokens = maxTokens;
    this.lastRefillTime = Date.now();
    this.waiters = [];
  }

  private lazyRefill(): void {
    const now = Date.now();
    const elapsed = now - this.lastRefillTime;

    if (elapsed > 0 && this.refillRate > 0) {
      const tokensToAdd = (elapsed / this.refillIntervalMs) * this.refillRate;
      this.currentTokens = Math.min(this.maxTokens, this.currentTokens + tokensToAdd);
    }

    this.lastRefillTime = now;
  }

  private msUntilSatisfied(requested: number): number {
    if (this.currentTokens >= requested) return 0;
    if (this.refillRate <= 0) return Infinity;

    const deficit = requested - this.currentTokens;
    return Math.ceil((deficit / this.refillRate) * this.refillIntervalMs);
  }

  private processQueue(): void {
    while (this.waiters.length > 0) {
      const waiter = this.waiters[0]!;

      this.lazyRefill();

      if (this.currentTokens >= waiter.tokens) {
        this.currentTokens -= waiter.tokens;
        this.waiters.shift();
        if (waiter.timeoutId !== undefined) clearTimeout(waiter.timeoutId);
        waiter.resolve();
      } else {
        const delay = this.msUntilSatisfied(waiter.tokens);

        if (delay === Infinity) {
          this.waiters.shift();
          if (waiter.timeoutId !== undefined) clearTimeout(waiter.timeoutId);
          waiter.reject(new Error('Refill is disabled; this request can never be satisfied'));
        } else {
          if (waiter.timeoutId !== undefined) clearTimeout(waiter.timeoutId);
          waiter.timeoutId = setTimeout(() => this.processQueue(), delay);
        }
        break;
      }
    }
  }

  private validateTokenCount(tokens: number, label = 'tokens'): void {
    if (!Number.isFinite(tokens) || tokens < 0) {
      throw new RangeError(`${label} must be a non-negative finite number, got ${tokens}`);
    }
  }

  tryConsume(tokens: number = 1): boolean {
    this.validateTokenCount(tokens);

    if (tokens === 0) return true;
    if (tokens > this.maxTokens) return false;

    this.lazyRefill();

    if (this.currentTokens >= tokens) {
      this.currentTokens -= tokens;
      return true;
    }

    return false;
  }

  getTokens(): number {
    this.lazyRefill();
    return this.currentTokens;
  }

  reset(): void {
    this.currentTokens = this.maxTokens;
    this.lastRefillTime = Date.now();
    this.processQueue();
  }

  waitForTokens(tokens: number = 1): Promise<void> {
    try {
      this.validateTokenCount(tokens);
    } catch (err) {
      return Promise.reject(err);
    }

    if (tokens === 0) return Promise.resolve();

    if (tokens > this.maxTokens) {
      return Promise.reject(
        new RangeError(
          `Requested ${tokens} tokens exceeds maxTokens (${this.maxTokens}); can never be satisfied`
        )
      );
    }

    this.lazyRefill();

    if (this.waiters.length === 0 && this.currentTokens >= tokens) {
      this.currentTokens -= tokens;
      return Promise.resolve();
    }

    return new Promise<void>((resolve, reject) => {
      const waiter: Waiter = { tokens, resolve, reject };
      this.waiters.push(waiter);

      if (this.waiters.length === 1) {
        const delay = this.msUntilSatisfied(tokens);

        if (delay === Infinity) {
          this.waiters.pop();
          reject(new Error('Refill is disabled; this request can never be satisfied'));
          return;
        }

        waiter.timeoutId = setTimeout(() => this.processQueue(), delay);
      }
    });
  }
}

