export interface CronExpression {
  minute: number[];
  hour: number[];
  dayOfMonth: number[];
  month: number[];
  dayOfWeek: number[];
}

const FIELD_RANGES: Record<keyof CronExpression, [number, number]> = {
  minute: [0, 59],
  hour: [0, 23],
  dayOfMonth: [1, 31],
  month: [1, 12],
  dayOfWeek: [0, 6],
};

function generateRange(start: number, end: number, step = 1): number[] {
  if (step < 1) throw new Error(`Step must be >= 1, got ${step}`);
  if (start > end) throw new Error(`Range start ${start} exceeds end ${end}`);
  const values: number[] = [];
  for (let i = start; i <= end; i += step) {
    values.push(i);
  }
  return values;
}

function validateRange(values: number[], min: number, max: number, field: string): number[] {
  for (const v of values) {
    if (v < min || v > max) {
      throw new Error(`Value ${v} out of range [${min}, ${max}] for field "${field}"`);
    }
  }
  return values;
}

function parseSegment(segment: string, min: number, max: number, field: string): number[] {
  // Wildcard
  if (segment === "*") {
    return generateRange(min, max);
  }

  // Step on wildcard: */n
  const stepWildcardMatch = segment.match(/^\*\/(\d+)$/);
  if (stepWildcardMatch) {
    const step = parseInt(stepWildcardMatch[1], 10);
    return validateRange(generateRange(min, max, step), min, max, field);
  }

  // Range with optional step: a-b or a-b/n
  const rangeMatch = segment.match(/^(\d+)-(\d+)(?:\/(\d+))?$/);
  if (rangeMatch) {
    const start = parseInt(rangeMatch[1], 10);
    const end = parseInt(rangeMatch[2], 10);
    const step = rangeMatch[3] !== undefined ? parseInt(rangeMatch[3], 10) : 1;
    return validateRange(generateRange(start, end, step), min, max, field);
  }

  // Comma-separated list
  if (segment.includes(",")) {
    const parts = segment.split(",");
    const values = parts.flatMap((part) => parseSegment(part.trim(), min, max, field));
    const unique = [...new Set(values)].sort((a, b) => a - b);
    return unique;
  }

  // Plain number
  const numMatch = segment.match(/^(\d+)$/);
  if (numMatch) {
    const value = parseInt(numMatch[1], 10);
    return validateRange([value], min, max, field);
  }

  throw new Error(`Invalid cron segment "${segment}" for field "${field}"`);
}

export function parseCron(expression: string): CronExpression {
  if (typeof expression !== "string") {
    throw new Error("Cron expression must be a string");
  }

  const fields = expression.trim().split(/\s+/);
  if (fields.length !== 5) {
    throw new Error(
      `Cron expression must have exactly 5 fields, got ${fields.length}: "${expression}"`
    );
  }

  const fieldNames = Object.keys(FIELD_RANGES) as Array<keyof CronExpression>;
  const result = {} as CronExpression;

  for (let i = 0; i < fieldNames.length; i++) {
    const name = fieldNames[i];
    const [min, max] = FIELD_RANGES[name];
    result[name] = parseSegment(fields[i], min, max, name);
  }

  return result;
}

export default parseCron;

type CronResult = {
  minute: number[];
  hour: number[];
  dayOfMonth: number[];
  month: number[];
  dayOfWeek: number[];
};

type FieldDef = {
  readonly name: keyof CronResult;
  readonly min: number;
  readonly max: number;
};

const FIELD_DEFS: readonly FieldDef[] = [
  { name: "minute", min: 0, max: 59 },
  { name: "hour", min: 0, max: 23 },
  { name: "dayOfMonth", min: 1, max: 31 },
  { name: "month", min: 1, max: 12 },
  { name: "dayOfWeek", min: 0, max: 6 },
] as const;

function parseStrictInt(raw: string, context: string): number {
  if (!/^\d+$/.test(raw.trim())) {
    throw new Error(`Invalid integer "${raw}" in ${context}`);
  }
  const n = parseInt(raw.trim(), 10);
  if (!Number.isFinite(n)) {
    throw new Error(`Non-finite integer "${raw}" in ${context}`);
  }
  return n;
}

function assertInRange(value: number, min: number, max: number, context: string): void {
  if (value < min || value > max) {
    throw new Error(`Value ${value} out of range [${min}, ${max}] in "${context}"`);
  }
}

function expandRange(start: number, end: number, step: number, expr: string): number[] {
  if (start > end) {
    throw new Error(`Range start ${start} exceeds end ${end} in "${expr}"`);
  }
  if (step <= 0) {
    throw new Error(`Step must be a positive integer in "${expr}"`);
  }
  const values: number[] = [];
  for (let i = start; i <= end; i += step) {
    values.push(i);
  }
  return values;
}

function parseSegment(expr: string, min: number, max: number): number[] {
  // Step: */n  |  a-b/n  |  a/n
  if (expr.includes("/")) {
    const parts = expr.split("/");
    if (parts.length !== 2) {
      throw new Error(`Invalid step expression "${expr}": expected exactly one "/"`);
    }
    const [rangeExpr, stepRaw] = parts;
    const step = parseStrictInt(stepRaw, expr);
    if (step === 0) {
      throw new Error(`Step cannot be zero in "${expr}"`);
    }

    if (rangeExpr === "*") {
      return expandRange(min, max, step, expr);
    }

    if (rangeExpr.includes("-")) {
      const [lo, hi] = parseRangeBounds(rangeExpr, min, max);
      return expandRange(lo, hi, step, expr);
    }

    // single-start/step: e.g. "2/5" means start at 2 with step 5 to max
    const start = parseStrictInt(rangeExpr, expr);
    assertInRange(start, min, max, expr);
    return expandRange(start, max, step, expr);
  }

  // Wildcard
  if (expr === "*") {
    return expandRange(min, max, 1, expr);
  }

  // Range: a-b
  if (expr.includes("-")) {
    const [lo, hi] = parseRangeBounds(expr, min, max);
    return expandRange(lo, hi, 1, expr);
  }

  // Single value
  const value = parseStrictInt(expr, `field value`);
  assertInRange(value, min, max, expr);
  return [value];
}

function parseRangeBounds(expr: string, min: number, max: number): [number, number] {
  const parts = expr.split("-");
  if (parts.length !== 2) {
    throw new Error(`Invalid range "${expr}": expected exactly one "-"`);
  }
  const lo = parseStrictInt(parts[0], expr);
  const hi = parseStrictInt(parts[1], expr);
  assertInRange(lo, min, max, expr);
  assertInRange(hi, min, max, expr);
  return [lo, hi];
}

function parseField(expr: string, min: number, max: number): number[] {
  if (expr.length === 0) {
    throw new Error(`Empty field expression`);
  }

  if (expr.includes(",")) {
    const segments = expr.split(",");
    if (segments.some((s) => s.trim().length === 0)) {
      throw new Error(`Empty segment in list "${expr}"`);
    }
    const seen = new Set<number>();
    for (const segment of segments) {
      for (const v of parseSegment(segment.trim(), min, max)) {
        seen.add(v);
      }
    }
    return Array.from(seen).sort((a, b) => a - b);
  }

  return parseSegment(expr, min, max);
}

export default function parseCron(expression: string): CronResult {
  if (typeof expression !== "string") {
    throw new TypeError(`Cron expression must be a string, got ${typeof expression}`);
  }

  const trimmed = expression.trim();
  if (trimmed.length === 0) {
    throw new Error(`Cron expression must not be empty`);
  }

  const fields = trimmed.split(/\s+/);
  if (fields.length !== 5) {
    throw new Error(
      `Cron expression must have exactly 5 fields (minute hour dayOfMonth month dayOfWeek), got ${fields.length}: "${trimmed}"`
    );
  }

  const result = {} as CronResult;

  for (let i = 0; i < FIELD_DEFS.length; i++) {
    const { name, min, max } = FIELD_DEFS[i];
    try {
      result[name] = parseField(fields[i], min, max);
    } catch (err) {
      throw new Error(
        `Invalid ${name} field "${fields[i]}": ${(err as Error).message}`
      );
    }
  }

  return result;
}

interface RateLimiterOptions {
  maxTokens: number;
  refillRate: number;
  refillIntervalMs: number;
}

class RateLimiter {
  private readonly maxTokens: number;
  private readonly refillRate: number;
  private readonly refillIntervalMs: number;
  private currentTokens: number;
  private lastRefillTime: number;

  constructor(options: RateLimiterOptions) {
    if (options.maxTokens <= 0) throw new RangeError("maxTokens must be > 0");
    if (options.refillRate <= 0) throw new RangeError("refillRate must be > 0");
    if (options.refillIntervalMs <= 0) throw new RangeError("refillIntervalMs must be > 0");

    this.maxTokens = options.maxTokens;
    this.refillRate = options.refillRate;
    this.refillIntervalMs = options.refillIntervalMs;
    this.currentTokens = options.maxTokens;
    this.lastRefillTime = Date.now();
  }

  private refill(): void {
    const now = Date.now();
    const elapsed = now - this.lastRefillTime;
    const intervals = Math.floor(elapsed / this.refillIntervalMs);

    if (intervals > 0) {
      const tokensToAdd = intervals * this.refillRate;
      this.currentTokens = Math.min(this.maxTokens, this.currentTokens + tokensToAdd);
      this.lastRefillTime += intervals * this.refillIntervalMs;
    }
  }

  tryConsume(tokens: number = 1): boolean {
    if (tokens <= 0) throw new RangeError("tokens must be > 0");
    if (tokens > this.maxTokens) return false;

    this.refill();

    if (this.currentTokens >= tokens) {
      this.currentTokens -= tokens;
      return true;
    }

    return false;
  }

  getTokens(): number {
    this.refill();
    return this.currentTokens;
  }

  reset(): void {
    this.currentTokens = this.maxTokens;
    this.lastRefillTime = Date.now();
  }

  async waitForTokens(tokens: number = 1): Promise<void> {
    if (tokens <= 0) throw new RangeError("tokens must be > 0");
    if (tokens > this.maxTokens) {
      throw new RangeError(`Requested ${tokens} tokens exceeds maxTokens (${this.maxTokens})`);
    }

    while (!this.tryConsume(tokens)) {
      const tokensNeeded = tokens - this.currentTokens;
      const intervalsNeeded = Math.ceil(tokensNeeded / this.refillRate);
      const elapsed = Date.now() - this.lastRefillTime;
      const waitMs = Math.max(1, intervalsNeeded * this.refillIntervalMs - elapsed);

      await new Promise<void>((resolve) => setTimeout(resolve, waitMs));
    }
  }
}

export default RateLimiter;

export interface CronExpression {
  minute: number[];
  hour: number[];
  dayOfMonth: number[];
  month: number[];
  dayOfWeek: number[];
}

interface FieldConfig {
  readonly name: string;
  readonly min: number;
  readonly max: number;
}

const FIELD_CONFIGS = [
  { name: "minute",     min: 0,  max: 59 },
  { name: "hour",       min: 0,  max: 23 },
  { name: "dayOfMonth", min: 1,  max: 31 },
  { name: "month",      min: 1,  max: 12 },
  { name: "dayOfWeek",  min: 0,  max: 7  },
] as const satisfies FieldConfig[];

const INTEGER_RE = /^\d+$/;

function expandRange(from: number, to: number, step: number, config: FieldConfig): number[] {
  if (!Number.isInteger(step) || step <= 0) {
    throw new RangeError(`Step must be a positive integer in field "${config.name}", got ${step}`);
  }
  if (from < config.min || to > config.max) {
    throw new RangeError(
      `Range ${from}-${to} exceeds valid bounds [${config.min}-${config.max}] for field "${config.name}"`
    );
  }
  if (from > to) {
    throw new RangeError(
      `Range start ${from} must not exceed end ${to} in field "${config.name}"`
    );
  }
  const values: number[] = [];
  for (let i = from; i <= to; i += step) {
    values.push(i);
  }
  return values;
}

function parseInteger(raw: string, config: FieldConfig): number {
  if (!INTEGER_RE.test(raw)) {
    throw new SyntaxError(`Invalid integer "${raw}" in field "${config.name}"`);
  }
  const value = parseInt(raw, 10);
  if (value < config.min || value > config.max) {
    throw new RangeError(
      `Value ${value} out of bounds [${config.min}-${config.max}] for field "${config.name}"`
    );
  }
  return value;
}

function parseSegment(segment: string, config: FieldConfig): number[] {
  // Step: "*/n", "a/n", or "a-b/n"
  if (segment.includes("/")) {
    const slashIdx = segment.lastIndexOf("/");
    const baseExpr = segment.slice(0, slashIdx);
    const stepRaw = segment.slice(slashIdx + 1);

    if (!INTEGER_RE.test(stepRaw)) {
      throw new SyntaxError(`Invalid step "${stepRaw}" in field "${config.name}"`);
    }
    const step = parseInt(stepRaw, 10);

    if (baseExpr === "*") {
      return expandRange(config.min, config.max, step, config);
    }

    if (baseExpr.includes("-")) {
      const parts = baseExpr.split("-");
      if (parts.length !== 2) {
        throw new SyntaxError(`Invalid range expression "${baseExpr}" in field "${config.name}"`);
      }
      const from = parseInteger(parts[0], config);
      const to   = parseInteger(parts[1], config);
      return expandRange(from, to, step, config);
    }

    // "n/step" — start from n, run to max
    const from = parseInteger(baseExpr, config);
    return expandRange(from, config.max, step, config);
  }

  // Wildcard
  if (segment === "*") {
    return expandRange(config.min, config.max, 1, config);
  }

  // Range: "a-b"
  if (segment.includes("-")) {
    const parts = segment.split("-");
    if (parts.length !== 2) {
      throw new SyntaxError(`Invalid range expression "${segment}" in field "${config.name}"`);
    }
    const from = parseInteger(parts[0], config);
    const to   = parseInteger(parts[1], config);
    return expandRange(from, to, 1, config);
  }

  // Single value
  return [parseInteger(segment, config)];
}

function parseField(field: string, config: FieldConfig): number[] {
  if (!field || field.trim() === "") {
    throw new SyntaxError(`Empty expression for field "${config.name}"`);
  }

  const seen = new Set<number>();
  const segments = field.split(",");

  for (const segment of segments) {
    const trimmed = segment.trim();
    if (trimmed === "") {
      throw new SyntaxError(`Empty segment in comma list for field "${config.name}"`);
    }
    for (const value of parseSegment(trimmed, config)) {
      seen.add(value);
    }
  }

  return Array.from(seen).sort((a, b) => a - b);
}

export default function parseCron(expression: string): CronExpression {
  if (typeof expression !== "string") {
    throw new TypeError(`Cron expression must be a string, got ${typeof expression}`);
  }

  const fields = expression.trim().split(/\s+/);

  if (fields.length !== 5) {
    throw new SyntaxError(
      `Cron expression must have exactly 5 fields (minute hour dayOfMonth month dayOfWeek), got ${fields.length}`
    );
  }

  const minute     = parseField(fields[0], FIELD_CONFIGS[0]);
  const hour       = parseField(fields[1], FIELD_CONFIGS[1]);
  const dayOfMonth = parseField(fields[2], FIELD_CONFIGS[2]);
  const month      = parseField(fields[3], FIELD_CONFIGS[3]);

  // dayOfWeek: 0 and 7 are both Sunday — normalize 7 → 0 to avoid duplicates
  const rawDow = parseField(fields[4], FIELD_CONFIGS[4]);
  const dowSet = new Set<number>(rawDow.map((d) => (d === 7 ? 0 : d)));
  const dayOfWeek = Array.from(dowSet).sort((a, b) => a - b);

  return { minute, hour, dayOfMonth, month, dayOfWeek };
}

interface RateLimiterOptions {
  maxTokens: number;
  refillRate: number;
  refillIntervalMs: number;
}

interface Waiter {
  tokens: number;
  resolve: () => void;
  reject: (reason: Error) => void;
}

export class RateLimiter {
  private readonly maxTokens: number;
  private readonly refillRate: number;
  private readonly refillIntervalMs: number;

  private currentTokens: number;
  private lastRefillTime: number;

  private readonly waitQueue: Waiter[] = [];
  private drainTimeout: ReturnType<typeof setTimeout> | null = null;

  constructor(options: RateLimiterOptions) {
    const { maxTokens, refillRate, refillIntervalMs } = options;

    if (!Number.isFinite(maxTokens) || maxTokens <= 0) {
      throw new RangeError(
        `maxTokens must be a positive finite number, got ${maxTokens}`,
      );
    }
    if (!Number.isFinite(refillRate) || refillRate <= 0) {
      throw new RangeError(
        `refillRate must be a positive finite number, got ${refillRate}`,
      );
    }
    if (!Number.isFinite(refillIntervalMs) || refillIntervalMs <= 0) {
      throw new RangeError(
        `refillIntervalMs must be a positive finite number, got ${refillIntervalMs}`,
      );
    }

    this.maxTokens = maxTokens;
    this.refillRate = refillRate;
    this.refillIntervalMs = refillIntervalMs;
    this.currentTokens = maxTokens;
    this.lastRefillTime = Date.now();
  }

  private lazyRefill(): void {
    const now = Date.now();
    const elapsed = now - this.lastRefillTime;

    if (elapsed <= 0) return;

    const tokensToAdd = (elapsed / this.refillIntervalMs) * this.refillRate;
    this.currentTokens = Math.min(
      this.maxTokens,
      this.currentTokens + tokensToAdd,
    );
    this.lastRefillTime = now;
  }

  private drainQueue(): void {
    while (this.waitQueue.length > 0) {
      const waiter = this.waitQueue[0];
      if (this.currentTokens >= waiter.tokens) {
        this.currentTokens -= waiter.tokens;
        this.waitQueue.shift();
        waiter.resolve();
      } else {
        break;
      }
    }
  }

  private scheduleNextDrain(): void {
    if (this.drainTimeout !== null || this.waitQueue.length === 0) return;

    const waiter = this.waitQueue[0];
    const deficit = waiter.tokens - this.currentTokens;

    if (deficit <= 0) {
      this.drainQueue();
      if (this.waitQueue.length > 0) this.scheduleNextDrain();
      return;
    }

    const msUntilReady = Math.ceil(
      (deficit / this.refillRate) * this.refillIntervalMs,
    );

    this.drainTimeout = setTimeout(() => {
      this.drainTimeout = null;
      this.lazyRefill();
      this.drainQueue();
      if (this.waitQueue.length > 0) this.scheduleNextDrain();
    }, msUntilReady);
  }

  private validateTokenCount(tokens: number, context: string): void {
    if (!Number.isInteger(tokens) || tokens <= 0) {
      throw new RangeError(
        `${context}: tokens must be a positive integer, got ${tokens}`,
      );
    }
  }

  /**
   * Attempts to consume tokens immediately.
   *
   * Returns false — without consuming — if:
   *   - The bucket does not currently hold enough tokens.
   *   - There are pending waiters ahead in the queue (fairness guarantee).
   *   - The requested amount exceeds maxTokens (impossible to ever satisfy).
   */
  tryConsume(tokens = 1): boolean {
    this.validateTokenCount(tokens, "tryConsume");

    if (tokens > this.maxTokens) return false;

    this.lazyRefill();

    // Honour FIFO ordering: bypass is disallowed while waiters are queued.
    if (this.waitQueue.length > 0) return false;

    if (this.currentTokens < tokens) return false;

    this.currentTokens -= tokens;
    return true;
  }

  /** Returns current token count after applying any pending refill. */
  getTokens(): number {
    this.lazyRefill();
    return this.currentTokens;
  }

  /**
   * Resets the bucket to full capacity and resolves any pending waiters
   * that can now be satisfied in FIFO order.
   */
  reset(): void {
    this.currentTokens = this.maxTokens;
    this.lastRefillTime = Date.now();

    if (this.drainTimeout !== null) {
      clearTimeout(this.drainTimeout);
      this.drainTimeout = null;
    }

    this.drainQueue();
    if (this.waitQueue.length > 0) this.scheduleNextDrain();
  }

  /**
   * Resolves once the requested number of tokens can be consumed.
   *
   * Rejects immediately if the request exceeds maxTokens, since it could
   * never be satisfied regardless of how long we wait.
   *
   * Waiters are served in FIFO order to prevent starvation.
   */
  waitForTokens(tokens = 1): Promise<void> {
    try {
      this.validateTokenCount(tokens, "waitForTokens");
    } catch (err) {
      return Promise.reject(err as Error);
    }

    if (tokens > this.maxTokens) {
      return Promise.reject(
        new RangeError(
          `Requested ${tokens} tokens exceeds the maximum bucket capacity of ${this.maxTokens}; ` +
            `this request can never be satisfied`,
        ),
      );
    }

    this.lazyRefill();

    if (this.waitQueue.length === 0 && this.currentTokens >= tokens) {
      this.currentTokens -= tokens;
      return Promise.resolve();
    }

    return new Promise<void>((resolve, reject) => {
      this.waitQueue.push({ tokens, resolve, reject });
      this.scheduleNextDrain();
    });
  }
}

export default RateLimiter;

export class RateLimiter {
  private readonly maxTokens: number;
  private readonly refillRate: number;
  private readonly refillIntervalMs: number;
  private currentTokens: number;
  private lastRefillTime: number;

  constructor(options: {
    maxTokens: number;
    refillRate: number;
    refillIntervalMs: number;
  }) {
    if (options.maxTokens <= 0) throw new RangeError("maxTokens must be positive");
    if (options.refillRate <= 0) throw new RangeError("refillRate must be positive");
    if (options.refillIntervalMs <= 0) throw new RangeError("refillIntervalMs must be positive");

    this.maxTokens = options.maxTokens;
    this.refillRate = options.refillRate;
    this.refillIntervalMs = options.refillIntervalMs;
    this.currentTokens = options.maxTokens;
    this.lastRefillTime = Date.now();
  }

  private lazyRefill(): void {
    const now = Date.now();
    const elapsed = now - this.lastRefillTime;

    if (elapsed <= 0) return;

    const tokensToAdd = (elapsed / this.refillIntervalMs) * this.refillRate;
    this.currentTokens = Math.min(this.maxTokens, this.currentTokens + tokensToAdd);
    this.lastRefillTime = now;
  }

  tryConsume(tokens: number = 1): boolean {
    if (tokens < 0) throw new RangeError("tokens must be non-negative");
    if (tokens === 0) return true;

    this.lazyRefill();

    if (this.currentTokens >= tokens) {
      this.currentTokens -= tokens;
      return true;
    }

    return false;
  }

  getTokens(): number {
    this.lazyRefill();
    return this.currentTokens;
  }

  reset(): void {
    this.currentTokens = this.maxTokens;
    this.lastRefillTime = Date.now();
  }

  waitForTokens(tokens: number = 1): Promise<void> {
    if (tokens < 0) throw new RangeError("tokens must be non-negative");
    if (tokens === 0) return Promise.resolve();
    if (tokens > this.maxTokens) {
      return Promise.reject(
        new RangeError(
          `Requested ${tokens} tokens exceeds maxTokens (${this.maxTokens}) and can never be satisfied`
        )
      );
    }

    return new Promise<void>((resolve) => {
      const attempt = (): void => {
        if (this.tryConsume(tokens)) {
          resolve();
          return;
        }

        // tryConsume already performed lazyRefill, so currentTokens reflects now.
        const deficit = tokens - this.currentTokens;
        const msPerToken = this.refillIntervalMs / this.refillRate;
        const waitMs = Math.max(1, Math.ceil(deficit * msPerToken));

        setTimeout(attempt, waitMs);
      };

      attempt();
    });
  }
}

export default RateLimiter;

type CronField = "minute" | "hour" | "dayOfMonth" | "month" | "dayOfWeek";

interface CronExpression {
  minute: number[];
  hour: number[];
  dayOfMonth: number[];
  month: number[];
  dayOfWeek: number[];
}

interface FieldRange {
  min: number;
  max: number;
}

const FIELD_RANGES: Record<CronField, FieldRange> = {
  minute: { min: 0, max: 59 },
  hour: { min: 0, max: 23 },
  dayOfMonth: { min: 1, max: 31 },
  month: { min: 1, max: 12 },
  dayOfWeek: { min: 0, max: 6 },
};

const FIELD_ORDER: CronField[] = [
  "minute",
  "hour",
  "dayOfMonth",
  "month",
  "dayOfWeek",
];

function parseInteger(value: string, context: string): number {
  const trimmed = value.trim();
  if (!/^\d+$/.test(trimmed)) {
    throw new Error(`Invalid numeric value "${trimmed}" in ${context}`);
  }
  return parseInt(trimmed, 10);
}

function assertInRange(
  value: number,
  range: FieldRange,
  context: string
): void {
  if (value < range.min || value > range.max) {
    throw new RangeError(
      `Value ${value} out of range [${range.min}, ${range.max}] in ${context}`
    );
  }
}

function generateSequence(start: number, end: number, step: number): number[] {
  if (step <= 0) throw new RangeError(`Step must be positive, got ${step}`);
  const values: number[] = [];
  for (let i = start; i <= end; i += step) {
    values.push(i);
  }
  return values;
}

function parseRange(
  expression: string,
  fieldRange: FieldRange,
  context: string
): [number, number] {
  const parts = expression.split("-");
  if (parts.length !== 2 || parts[0].trim() === "" || parts[1].trim() === "") {
    throw new Error(`Malformed range expression "${expression}" in ${context}`);
  }
  const start = parseInteger(parts[0], context);
  const end = parseInteger(parts[1], context);
  assertInRange(start, fieldRange, context);
  assertInRange(end, fieldRange, context);
  if (start > end) {
    throw new RangeError(
      `Range start ${start} exceeds end ${end} in ${context}`
    );
  }
  return [start, end];
}

function parseSegment(
  segment: string,
  fieldRange: FieldRange,
  field: CronField
): number[] {
  const context = `field "${field}"`;
  const trimmed = segment.trim();

  if (trimmed === "") {
    throw new Error(`Empty segment in ${context}`);
  }

  // Step expression: */n  or  a-b/n  or  a/n
  if (trimmed.includes("/")) {
    const slashParts = trimmed.split("/");
    if (slashParts.length !== 2) {
      throw new Error(`Invalid step expression "${trimmed}" in ${context}`);
    }
    const [rangePart, stepPart] = slashParts;
    const step = parseInteger(stepPart.trim(), context);
    if (step <= 0) {
      throw new RangeError(
        `Step value must be positive, got ${step} in ${context}`
      );
    }

    if (rangePart === "*") {
      return generateSequence(fieldRange.min, fieldRange.max, step);
    }

    if (rangePart.includes("-")) {
      const [start, end] = parseRange(rangePart.trim(), fieldRange, context);
      return generateSequence(start, end, step);
    }

    // Bare number with step: treat start as the number, end as field max
    const start = parseInteger(rangePart.trim(), context);
    assertInRange(start, fieldRange, context);
    return generateSequence(start, fieldRange.max, step);
  }

  // Wildcard
  if (trimmed === "*") {
    return generateSequence(fieldRange.min, fieldRange.max, 1);
  }

  // Range: a-b
  if (trimmed.includes("-")) {
    const [start, end] = parseRange(trimmed, fieldRange, context);
    return generateSequence(start, end, 1);
  }

  // Single numeric value
  const value = parseInteger(trimmed, context);
  assertInRange(value, fieldRange, context);
  return [value];
}

function parseField(expression: string, field: CronField): number[] {
  const fieldRange = FIELD_RANGES[field];
  const context = `field "${field}"`;
  const trimmed = expression.trim();

  if (trimmed === "") {
    throw new Error(`Empty expression for ${context}`);
  }

  if (trimmed.includes(",")) {
    const parts = trimmed.split(",");
    for (const part of parts) {
      if (part.trim() === "") {
        throw new Error(
          `Empty item in comma-separated list for ${context}: "${trimmed}"`
        );
      }
    }
    const allValues = parts.flatMap((part) =>
      parseSegment(part.trim(), fieldRange, field)
    );
    return [...new Set(allValues)].sort((a, b) => a - b);
  }

  return parseSegment(trimmed, fieldRange, field);
}

export default function parseCron(expression: string): CronExpression {
  if (typeof expression !== "string") {
    throw new TypeError(
      `parseCron expects a string, received ${typeof expression}`
    );
  }

  const trimmed = expression.trim();

  if (trimmed === "") {
    throw new Error("Cron expression must not be empty");
  }

  const fields = trimmed.split(/\s+/);

  if (fields.length !== 5) {
    throw new Error(
      `Cron expression must have exactly 5 fields, got ${fields.length}: "${expression}"`
    );
  }

  const result = {} as CronExpression;

  for (let i = 0; i < FIELD_ORDER.length; i++) {
    const field = FIELD_ORDER[i];
    result[field] = parseField(fields[i], field);
  }

  return result;
}

interface RateLimiterOptions {
  maxTokens: number;
  refillRate: number;
  refillIntervalMs: number;
}

interface PendingRequest {
  tokens: number;
  resolve: () => void;
  reject: (err: Error) => void;
}

export default class RateLimiter {
  private readonly maxTokens: number;
  private readonly refillRate: number;
  private readonly refillIntervalMs: number;
  private currentTokens: number;
  private lastRefillTime: number;
  private readonly waitQueue: PendingRequest[] = [];
  private drainScheduled = false;

  constructor(options: RateLimiterOptions) {
    if (!Number.isFinite(options.maxTokens) || options.maxTokens <= 0) {
      throw new RangeError(`maxTokens must be a finite positive number, got ${options.maxTokens}`);
    }
    if (!Number.isFinite(options.refillRate) || options.refillRate <= 0) {
      throw new RangeError(`refillRate must be a finite positive number, got ${options.refillRate}`);
    }
    if (!Number.isFinite(options.refillIntervalMs) || options.refillIntervalMs <= 0) {
      throw new RangeError(`refillIntervalMs must be a finite positive number, got ${options.refillIntervalMs}`);
    }

    this.maxTokens = options.maxTokens;
    this.refillRate = options.refillRate;
    this.refillIntervalMs = options.refillIntervalMs;
    this.currentTokens = options.maxTokens;
    this.lastRefillTime = Date.now();
  }

  private applyRefill(): void {
    const now = Date.now();
    const elapsedMs = now - this.lastRefillTime;

    if (elapsedMs > 0) {
      const tokensToAdd = (elapsedMs / this.refillIntervalMs) * this.refillRate;
      this.currentTokens = Math.min(this.maxTokens, this.currentTokens + tokensToAdd);
      this.lastRefillTime = now;
    }
  }

  private validateTokenArg(tokens: number, caller: string): void {
    if (!Number.isFinite(tokens) || tokens <= 0) {
      throw new RangeError(`${caller}: tokens must be a finite positive number, got ${tokens}`);
    }
  }

  tryConsume(tokens = 1): boolean {
    this.validateTokenArg(tokens, "tryConsume");

    if (tokens > this.maxTokens) {
      return false;
    }

    this.applyRefill();

    if (this.currentTokens >= tokens) {
      this.currentTokens -= tokens;
      return true;
    }

    return false;
  }

  getTokens(): number {
    this.applyRefill();
    return this.currentTokens;
  }

  reset(): void {
    this.currentTokens = this.maxTokens;
    this.lastRefillTime = Date.now();
    this.scheduleDrain(0);
  }

  waitForTokens(tokens = 1): Promise<void> {
    this.validateTokenArg(tokens, "waitForTokens");

    if (tokens > this.maxTokens) {
      return Promise.reject(
        new RangeError(
          `waitForTokens: requested ${tokens} tokens exceeds bucket capacity of ${this.maxTokens} and can never be fulfilled`
        )
      );
    }

    return new Promise<void>((resolve, reject) => {
      this.waitQueue.push({ tokens, resolve, reject });
      this.scheduleDrain(0);
    });
  }

  private scheduleDrain(delayMs: number): void {
    if (this.drainScheduled) return;
    this.drainScheduled = true;

    setTimeout(() => {
      this.drainScheduled = false;
      this.drainQueue();
    }, delayMs);
  }

  private drainQueue(): void {
    this.applyRefill();

    while (this.waitQueue.length > 0) {
      const head = this.waitQueue[0];

      if (this.currentTokens >= head.tokens) {
        this.waitQueue.shift();
        this.currentTokens -= head.tokens;
        head.resolve();
      } else {
        const deficit = head.tokens - this.currentTokens;
        const msUntilSufficient = (deficit / this.refillRate) * this.refillIntervalMs;
        this.scheduleDrain(Math.ceil(msUntilSufficient));
        return;
      }
    }
  }
}

export interface RateLimiterOptions {
  maxTokens: number;
  refillRate: number;
  refillIntervalMs: number;
}

interface Waiter {
  tokens: number;
  resolve: () => void;
  reject: (err: Error) => void;
}

export class RateLimiter {
  private readonly maxTokens: number;
  private readonly refillRate: number;
  private readonly refillIntervalMs: number;
  private currentTokens: number;
  private lastRefillTime: number;
  private readonly waitQueue: Waiter[];
  private wakeupScheduled: boolean;

  constructor(options: RateLimiterOptions) {
    if (!Number.isFinite(options.maxTokens) || options.maxTokens <= 0) {
      throw new RangeError("maxTokens must be a positive finite number");
    }
    if (!Number.isFinite(options.refillRate) || options.refillRate < 0) {
      throw new RangeError("refillRate must be a non-negative finite number");
    }
    if (!Number.isFinite(options.refillIntervalMs) || options.refillIntervalMs <= 0) {
      throw new RangeError("refillIntervalMs must be a positive finite number");
    }

    this.maxTokens = options.maxTokens;
    this.refillRate = options.refillRate;
    this.refillIntervalMs = options.refillIntervalMs;
    this.currentTokens = options.maxTokens;
    this.lastRefillTime = Date.now();
    this.waitQueue = [];
    this.wakeupScheduled = false;
  }

  private refill(): void {
    if (this.refillRate === 0) return;
    const now = Date.now();
    const elapsed = now - this.lastRefillTime;
    if (elapsed <= 0) return;
    const tokensToAdd = (elapsed / this.refillIntervalMs) * this.refillRate;
    this.currentTokens = Math.min(this.maxTokens, this.currentTokens + tokensToAdd);
    this.lastRefillTime = now;
  }

  private drainQueue(): void {
    while (this.waitQueue.length > 0) {
      const head = this.waitQueue[0];
      if (this.currentTokens >= head.tokens) {
        this.currentTokens -= head.tokens;
        this.waitQueue.shift();
        head.resolve();
      } else {
        break; // FIFO: do not skip over head even if later waiters could be served
      }
    }
  }

  private scheduleWakeup(): void {
    if (this.wakeupScheduled || this.waitQueue.length === 0) return;

    // If refillRate is zero we can never add tokens; waiters will hang
    // until reset() is called — that is intentional and documented behaviour.
    if (this.refillRate === 0) return;

    const head = this.waitQueue[0];
    const deficit = head.tokens - this.currentTokens;

    if (deficit <= 0) {
      this.drainQueue();
      if (this.waitQueue.length > 0) this.scheduleWakeup();
      return;
    }

    const tokensPerMs = this.refillRate / this.refillIntervalMs;
    const waitMs = Math.ceil(deficit / tokensPerMs);

    this.wakeupScheduled = true;
    setTimeout(() => {
      this.wakeupScheduled = false;
      this.refill();
      this.drainQueue();
      if (this.waitQueue.length > 0) this.scheduleWakeup();
    }, waitMs);
  }

  tryConsume(tokens: number = 1): boolean {
    if (!Number.isFinite(tokens) || tokens < 0) {
      throw new RangeError("tokens must be a non-negative finite number");
    }
    // A request larger than the bucket capacity can never be satisfied.
    if (tokens > this.maxTokens) return false;
    this.refill();
    if (this.currentTokens >= tokens) {
      this.currentTokens -= tokens;
      return true;
    }
    return false;
  }

  getTokens(): number {
    this.refill();
    return this.currentTokens;
  }

  reset(): void {
    this.currentTokens = this.maxTokens;
    this.lastRefillTime = Date.now();
    this.drainQueue();
    if (this.waitQueue.length > 0) this.scheduleWakeup();
  }

  waitForTokens(tokens: number = 1): Promise<void> {
    if (!Number.isFinite(tokens) || tokens < 0) {
      return Promise.reject(
        new RangeError("tokens must be a non-negative finite number"),
      );
    }
    if (tokens > this.maxTokens) {
      return Promise.reject(
        new RangeError(
          `Requested ${tokens} tokens exceeds maxTokens (${this.maxTokens}); ` +
            "this request can never be fulfilled",
        ),
      );
    }

    this.refill();

    // Fast path: nothing queued ahead and sufficient tokens available.
    if (this.waitQueue.length === 0 && this.currentTokens >= tokens) {
      this.currentTokens -= tokens;
      return Promise.resolve();
    }

    // Slow path: park the caller in FIFO order.
    return new Promise<void>((resolve, reject) => {
      this.waitQueue.push({ tokens, resolve, reject });
      this.scheduleWakeup();
    });
  }
}

export default RateLimiter;

type CronResult = {
  minute: number[];
  hour: number[];
  dayOfMonth: number[];
  month: number[];
  dayOfWeek: number[];
};

type FieldConfig = {
  min: number;
  max: number;
};

const FIELD_CONFIGS: Record<keyof CronResult, FieldConfig> = {
  minute:     { min: 0,  max: 59 },
  hour:       { min: 0,  max: 23 },
  dayOfMonth: { min: 1,  max: 31 },
  month:      { min: 1,  max: 12 },
  dayOfWeek:  { min: 0,  max: 6  },
};

const range = (start: number, end: number): number[] =>
  Array.from({ length: end - start + 1 }, (_, i) => start + i);

const parseSegment = (segment: string, config: FieldConfig): number[] => {
  const { min, max } = config;

  // Wildcard
  if (segment === "*") {
    return range(min, max);
  }

  // Step with wildcard base: */n
  if (segment.startsWith("*/")) {
    const step = parseInt(segment.slice(2), 10);
    if (isNaN(step) || step <= 0) throw new Error(`Invalid step value: ${segment}`);
    return range(min, max).filter(v => (v - min) % step === 0);
  }

  // Range with optional step: a-b or a-b/n
  if (segment.includes("-")) {
    const [rangePart, stepPart] = segment.split("/");
    const [startStr, endStr] = rangePart!.split("-");
    const start = parseInt(startStr!, 10);
    const end = parseInt(endStr!, 10);

    if (isNaN(start) || isNaN(end)) throw new Error(`Invalid range: ${segment}`);
    if (start < min || end > max) throw new Error(`Range out of bounds: ${segment} (valid: ${min}-${max})`);
    if (start > end) throw new Error(`Range start must be <= end: ${segment}`);

    const values = range(start, end);

    if (stepPart !== undefined) {
      const step = parseInt(stepPart, 10);
      if (isNaN(step) || step <= 0) throw new Error(`Invalid step value in range: ${segment}`);
      return values.filter((_, i) => i % step === 0);
    }

    return values;
  }

  // Plain number
  const value = parseInt(segment, 10);
  if (isNaN(value)) throw new Error(`Invalid cron field value: ${segment}`);
  if (value < min || value > max) throw new Error(`Value ${value} out of bounds (valid: ${min}-${max})`);
  return [value];
};

const parseField = (field: string, config: FieldConfig): number[] => {
  if (field.includes(",")) {
    const values = field
      .split(",")
      .flatMap(segment => parseSegment(segment.trim(), config));
    const unique = [...new Set(values)].sort((a, b) => a - b);
    return unique;
  }

  return parseSegment(field.trim(), config);
};

const parseCron = (expression: string): CronResult => {
  const fields = expression.trim().split(/\s+/);

  if (fields.length !== 5) {
    throw new Error(`Invalid cron expression: expected 5 fields, got ${fields.length}`);
  }

  const [minuteField, hourField, domField, monthField, dowField] = fields as [
    string, string, string, string, string
  ];

  return {
    minute:     parseField(minuteField, FIELD_CONFIGS.minute),
    hour:       parseField(hourField,   FIELD_CONFIGS.hour),
    dayOfMonth: parseField(domField,    FIELD_CONFIGS.dayOfMonth),
    month:      parseField(monthField,  FIELD_CONFIGS.month),
    dayOfWeek:  parseField(dowField,    FIELD_CONFIGS.dayOfWeek),
  };
};

export default parseCron;

export interface RateLimiterOptions {
  maxTokens: number;
  refillRate: number;
  refillIntervalMs: number;
}

type Waiter = {
  tokens: number;
  resolve: () => void;
  reject: (err: Error) => void;
};

export class RateLimiter {
  private readonly maxTokens: number;
  private readonly refillRate: number;
  private readonly refillIntervalMs: number;

  private currentTokens: number;
  private lastRefillTime: number;

  private readonly waitQueue: Waiter[] = [];
  private pendingTimer: ReturnType<typeof setTimeout> | null = null;

  constructor(options: RateLimiterOptions) {
    const { maxTokens, refillRate, refillIntervalMs } = options;

    if (!Number.isFinite(maxTokens) || maxTokens <= 0) {
      throw new RangeError(`maxTokens must be a positive finite number, got ${maxTokens}`);
    }
    if (!Number.isFinite(refillRate) || refillRate <= 0) {
      throw new RangeError(`refillRate must be a positive finite number, got ${refillRate}`);
    }
    if (!Number.isFinite(refillIntervalMs) || refillIntervalMs <= 0) {
      throw new RangeError(`refillIntervalMs must be a positive finite number, got ${refillIntervalMs}`);
    }

    this.maxTokens = maxTokens;
    this.refillRate = refillRate;
    this.refillIntervalMs = refillIntervalMs;
    this.currentTokens = maxTokens;
    this.lastRefillTime = Date.now();
  }

  private applyRefill(): void {
    const now = Date.now();
    const elapsed = now - this.lastRefillTime;

    if (elapsed < this.refillIntervalMs) return;

    const intervals = Math.floor(elapsed / this.refillIntervalMs);
    const newTokens = intervals * this.refillRate;

    this.currentTokens = Math.min(this.maxTokens, this.currentTokens + newTokens);
    // Advance lastRefillTime by whole intervals only — preserve fractional elapsed time
    this.lastRefillTime += intervals * this.refillIntervalMs;
  }

  private validateTokenAmount(tokens: number, label = "tokens"): void {
    if (!Number.isFinite(tokens) || tokens < 0) {
      throw new RangeError(`${label} must be a non-negative finite number, got ${tokens}`);
    }
  }

  tryConsume(tokens: number = 1): boolean {
    this.validateTokenAmount(tokens);
    if (tokens === 0) return true;

    this.applyRefill();

    if (this.currentTokens >= tokens) {
      this.currentTokens -= tokens;
      return true;
    }

    return false;
  }

  getTokens(): number {
    this.applyRefill();
    return this.currentTokens;
  }

  reset(): void {
    this.currentTokens = this.maxTokens;
    this.lastRefillTime = Date.now();
    // Drain the wait queue — the bucket is now full again
    this.drainWaitQueue();
  }

  waitForTokens(tokens: number = 1): Promise<void> {
    try {
      this.validateTokenAmount(tokens);
    } catch (err) {
      return Promise.reject(err as Error);
    }

    if (tokens === 0) return Promise.resolve();

    if (tokens > this.maxTokens) {
      return Promise.reject(
        new RangeError(
          `Requested ${tokens} tokens exceeds maxTokens (${this.maxTokens}); will never be fulfilled`
        )
      );
    }

    // Only allow immediate consumption if the queue is empty — preserve FIFO ordering
    if (this.waitQueue.length === 0) {
      this.applyRefill();
      if (this.currentTokens >= tokens) {
        this.currentTokens -= tokens;
        return Promise.resolve();
      }
    }

    return new Promise<void>((resolve, reject) => {
      this.waitQueue.push({ tokens, resolve, reject });
      this.scheduleNextCheck();
    });
  }

  private drainWaitQueue(): void {
    this.applyRefill();

    while (this.waitQueue.length > 0) {
      const waiter = this.waitQueue[0]!;

      if (this.currentTokens < waiter.tokens) break;

      this.currentTokens -= waiter.tokens;
      this.waitQueue.shift();
      waiter.resolve();
    }
  }

  private scheduleNextCheck(): void {
    // Avoid stacking timers — one is always sufficient
    if (this.pendingTimer !== null) return;

    const now = Date.now();
    const elapsed = now - this.lastRefillTime;
    // Time remaining until the next refill tick, plus a small epsilon to
    // ensure we land strictly after the boundary
    const msUntilNextRefill = this.refillIntervalMs - (elapsed % this.refillIntervalMs) + 1;

    this.pendingTimer = setTimeout(() => {
      this.pendingTimer = null;
      this.drainWaitQueue();

      if (this.waitQueue.length > 0) {
        this.scheduleNextCheck();
      }
    }, msUntilNextRefill);
  }
}

export default RateLimiter;

interface CronFields {
  minute: number[];
  hour: number[];
  dayOfMonth: number[];
  month: number[];
  dayOfWeek: number[];
}

const FIELD_RANGES: Record<keyof CronFields, [number, number]> = {
  minute: [0, 59],
  hour: [0, 23],
  dayOfMonth: [1, 31],
  month: [1, 12],
  dayOfWeek: [0, 7],
};

const range = (start: number, end: number): number[] =>
  Array.from({ length: end - start + 1 }, (_, i) => start + i);

const parseField = (
  field: string,
  min: number,
  max: number,
  fieldName: string
): number[] => {
  const assertInRange = (val: number): number => {
    if (val < min || val > max) {
      throw new RangeError(
        `Value ${val} is out of range [${min}, ${max}] for field "${fieldName}"`
      );
    }
    return val;
  };

  // Comma-separated list
  if (field.includes(",")) {
    const values = field.split(",").flatMap((part) =>
      parseField(part.trim(), min, max, fieldName)
    );
    return [...new Set(values)].sort((a, b) => a - b);
  }

  // Wildcard
  if (field === "*") {
    return range(min, max);
  }

  // Step value: */step or start-end/step
  if (field.includes("/")) {
    const [rangePart, stepPart] = field.split("/");
    const step = parseInt(stepPart, 10);

    if (isNaN(step) || step <= 0) {
      throw new SyntaxError(
        `Invalid step value "${stepPart}" in field "${fieldName}"`
      );
    }

    let start: number;
    let end: number;

    if (rangePart === "*") {
      start = min;
      end = max;
    } else if (rangePart.includes("-")) {
      const [s, e] = rangePart.split("-").map((n) => parseInt(n, 10));
      start = assertInRange(s);
      end = assertInRange(e);
      if (start > end) {
        throw new RangeError(
          `Invalid range ${s}-${e} in field "${fieldName}": start must be <= end`
        );
      }
    } else {
      start = assertInRange(parseInt(rangePart, 10));
      end = max;
    }

    const result: number[] = [];
    for (let i = start; i <= end; i += step) {
      result.push(i);
    }
    return result;
  }

  // Range: start-end
  if (field.includes("-")) {
    const [startStr, endStr] = field.split("-");
    const start = assertInRange(parseInt(startStr, 10));
    const end = assertInRange(parseInt(endStr, 10));

    if (isNaN(start) || isNaN(end)) {
      throw new SyntaxError(`Invalid range "${field}" in field "${fieldName}"`);
    }
    if (start > end) {
      throw new RangeError(
        `Invalid range ${start}-${end} in field "${fieldName}": start must be <= end`
      );
    }
    return range(start, end);
  }

  // Plain number
  const num = parseInt(field, 10);
  if (isNaN(num)) {
    throw new SyntaxError(
      `Invalid value "${field}" in field "${fieldName}"`
    );
  }
  assertInRange(num);
  return [num];
};

const parseCron = (expression: string): CronFields => {
  const parts = expression.trim().split(/\s+/);

  if (parts.length !== 5) {
    throw new SyntaxError(
      `Invalid cron expression: expected 5 fields, got ${parts.length}`
    );
  }

  const fieldNames = Object.keys(FIELD_RANGES) as (keyof CronFields)[];

  const result = {} as CronFields;

  for (let i = 0; i < fieldNames.length; i++) {
    const name = fieldNames[i];
    const [min, max] = FIELD_RANGES[name];
    let values = parseField(parts[i], min, max, name);

    // Normalize dayOfWeek: treat 7 as 0 (Sunday)
    if (name === "dayOfWeek") {
      values = [...new Set(values.map((v) => (v === 7 ? 0 : v)))].sort(
        (a, b) => a - b
      );
    }

    result[name] = values;
  }

  return result;
};

export default parseCron;

interface CronExpression {
  minute: number[];
  hour: number[];
  dayOfMonth: number[];
  month: number[];
  dayOfWeek: number[];
}

interface FieldConfig {
  name: string;
  min: number;
  max: number;
}

const FIELD_CONFIGS: FieldConfig[] = [
  { name: "minute",     min: 0,  max: 59 },
  { name: "hour",       min: 0,  max: 23 },
  { name: "dayOfMonth", min: 1,  max: 31 },
  { name: "month",      min: 1,  max: 12 },
  { name: "dayOfWeek",  min: 0,  max: 6  },
];

function assertInRange(value: number, config: FieldConfig, context: string): void {
  if (!Number.isInteger(value) || value < config.min || value > config.max) {
    throw new RangeError(
      `Value ${value} in "${context}" is out of valid range [${config.min}, ${config.max}] for field "${config.name}"`
    );
  }
}

function parsePart(part: string, config: FieldConfig): number[] {
  const values: number[] = [];

  // Wildcard: "*"
  if (part === "*") {
    for (let i = config.min; i <= config.max; i++) values.push(i);
    return values;
  }

  // Step on wildcard: "*/N"
  const stepWildcard = /^\*\/(\d+)$/.exec(part);
  if (stepWildcard) {
    const step = parseInt(stepWildcard[1], 10);
    if (step <= 0) throw new RangeError(`Step value must be >= 1 in "${part}"`);
    for (let i = config.min; i <= config.max; i += step) values.push(i);
    return values;
  }

  // Range with optional step: "N-M" or "N-M/S"
  const rangePattern = /^(\d+)-(\d+)(?:\/(\d+))?$/.exec(part);
  if (rangePattern) {
    const start = parseInt(rangePattern[1], 10);
    const end   = parseInt(rangePattern[2], 10);
    const step  = rangePattern[3] !== undefined ? parseInt(rangePattern[3], 10) : 1;

    assertInRange(start, config, part);
    assertInRange(end,   config, part);

    if (start > end) {
      throw new RangeError(
        `Range start ${start} exceeds end ${end} in "${part}" for field "${config.name}"`
      );
    }
    if (step <= 0) throw new RangeError(`Step value must be >= 1 in "${part}"`);

    for (let i = start; i <= end; i += step) values.push(i);
    return values;
  }

  // Single numeric value: "N"
  const singlePattern = /^\d+$/.exec(part);
  if (singlePattern) {
    const val = parseInt(part, 10);
    assertInRange(val, config, part);
    values.push(val);
    return values;
  }

  throw new SyntaxError(
    `Unrecognised token "${part}" in field "${config.name}"`
  );
}

function parseField(raw: string, config: FieldConfig): number[] {
  if (!raw || raw.trim() === "") {
    throw new SyntaxError(`Field "${config.name}" is empty`);
  }

  const parts = raw.split(",");
  if (parts.some(p => p === "")) {
    throw new SyntaxError(`Trailing or consecutive commas in field "${config.name}": "${raw}"`);
  }

  const seen = new Set<number>();

  for (const part of parts) {
    const trimmed = part.trim();
    for (const v of parsePart(trimmed, config)) {
      seen.add(v);
    }
  }

  return Array.from(seen).sort((a, b) => a - b);
}

export default function parseCron(expression: string): CronExpression {
  if (typeof expression !== "string") {
    throw new TypeError(`parseCron expects a string, got ${typeof expression}`);
  }

  const trimmed = expression.trim();
  if (trimmed === "") {
    throw new SyntaxError("Cron expression must not be empty");
  }

  const fields = trimmed.split(/\s+/);

  if (fields.length !== 5) {
    throw new SyntaxError(
      `Cron expression must have exactly 5 fields (minute hour dayOfMonth month dayOfWeek), got ${fields.length}: "${expression}"`
    );
  }

  const [minuteRaw, hourRaw, domRaw, monthRaw, dowRaw] = fields;

  return {
    minute:     parseField(minuteRaw, FIELD_CONFIGS[0]),
    hour:       parseField(hourRaw,   FIELD_CONFIGS[1]),
    dayOfMonth: parseField(domRaw,    FIELD_CONFIGS[2]),
    month:      parseField(monthRaw,  FIELD_CONFIGS[3]),
    dayOfWeek:  parseField(dowRaw,    FIELD_CONFIGS[4]),
  };
}

interface CronFields {
  minute: number[];
  hour: number[];
  dayOfMonth: number[];
  month: number[];
  dayOfWeek: number[];
}

const FIELD_RANGES: Record<keyof CronFields, { min: number; max: number }> = {
  minute:     { min: 0,  max: 59 },
  hour:       { min: 0,  max: 23 },
  dayOfMonth: { min: 1,  max: 31 },
  month:      { min: 1,  max: 12 },
  dayOfWeek:  { min: 0,  max: 6  },
};

const clamp = (value: number, min: number, max: number): number => {
  if (value < min || value > max) {
    throw new RangeError(`Value ${value} is out of range [${min}, ${max}]`);
  }
  return value;
};

const range = (start: number, end: number): number[] =>
  Array.from({ length: end - start + 1 }, (_, i) => start + i);

const parseSegment = (segment: string, min: number, max: number): number[] => {
  // Wildcard
  if (segment === "*") {
    return range(min, max);
  }

  // Step value: */n or start-end/n
  if (segment.includes("/")) {
    const [rangePart, stepStr] = segment.split("/");
    const step = parseInt(stepStr, 10);

    if (isNaN(step) || step < 1) {
      throw new Error(`Invalid step value: "${stepStr}"`);
    }

    let start: number;
    let end: number;

    if (rangePart === "*") {
      start = min;
      end = max;
    } else if (rangePart.includes("-")) {
      const [startStr, endStr] = rangePart.split("-");
      start = clamp(parseInt(startStr, 10), min, max);
      end   = clamp(parseInt(endStr,   10), min, max);
      if (start > end) throw new Error(`Invalid range: "${rangePart}"`);
    } else {
      start = clamp(parseInt(rangePart, 10), min, max);
      end   = max;
    }

    const values: number[] = [];
    for (let i = start; i <= end; i += step) values.push(i);
    return values;
  }

  // Range: start-end
  if (segment.includes("-")) {
    const [startStr, endStr] = segment.split("-");
    const start = clamp(parseInt(startStr, 10), min, max);
    const end   = clamp(parseInt(endStr,   10), min, max);
    if (start > end) throw new Error(`Invalid range: "${segment}"`);
    return range(start, end);
  }

  // Comma-separated list
  if (segment.includes(",")) {
    const values = segment
      .split(",")
      .map((s) => s.trim())
      .flatMap((s) => parseSegment(s, min, max));
    return [...new Set(values)].sort((a, b) => a - b);
  }

  // Single number
  const value = parseInt(segment, 10);
  if (isNaN(value)) throw new Error(`Invalid cron value: "${segment}"`);
  return [clamp(value, min, max)];
};

const parseCron = (expression: string): CronFields => {
  const fields = expression.trim().split(/\s+/);

  if (fields.length !== 5) {
    throw new Error(
      `Invalid cron expression: expected 5 fields, got ${fields.length}`
    );
  }

  const [minuteStr, hourStr, domStr, monthStr, dowStr] = fields;
  const fieldNames = Object.keys(FIELD_RANGES) as (keyof CronFields)[];
  const segments   = [minuteStr, hourStr, domStr, monthStr, dowStr];

  const result = {} as CronFields;

  for (let i = 0; i < fieldNames.length; i++) {
    const name           = fieldNames[i];
    const { min, max }   = FIELD_RANGES[name];
    const parsed         = parseSegment(segments[i], min, max);
    result[name]         = [...new Set(parsed)].sort((a, b) => a - b);
  }

  return result;
};

export default parseCron;

type RateLimiterOptions = {
  maxTokens: number;
  refillRate: number;
  refillIntervalMs: number;
};

type Waiter = {
  tokens: number;
  resolve: () => void;
  reject: (err: Error) => void;
};

class RateLimiter {
  private readonly maxTokens: number;
  private readonly refillRate: number;
  private readonly refillIntervalMs: number;
  private currentTokens: number;
  private lastRefillTime: number;
  private readonly waitQueue: Waiter[];
  private scheduledDrain: ReturnType<typeof setTimeout> | null;

  constructor(options: RateLimiterOptions) {
    const { maxTokens, refillRate, refillIntervalMs } = options;

    if (!Number.isFinite(maxTokens) || maxTokens <= 0) {
      throw new RangeError(`maxTokens must be a positive finite number, got ${maxTokens}`);
    }
    if (!Number.isFinite(refillRate) || refillRate <= 0) {
      throw new RangeError(`refillRate must be a positive finite number, got ${refillRate}`);
    }
    if (!Number.isFinite(refillIntervalMs) || refillIntervalMs <= 0) {
      throw new RangeError(`refillIntervalMs must be a positive finite number, got ${refillIntervalMs}`);
    }

    this.maxTokens = maxTokens;
    this.refillRate = refillRate;
    this.refillIntervalMs = refillIntervalMs;
    this.currentTokens = maxTokens;
    this.lastRefillTime = Date.now();
    this.waitQueue = [];
    this.scheduledDrain = null;
  }

  private refill(): void {
    const now = Date.now();
    // Guard against backwards clock skew — never subtract tokens due to time anomalies.
    const elapsed = Math.max(0, now - this.lastRefillTime);
    if (elapsed > 0) {
      const tokensToAdd = (elapsed / this.refillIntervalMs) * this.refillRate;
      // Cap to maxTokens; also guard against NaN propagation from extreme elapsed values.
      this.currentTokens = Math.min(this.maxTokens, this.currentTokens + tokensToAdd);
      this.lastRefillTime = now;
    }
  }

  private msUntilAvailable(needed: number): number {
    if (this.currentTokens >= needed) return 0;
    const deficit = needed - this.currentTokens;
    // Ceiling to avoid waking up just a hair too early and looping.
    return Math.ceil((deficit / this.refillRate) * this.refillIntervalMs);
  }

  private scheduleDrain(): void {
    // Only one outstanding drain timer at a time; skip if queue is already empty.
    if (this.scheduledDrain !== null || this.waitQueue.length === 0) return;

    this.refill();
    const delay = this.msUntilAvailable(this.waitQueue[0].tokens);

    this.scheduledDrain = setTimeout(() => {
      this.scheduledDrain = null;
      this.drainQueue();
    }, delay);
  }

  private drainQueue(): void {
    this.refill();

    while (this.waitQueue.length > 0) {
      const next = this.waitQueue[0];
      if (this.currentTokens >= next.tokens) {
        this.currentTokens -= next.tokens;
        this.waitQueue.shift();
        next.resolve();
        // After resolving, re-refill to catch time that passed during microtask processing.
        this.refill();
      } else {
        // Not enough tokens yet — schedule a wakeup and stop processing.
        this.scheduleDrain();
        break;
      }
    }
  }

  private validateTokenArg(tokens: number, label = "tokens"): void {
    if (!Number.isFinite(tokens) || tokens < 0) {
      throw new RangeError(`${label} must be a non-negative finite number, got ${tokens}`);
    }
  }

  tryConsume(tokens = 1): boolean {
    this.validateTokenArg(tokens);
    if (tokens === 0) return true;

    // A request that can never be satisfied should fail fast rather than silently lie.
    if (tokens > this.maxTokens) return false;

    this.refill();

    if (this.currentTokens >= tokens) {
      this.currentTokens -= tokens;
      return true;
    }

    return false;
  }

  getTokens(): number {
    this.refill();
    return this.currentTokens;
  }

  reset(): void {
    this.currentTokens = this.maxTokens;
    this.lastRefillTime = Date.now();

    // Cancel any pending drain; a fresh one will be scheduled if still needed.
    if (this.scheduledDrain !== null) {
      clearTimeout(this.scheduledDrain);
      this.scheduledDrain = null;
    }

    // Immediately service any waiting callers that can now be satisfied.
    if (this.waitQueue.length > 0) {
      this.drainQueue();
    }
  }

  waitForTokens(tokens = 1): Promise<void> {
    try {
      this.validateTokenArg(tokens);
    } catch (err) {
      return Promise.reject(err);
    }

    if (tokens === 0) return Promise.resolve();

    if (tokens > this.maxTokens) {
      return Promise.reject(
        new RangeError(
          `Requested ${tokens} tokens exceeds the bucket's maximum capacity of ${this.maxTokens} — ` +
            "this request can never be satisfied."
        )
      );
    }

    this.refill();

    // Fast path: no queue backlog and sufficient tokens available right now.
    if (this.waitQueue.length === 0 && this.currentTokens >= tokens) {
      this.currentTokens -= tokens;
      return Promise.resolve();
    }

    // Slow path: enqueue and let the drain loop handle it in FIFO order.
    return new Promise<void>((resolve, reject) => {
      this.waitQueue.push({ tokens, resolve, reject });
      this.scheduleDrain();
    });
  }
}

export default RateLimiter;

interface RateLimiterOptions {
  maxTokens: number;
  refillRate: number;
  refillIntervalMs: number;
}

interface Waiter {
  tokens: number;
  resolve: () => void;
  reject: (err: Error) => void;
}

export class RateLimiter {
  private readonly maxTokens: number;
  private readonly refillRate: number;
  private readonly refillIntervalMs: number;
  private currentTokens: number;
  private lastRefillTime: number;
  private readonly waitQueue: Waiter[];
  private scheduledDrain: ReturnType<typeof setTimeout> | null;

  constructor(options: RateLimiterOptions) {
    if (!Number.isFinite(options.maxTokens) || options.maxTokens <= 0) {
      throw new RangeError("maxTokens must be a positive finite number");
    }
    if (!Number.isFinite(options.refillRate) || options.refillRate < 0) {
      throw new RangeError("refillRate must be a non-negative finite number");
    }
    if (!Number.isFinite(options.refillIntervalMs) || options.refillIntervalMs <= 0) {
      throw new RangeError("refillIntervalMs must be a positive finite number");
    }

    this.maxTokens = options.maxTokens;
    this.refillRate = options.refillRate;
    this.refillIntervalMs = options.refillIntervalMs;
    this.currentTokens = options.maxTokens;
    this.lastRefillTime = Date.now();
    this.waitQueue = [];
    this.scheduledDrain = null;
  }

  private applyRefill(): void {
    const now = Date.now();
    const elapsed = now - this.lastRefillTime;

    if (elapsed > 0 && this.refillRate > 0) {
      const tokensToAdd = (elapsed / this.refillIntervalMs) * this.refillRate;
      this.currentTokens = Math.min(this.maxTokens, this.currentTokens + tokensToAdd);
    }

    this.lastRefillTime = now;
  }

  private msUntilAvailable(tokens: number): number {
    if (this.currentTokens >= tokens) return 0;
    if (this.refillRate <= 0) return Infinity;

    const deficit = tokens - this.currentTokens;
    return Math.ceil((deficit / this.refillRate) * this.refillIntervalMs);
  }

  private drainQueue(): void {
    this.scheduledDrain = null;

    while (this.waitQueue.length > 0) {
      const waiter = this.waitQueue[0];
      this.applyRefill();

      if (this.currentTokens >= waiter.tokens) {
        this.currentTokens -= waiter.tokens;
        this.waitQueue.shift();
        waiter.resolve();
      } else {
        this.scheduleNextDrain();
        return;
      }
    }
  }

  private scheduleNextDrain(): void {
    if (this.scheduledDrain !== null || this.waitQueue.length === 0) return;

    const waiter = this.waitQueue[0];
    const delay = this.msUntilAvailable(waiter.tokens);

    if (!Number.isFinite(delay)) {
      // Tokens can never accumulate — reject all queued waiters
      while (this.waitQueue.length > 0) {
        this.waitQueue
          .shift()!
          .reject(
            new Error(
              "Cannot wait for tokens: refillRate is 0 and tokens are insufficient"
            )
          );
      }
      return;
    }

    this.scheduledDrain = setTimeout(() => this.drainQueue(), delay);
  }

  tryConsume(tokens: number = 1): boolean {
    if (!Number.isFinite(tokens) || tokens <= 0) {
      throw new RangeError("tokens must be a positive finite number");
    }
    if (tokens > this.maxTokens) return false;

    this.applyRefill();

    if (this.currentTokens >= tokens) {
      this.currentTokens -= tokens;
      return true;
    }

    return false;
  }

  getTokens(): number {
    this.applyRefill();
    return this.currentTokens;
  }

  reset(): void {
    this.currentTokens = this.maxTokens;
    this.lastRefillTime = Date.now();

    // Opportunistically serve any queued waiters now that bucket is full
    if (this.waitQueue.length > 0) {
      if (this.scheduledDrain !== null) {
        clearTimeout(this.scheduledDrain);
        this.scheduledDrain = null;
      }
      this.drainQueue();
    }
  }

  waitForTokens(tokens: number = 1): Promise<void> {
    if (!Number.isFinite(tokens) || tokens <= 0) {
      return Promise.reject(new RangeError("tokens must be a positive finite number"));
    }
    if (tokens > this.maxTokens) {
      return Promise.reject(
        new RangeError(
          `Requested ${tokens} tokens exceeds bucket capacity of ${this.maxTokens}`
        )
      );
    }

    // Fast path: no queue backlog and enough tokens available right now
    if (this.waitQueue.length === 0) {
      this.applyRefill();
      if (this.currentTokens >= tokens) {
        this.currentTokens -= tokens;
        return Promise.resolve();
      }
    }

    return new Promise<void>((resolve, reject) => {
      this.waitQueue.push({ tokens, resolve, reject });
      this.scheduleNextDrain();
    });
  }
}

export default RateLimiter;

export class RateLimiter {
  private readonly maxTokens: number;
  private readonly refillRate: number;
  private readonly refillIntervalMs: number;
  private tokens: number;
  private lastRefillAt: number;
  private readonly queue: Array<{ needed: number; resolve: () => void }>;
  private wakeTimer: ReturnType<typeof setTimeout> | null;

  constructor(options: { maxTokens: number; refillRate: number; refillIntervalMs: number }) {
    const { maxTokens, refillRate, refillIntervalMs } = options;

    if (!Number.isFinite(maxTokens) || maxTokens <= 0) {
      throw new RangeError("maxTokens must be a positive finite number");
    }
    if (!Number.isFinite(refillRate) || refillRate < 0) {
      throw new RangeError("refillRate must be a non-negative finite number");
    }
    if (!Number.isFinite(refillIntervalMs) || refillIntervalMs <= 0) {
      throw new RangeError("refillIntervalMs must be a positive finite number");
    }

    this.maxTokens = maxTokens;
    this.refillRate = refillRate;
    this.refillIntervalMs = refillIntervalMs;
    this.tokens = maxTokens;
    this.lastRefillAt = Date.now();
    this.queue = [];
    this.wakeTimer = null;
  }

  private applyRefill(): void {
    const now = Date.now();
    const elapsed = now - this.lastRefillAt;
    const intervals = Math.floor(elapsed / this.refillIntervalMs);
    if (intervals > 0) {
      this.tokens = Math.min(this.maxTokens, this.tokens + intervals * this.refillRate);
      // Advance by whole intervals only — preserves sub-interval remainder
      this.lastRefillAt += intervals * this.refillIntervalMs;
    }
  }

  tryConsume(tokens = 1): boolean {
    if (!Number.isFinite(tokens) || tokens < 0) {
      throw new RangeError("tokens must be a non-negative finite number");
    }
    if (tokens === 0) return true;
    // A request that can never fit the bucket is permanently unsatisfiable
    if (tokens > this.maxTokens) return false;

    this.applyRefill();

    if (this.tokens >= tokens) {
      this.tokens -= tokens;
      return true;
    }
    return false;
  }

  getTokens(): number {
    this.applyRefill();
    return this.tokens;
  }

  reset(): void {
    if (this.wakeTimer !== null) {
      clearTimeout(this.wakeTimer);
      this.wakeTimer = null;
    }
    this.tokens = this.maxTokens;
    this.lastRefillAt = Date.now();
    // Give queued waiters a chance — bucket is now full
    this.flushQueue();
  }

  waitForTokens(tokens = 1): Promise<void> {
    if (!Number.isFinite(tokens) || tokens < 0) {
      return Promise.reject(new RangeError("tokens must be a non-negative finite number"));
    }
    if (tokens > this.maxTokens) {
      return Promise.reject(
        new RangeError(
          `Requested ${tokens} tokens exceeds bucket capacity of ${this.maxTokens}; can never be satisfied`
        )
      );
    }
    if (tokens === 0) return Promise.resolve();

    this.applyRefill();

    // Fast path: queue is empty and there are enough tokens right now
    if (this.queue.length === 0 && this.tokens >= tokens) {
      this.tokens -= tokens;
      return Promise.resolve();
    }

    // If the bucket never refills and we can't satisfy immediately, this will deadlock forever
    if (this.refillRate === 0) {
      return Promise.reject(
        new Error(
          "waitForTokens cannot proceed: refillRate is 0 and current tokens are insufficient"
        )
      );
    }

    return new Promise<void>((resolve) => {
      this.queue.push({ needed: tokens, resolve });
      this.scheduleNextWake();
    });
  }

  /** Drain FIFO queue as far as current tokens allow. */
  private flushQueue(): void {
    while (this.queue.length > 0) {
      const head = this.queue[0];
      if (this.tokens >= head.needed) {
        this.tokens -= head.needed;
        this.queue.shift();
        head.resolve();
      } else {
        break;
      }
    }
  }

  /** Schedule a single timer to fire exactly when the head waiter can be unblocked. */
  private scheduleNextWake(): void {
    // Only one timer drives the queue at a time
    if (this.wakeTimer !== null || this.queue.length === 0) return;

    const head = this.queue[0];
    const deficit = head.needed - this.tokens;

    if (deficit <= 0) {
      // Already satisfiable (edge case guard)
      this.flushQueue();
      this.scheduleNextWake();
      return;
    }

    const intervalsNeeded = Math.ceil(deficit / this.refillRate);
    const msSinceLastRefill = Date.now() - this.lastRefillAt;
    const msUntilNextRefill = this.refillIntervalMs - (msSinceLastRefill % this.refillIntervalMs);
    // Total delay: wait for the refill interval that pushes us over the deficit
    const delay = msUntilNextRefill + (intervalsNeeded - 1) * this.refillIntervalMs;

    this.wakeTimer = setTimeout(() => {
      this.wakeTimer = null;
      this.applyRefill();
      this.flushQueue();
      // If more waiters remain, schedule the next wake immediately
      this.scheduleNextWake();
    }, Math.max(0, delay) + 1); // +1 ms guards against sub-ms timer imprecision
  }
}

export default RateLimiter;

interface CronResult {
  minute: number[];
  hour: number[];
  dayOfMonth: number[];
  month: number[];
  dayOfWeek: number[];
}

type FieldName = keyof CronResult;

interface FieldConfig {
  readonly min: number;
  readonly max: number;
}

const FIELD_CONFIGS: Readonly<Record<FieldName, FieldConfig>> = {
  minute:     { min: 0,  max: 59 },
  hour:       { min: 0,  max: 23 },
  dayOfMonth: { min: 1,  max: 31 },
  month:      { min: 1,  max: 12 },
  dayOfWeek:  { min: 0,  max: 6  },
};

const FIELD_ORDER: readonly FieldName[] = [
  "minute",
  "hour",
  "dayOfMonth",
  "month",
  "dayOfWeek",
];

function parseStrictInt(raw: string): number {
  if (!/^\d+$/.test(raw)) {
    throw new Error(`"${raw}" is not a valid non-negative integer`);
  }
  return Number(raw);
}

function assertInRange(value: number, config: FieldConfig, context: string): void {
  if (value < config.min || value > config.max) {
    throw new Error(
      `${context}: value ${value} is outside the valid range [${config.min}, ${config.max}]`
    );
  }
}

function expandValues(
  start: number,
  end: number,
  step: number,
  config: FieldConfig,
  context: string
): number[] {
  assertInRange(start, config, `${context} range start`);
  assertInRange(end, config, `${context} range end`);

  if (start > end) {
    throw new Error(`${context}: range start (${start}) must not exceed range end (${end})`);
  }
  if (step < 1) {
    throw new Error(`${context}: step (${step}) must be >= 1`);
  }

  const values: number[] = [];
  for (let v = start; v <= end; v += step) {
    values.push(v);
  }
  return values;
}

function parseAtom(token: string, config: FieldConfig, context: string): number[] {
  // Step value: */step  |  start/step  |  start-end/step
  if (token.includes("/")) {
    const slashIndex = token.indexOf("/");
    const lhs = token.slice(0, slashIndex);
    const rhs = token.slice(slashIndex + 1);

    if (rhs.includes("/")) {
      throw new Error(`${context}: only one '/' allowed per token`);
    }

    const step = parseStrictInt(rhs);

    if (lhs === "*") {
      return expandValues(config.min, config.max, step, config, context);
    }

    if (lhs.includes("-")) {
      const dashIndex = lhs.indexOf("-");
      const start = parseStrictInt(lhs.slice(0, dashIndex));
      const end = parseStrictInt(lhs.slice(dashIndex + 1));
      return expandValues(start, end, step, config, context);
    }

    const start = parseStrictInt(lhs);
    return expandValues(start, config.max, step, config, context);
  }

  // Wildcard
  if (token === "*") {
    return expandValues(config.min, config.max, 1, config, context);
  }

  // Range: start-end
  if (token.includes("-")) {
    const dashIndex = token.indexOf("-");
    const start = parseStrictInt(token.slice(0, dashIndex));
    const end = parseStrictInt(token.slice(dashIndex + 1));
    return expandValues(start, end, 1, config, context);
  }

  // Single value
  const value = parseStrictInt(token);
  assertInRange(value, config, `${context} single value`);
  return [value];
}

function parseField(raw: string, config: FieldConfig, fieldName: string): number[] {
  if (raw.length === 0) {
    throw new Error(`${fieldName}: field must not be empty`);
  }

  const parts = raw.split(",");
  const seen = new Set<number>();

  for (const part of parts) {
    const trimmed = part.trim();
    if (trimmed.length === 0) {
      throw new Error(`${fieldName}: empty element in comma-separated list`);
    }

    const values = parseAtom(trimmed, config, fieldName);
    for (const v of values) {
      seen.add(v);
    }
  }

  return Array.from(seen).sort((a, b) => a - b);
}

export default function parseCron(expression: string): CronResult {
  if (typeof expression !== "string") {
    throw new TypeError("parseCron: expression must be a string");
  }

  const trimmed = expression.trim();
  if (trimmed.length === 0) {
    throw new Error("parseCron: expression must not be empty");
  }

  const tokens = trimmed.split(/\s+/);

  if (tokens.length !== 5) {
    throw new Error(
      `parseCron: expected exactly 5 fields (minute hour dayOfMonth month dayOfWeek), got ${tokens.length}`
    );
  }

  const result = {} as CronResult;

  for (let i = 0; i < FIELD_ORDER.length; i++) {
    const name = FIELD_ORDER[i];
    result[name] = parseField(tokens[i], FIELD_CONFIGS[name], name);
  }

  return result;
}

export class RateLimiter {
  private readonly maxTokens: number;
  private readonly refillRate: number;
  private readonly refillIntervalMs: number;
  private currentTokens: number;
  private lastRefillTime: number;
  private readonly waitQueue: Array<{ tokens: number; resolve: () => void }>;
  private drainScheduled: boolean;

  constructor(options: {
    maxTokens: number;
    refillRate: number;
    refillIntervalMs: number;
  }) {
    if (!Number.isFinite(options.maxTokens) || options.maxTokens <= 0)
      throw new RangeError("maxTokens must be a finite positive number");
    if (!Number.isFinite(options.refillRate) || options.refillRate <= 0)
      throw new RangeError("refillRate must be a finite positive number");
    if (
      !Number.isFinite(options.refillIntervalMs) ||
      options.refillIntervalMs <= 0
    )
      throw new RangeError("refillIntervalMs must be a finite positive number");

    this.maxTokens = options.maxTokens;
    this.refillRate = options.refillRate;
    this.refillIntervalMs = options.refillIntervalMs;
    this.currentTokens = options.maxTokens;
    this.lastRefillTime = Date.now();
    this.waitQueue = [];
    this.drainScheduled = false;
  }

  private lazyRefill(): void {
    const now = Date.now();
    const elapsed = now - this.lastRefillTime;
    if (elapsed <= 0) return;

    const tokensToAdd = (elapsed / this.refillIntervalMs) * this.refillRate;
    if (tokensToAdd > 0) {
      this.currentTokens = Math.min(
        this.maxTokens,
        this.currentTokens + tokensToAdd
      );
      this.lastRefillTime = now;
    }
  }

  tryConsume(tokens: number = 1): boolean {
    if (!Number.isFinite(tokens) || tokens < 0)
      throw new RangeError("tokens must be a finite non-negative number");
    if (tokens === 0) return true;
    if (tokens > this.maxTokens) return false;

    this.lazyRefill();

    if (this.currentTokens >= tokens) {
      this.currentTokens -= tokens;
      return true;
    }

    return false;
  }

  getTokens(): number {
    this.lazyRefill();
    return this.currentTokens;
  }

  reset(): void {
    this.currentTokens = this.maxTokens;
    this.lastRefillTime = Date.now();
    this.drainQueue();
  }

  waitForTokens(tokens: number = 1): Promise<void> {
    if (!Number.isFinite(tokens) || tokens < 0)
      return Promise.reject(
        new RangeError("tokens must be a finite non-negative number")
      );
    if (tokens > this.maxTokens)
      return Promise.reject(
        new RangeError(
          `tokens (${tokens}) exceeds maxTokens (${this.maxTokens}); request can never be satisfied`
        )
      );
    if (tokens === 0) return Promise.resolve();

    if (this.waitQueue.length === 0 && this.tryConsume(tokens)) {
      return Promise.resolve();
    }

    return new Promise<void>((resolve) => {
      this.waitQueue.push({ tokens, resolve });
      this.scheduleQueueDrain();
    });
  }

  private drainQueue(): void {
    this.lazyRefill();

    while (this.waitQueue.length > 0) {
      const next = this.waitQueue[0];
      if (this.currentTokens >= next.tokens) {
        this.currentTokens -= next.tokens;
        this.waitQueue.shift();
        next.resolve();
      } else {
        break;
      }
    }

    if (this.waitQueue.length > 0) {
      this.scheduleQueueDrain();
    } else {
      this.drainScheduled = false;
    }
  }

  private scheduleQueueDrain(): void {
    if (this.drainScheduled || this.waitQueue.length === 0) return;

    const next = this.waitQueue[0];
    const needed = next.tokens - this.currentTokens;
    const delayMs =
      needed > 0
        ? Math.ceil((needed / this.refillRate) * this.refillIntervalMs)
        : 0;

    this.drainScheduled = true;
    setTimeout(() => {
      this.drainScheduled = false;
      this.drainQueue();
    }, Math.max(1, delayMs));
  }
}

export default RateLimiter;

interface RateLimiterOptions {
  maxTokens: number;
  refillRate: number;
  refillIntervalMs: number;
}

export class RateLimiter {
  private readonly maxTokens: number;
  private readonly refillRate: number;
  private readonly refillIntervalMs: number;
  private currentTokens: number;
  private lastRefillTime: number;

  constructor(options: RateLimiterOptions) {
    if (options.maxTokens <= 0) throw new RangeError("maxTokens must be > 0");
    if (options.refillRate <= 0) throw new RangeError("refillRate must be > 0");
    if (options.refillIntervalMs <= 0) throw new RangeError("refillIntervalMs must be > 0");

    this.maxTokens = options.maxTokens;
    this.refillRate = options.refillRate;
    this.refillIntervalMs = options.refillIntervalMs;
    this.currentTokens = options.maxTokens;
    this.lastRefillTime = Date.now();
  }

  private refill(): void {
    const now = Date.now();
    const elapsed = now - this.lastRefillTime;
    const intervals = Math.floor(elapsed / this.refillIntervalMs);

    if (intervals > 0) {
      this.currentTokens = Math.min(
        this.maxTokens,
        this.currentTokens + intervals * this.refillRate
      );
      this.lastRefillTime += intervals * this.refillIntervalMs;
    }
  }

  tryConsume(tokens: number = 1): boolean {
    if (tokens <= 0) throw new RangeError("tokens to consume must be > 0");
    if (tokens > this.maxTokens) return false;

    this.refill();

    if (this.currentTokens >= tokens) {
      this.currentTokens -= tokens;
      return true;
    }

    return false;
  }

  getTokens(): number {
    this.refill();
    return this.currentTokens;
  }

  reset(): void {
    this.currentTokens = this.maxTokens;
    this.lastRefillTime = Date.now();
  }

  waitForTokens(tokens: number = 1): Promise<void> {
    if (tokens <= 0) return Promise.reject(new RangeError("tokens to consume must be > 0"));
    if (tokens > this.maxTokens) return Promise.reject(new RangeError("tokens requested exceeds maxTokens"));

    return new Promise((resolve) => {
      const attempt = (): void => {
        if (this.tryConsume(tokens)) {
          resolve();
          return;
        }

        this.refill();
        const tokensNeeded = tokens - this.currentTokens;
        const intervalsNeeded = Math.ceil(tokensNeeded / this.refillRate);
        const msUntilRefill = this.refillIntervalMs - (Date.now() - this.lastRefillTime);
        const delay = Math.max(0, msUntilRefill + (intervalsNeeded - 1) * this.refillIntervalMs);

        setTimeout(attempt, delay);
      };

      attempt();
    });
  }
}

export default RateLimiter;

export interface CronFields {
  minute: number[];
  hour: number[];
  dayOfMonth: number[];
  month: number[];
  dayOfWeek: number[];
}

const FIELD_CONFIG: Array<{ name: keyof CronFields; min: number; max: number }> = [
  { name: "minute",     min: 0, max: 59 },
  { name: "hour",       min: 0, max: 23 },
  { name: "dayOfMonth", min: 1, max: 31 },
  { name: "month",      min: 1, max: 12 },
  { name: "dayOfWeek",  min: 0, max: 6  },
];

function assertInRange(value: number, min: number, max: number, context: string): void {
  if (!Number.isInteger(value) || value < min || value > max) {
    throw new RangeError(`${context}: value ${value} out of valid range [${min}, ${max}]`);
  }
}

function parseRange(token: string, min: number, max: number, context: string): [number, number] {
  const dashIndex = token.indexOf("-");
  if (dashIndex <= 0 || dashIndex === token.length - 1) {
    throw new SyntaxError(`${context}: malformed range "${token}"`);
  }
  const start = Number(token.slice(0, dashIndex));
  const end   = Number(token.slice(dashIndex + 1));
  if (!Number.isInteger(start) || !Number.isInteger(end)) {
    throw new SyntaxError(`${context}: non-integer bounds in range "${token}"`);
  }
  assertInRange(start, min, max, `${context} range start`);
  assertInRange(end,   min, max, `${context} range end`);
  if (start > end) {
    throw new RangeError(`${context}: range start ${start} exceeds end ${end}`);
  }
  return [start, end];
}

function expandRange(start: number, end: number, step: number): number[] {
  const values: number[] = [];
  for (let i = start; i <= end; i += step) {
    values.push(i);
  }
  return values;
}

function parseAtom(token: string, min: number, max: number, context: string): number[] {
  // Step expression: base/step — base may be *, a number, or a range
  const slashIndex = token.indexOf("/");
  if (slashIndex !== -1) {
    const basePart = token.slice(0, slashIndex);
    const stepPart = token.slice(slashIndex + 1);
    const step = Number(stepPart);
    if (!Number.isInteger(step) || step <= 0) {
      throw new RangeError(`${context}: invalid step value "${stepPart}" — must be a positive integer`);
    }

    let rangeStart: number;
    let rangeEnd: number;

    if (basePart === "*") {
      rangeStart = min;
      rangeEnd   = max;
    } else if (basePart.includes("-")) {
      [rangeStart, rangeEnd] = parseRange(basePart, min, max, context);
    } else {
      const base = Number(basePart);
      if (!Number.isInteger(base)) {
        throw new SyntaxError(`${context}: non-integer base "${basePart}" in step expression`);
      }
      assertInRange(base, min, max, `${context} step base`);
      rangeStart = base;
      rangeEnd   = max;
    }

    return expandRange(rangeStart, rangeEnd, step);
  }

  // Wildcard
  if (token === "*") {
    return expandRange(min, max, 1);
  }

  // Range expression
  if (token.includes("-")) {
    const [start, end] = parseRange(token, min, max, context);
    return expandRange(start, end, 1);
  }

  // Plain integer
  const value = Number(token);
  if (!Number.isInteger(value)) {
    throw new SyntaxError(`${context}: unrecognised token "${token}"`);
  }
  assertInRange(value, min, max, context);
  return [value];
}

function parseField(raw: string, min: number, max: number, context: string): number[] {
  if (raw == null || raw === "") {
    throw new SyntaxError(`${context}: field must not be empty`);
  }

  const seen = new Set<number>();

  for (const part of raw.split(",")) {
    const trimmed = part.trim();
    if (trimmed === "") {
      throw new SyntaxError(`${context}: empty element in comma-separated list`);
    }
    for (const v of parseAtom(trimmed, min, max, context)) {
      seen.add(v);
    }
  }

  return Array.from(seen).sort((a, b) => a - b);
}

export default function parseCron(expression: string): CronFields {
  if (typeof expression !== "string") {
    throw new TypeError("parseCron: expression must be a string");
  }

  const trimmed = expression.trim();
  if (trimmed === "") {
    throw new SyntaxError("parseCron: expression must not be empty");
  }

  const parts = trimmed.split(/\s+/);
  if (parts.length !== 5) {
    throw new SyntaxError(
      `parseCron: expected exactly 5 fields, got ${parts.length} — "${trimmed}"`
    );
  }

  const result = {} as CronFields;

  for (let i = 0; i < FIELD_CONFIG.length; i++) {
    const { name, min, max } = FIELD_CONFIG[i];
    result[name] = parseField(parts[i], min, max, `field[${i}] (${name})`);
  }

  return result;
}

interface CronExpression {
  minute: number[];
  hour: number[];
  dayOfMonth: number[];
  month: number[];
  dayOfWeek: number[];
}

interface FieldConfig {
  readonly name: keyof CronExpression;
  readonly min: number;
  readonly max: number;
}

const FIELD_CONFIGS: readonly FieldConfig[] = [
  { name: "minute",     min: 0,  max: 59 },
  { name: "hour",       min: 0,  max: 23 },
  { name: "dayOfMonth", min: 1,  max: 31 },
  { name: "month",      min: 1,  max: 12 },
  { name: "dayOfWeek",  min: 0,  max: 6  },
];

function assertInRange(value: number, min: number, max: number, context: string): void {
  if (!Number.isInteger(value) || value < min || value > max) {
    throw new RangeError(`Value ${value} is out of valid range [${min}, ${max}] in segment "${context}"`);
  }
}

function parseInteger(raw: string, context: string): number {
  const trimmed = raw.trim();
  if (trimmed === "" || !/^-?\d+$/.test(trimmed)) {
    throw new TypeError(`Expected an integer but got "${trimmed}" in segment "${context}"`);
  }
  return parseInt(trimmed, 10);
}

function expandStep(rangeMin: number, rangeMax: number, step: number, context: string): number[] {
  if (!Number.isInteger(step) || step <= 0) {
    throw new RangeError(`Step must be a positive integer in segment "${context}"`);
  }
  const result: number[] = [];
  for (let i = rangeMin; i <= rangeMax; i += step) {
    result.push(i);
  }
  return result;
}

function parseSegment(segment: string, min: number, max: number): number[] {
  // Guard against obviously malformed input early
  if (/\s/.test(segment)) {
    throw new SyntaxError(`Unexpected whitespace inside segment "${segment}"`);
  }

  // Step expression: (range|*)/N
  if (segment.includes("/")) {
    const slashParts = segment.split("/");
    if (slashParts.length !== 2) {
      throw new SyntaxError(`Invalid step expression "${segment}": expected exactly one "/"`);
    }
    const [rangePart, stepStr] = slashParts;
    const step = parseInteger(stepStr, segment);

    if (rangePart === "*") {
      return expandStep(min, max, step, segment);
    }

    if (rangePart.includes("-")) {
      const dashParts = rangePart.split("-");
      if (dashParts.length !== 2) {
        throw new SyntaxError(`Invalid range in "${segment}"`);
      }
      const start = parseInteger(dashParts[0], segment);
      const end   = parseInteger(dashParts[1], segment);
      assertInRange(start, min, max, segment);
      assertInRange(end,   min, max, segment);
      if (start > end) {
        throw new RangeError(`Range start ${start} exceeds end ${end} in segment "${segment}"`);
      }
      return expandStep(start, end, step, segment);
    }

    // Single-value base with step: treat as base/step from base to max
    const base = parseInteger(rangePart, segment);
    assertInRange(base, min, max, segment);
    return expandStep(base, max, step, segment);
  }

  // Wildcard
  if (segment === "*") {
    const result: number[] = [];
    for (let i = min; i <= max; i++) result.push(i);
    return result;
  }

  // Range: N-M
  if (segment.includes("-")) {
    const dashParts = segment.split("-");
    if (dashParts.length !== 2) {
      throw new SyntaxError(`Invalid range "${segment}": expected exactly one "-"`);
    }
    const start = parseInteger(dashParts[0], segment);
    const end   = parseInteger(dashParts[1], segment);
    assertInRange(start, min, max, segment);
    assertInRange(end,   min, max, segment);
    if (start > end) {
      throw new RangeError(`Range start ${start} exceeds end ${end} in segment "${segment}"`);
    }
    const result: number[] = [];
    for (let i = start; i <= end; i++) result.push(i);
    return result;
  }

  // Single numeric value
  const value = parseInteger(segment, segment);
  assertInRange(value, min, max, segment);
  return [value];
}

function parseField(field: string, config: FieldConfig): number[] {
  if (field.trim() === "") {
    throw new SyntaxError(`Field "${config.name}" is empty`);
  }

  const { min, max } = config;
  const seen = new Set<number>();

  for (const segment of field.split(",")) {
    if (segment.trim() === "") {
      throw new SyntaxError(`Empty segment (trailing/leading comma?) in field "${config.name}": "${field}"`);
    }
    for (const v of parseSegment(segment, min, max)) {
      seen.add(v);
    }
  }

  if (seen.size === 0) {
    throw new RangeError(`Field "${config.name}" resolved to zero values from expression "${field}"`);
  }

  return Array.from(seen).sort((a, b) => a - b);
}

export default function parseCron(expression: string): CronExpression {
  if (typeof expression !== "string") {
    throw new TypeError(`parseCron expects a string, got ${typeof expression}`);
  }

  const fields = expression.trim().split(/\s+/);

  if (fields.length !== 5) {
    throw new SyntaxError(
      `Cron expression must have exactly 5 fields (got ${fields.length}): "${expression}"`
    );
  }

  const result = {} as CronExpression;

  for (let i = 0; i < FIELD_CONFIGS.length; i++) {
    const config = FIELD_CONFIGS[i];
    result[config.name] = parseField(fields[i], config);
  }

  return result;
}

interface RateLimiterOptions {
  maxTokens: number;
  refillRate: number;
  refillIntervalMs: number;
}

class RateLimiter {
  private readonly maxTokens: number;
  private readonly refillRate: number;
  private readonly refillIntervalMs: number;
  private currentTokens: number;
  private lastRefillTime: number;

  constructor(options: RateLimiterOptions) {
    if (options.maxTokens <= 0) throw new RangeError("maxTokens must be greater than 0");
    if (options.refillRate <= 0) throw new RangeError("refillRate must be greater than 0");
    if (options.refillIntervalMs <= 0) throw new RangeError("refillIntervalMs must be greater than 0");

    this.maxTokens = options.maxTokens;
    this.refillRate = options.refillRate;
    this.refillIntervalMs = options.refillIntervalMs;
    this.currentTokens = options.maxTokens;
    this.lastRefillTime = Date.now();
  }

  private refill(): void {
    const now = Date.now();
    const elapsed = now - this.lastRefillTime;
    const intervals = Math.floor(elapsed / this.refillIntervalMs);

    if (intervals > 0) {
      const tokensToAdd = intervals * this.refillRate;
      this.currentTokens = Math.min(this.maxTokens, this.currentTokens + tokensToAdd);
      this.lastRefillTime += intervals * this.refillIntervalMs;
    }
  }

  tryConsume(tokens: number = 1): boolean {
    if (tokens <= 0) throw new RangeError("tokens must be greater than 0");
    if (tokens > this.maxTokens) return false;

    this.refill();

    if (this.currentTokens >= tokens) {
      this.currentTokens -= tokens;
      return true;
    }

    return false;
  }

  getTokens(): number {
    this.refill();
    return this.currentTokens;
  }

  reset(): void {
    this.currentTokens = this.maxTokens;
    this.lastRefillTime = Date.now();
  }

  async waitForTokens(tokens: number = 1): Promise<void> {
    if (tokens <= 0) throw new RangeError("tokens must be greater than 0");
    if (tokens > this.maxTokens) {
      throw new RangeError(`Requested tokens (${tokens}) exceed maximum capacity (${this.maxTokens})`);
    }

    while (!this.tryConsume(tokens)) {
      this.refill();

      const deficit = tokens - this.currentTokens;
      const intervalsNeeded = Math.ceil(deficit / this.refillRate);
      const elapsed = Date.now() - this.lastRefillTime;
      const waitMs = Math.max(0, intervalsNeeded * this.refillIntervalMs - elapsed);

      await new Promise<void>((resolve) => setTimeout(resolve, waitMs || this.refillIntervalMs));
    }
  }
}

export default RateLimiter;

interface CronFields {
  minute: number[];
  hour: number[];
  dayOfMonth: number[];
  month: number[];
  dayOfWeek: number[];
}

interface FieldConfig {
  min: number;
  max: number;
}

const FIELD_CONFIGS: Record<keyof CronFields, FieldConfig> = {
  minute:     { min: 0,  max: 59 },
  hour:       { min: 0,  max: 23 },
  dayOfMonth: { min: 1,  max: 31 },
  month:      { min: 1,  max: 12 },
  dayOfWeek:  { min: 0,  max: 6  },
};

function rangeArray(start: number, end: number, step = 1): number[] {
  if (step <= 0) throw new Error(`Step must be a positive integer, got ${step}`);
  const result: number[] = [];
  for (let i = start; i <= end; i += step) {
    result.push(i);
  }
  return result;
}

function assertInRange(value: number, min: number, max: number, context: string): void {
  if (value < min || value > max) {
    throw new Error(`Value ${value} out of range [${min}, ${max}] in field "${context}"`);
  }
}

function parseSegment(segment: string, config: FieldConfig, fieldName: string): number[] {
  const { min, max } = config;

  // Wildcard with optional step: * or */n
  if (segment.startsWith("*")) {
    if (segment === "*") {
      return rangeArray(min, max);
    }
    if (segment.startsWith("*/")) {
      const stepStr = segment.slice(2);
      const step = parseInt(stepStr, 10);
      if (isNaN(step) || stepStr !== String(step)) {
        throw new Error(`Invalid step value "${stepStr}" in field "${fieldName}"`);
      }
      if (step <= 0) {
        throw new Error(`Step must be positive in field "${fieldName}"`);
      }
      return rangeArray(min, max, step);
    }
    throw new Error(`Invalid wildcard expression "${segment}" in field "${fieldName}"`);
  }

  // Range with optional step: n-m or n-m/s
  if (segment.includes("-")) {
    const slashIndex = segment.indexOf("/");
    const rangePart = slashIndex !== -1 ? segment.slice(0, slashIndex) : segment;
    const stepPart  = slashIndex !== -1 ? segment.slice(slashIndex + 1) : "1";

    const dashIndex = rangePart.indexOf("-");
    const startStr  = rangePart.slice(0, dashIndex);
    const endStr    = rangePart.slice(dashIndex + 1);

    const start = parseInt(startStr, 10);
    const end   = parseInt(endStr,   10);
    const step  = parseInt(stepPart, 10);

    if (isNaN(start) || startStr !== String(start)) throw new Error(`Invalid range start "${startStr}" in field "${fieldName}"`);
    if (isNaN(end)   || endStr   !== String(end))   throw new Error(`Invalid range end "${endStr}" in field "${fieldName}"`);
    if (isNaN(step)  || stepPart !== String(step))  throw new Error(`Invalid step "${stepPart}" in field "${fieldName}"`);
    if (step <= 0)  throw new Error(`Step must be positive in field "${fieldName}"`);
    if (start > end) throw new Error(`Range start ${start} > end ${end} in field "${fieldName}"`);

    assertInRange(start, min, max, fieldName);
    assertInRange(end,   min, max, fieldName);

    return rangeArray(start, end, step);
  }

  // Plain integer
  const value = parseInt(segment, 10);
  if (isNaN(value) || segment !== String(value)) {
    throw new Error(`Invalid value "${segment}" in field "${fieldName}"`);
  }
  assertInRange(value, min, max, fieldName);
  return [value];
}

function parseField(expression: string, config: FieldConfig, fieldName: string): number[] {
  const segments = expression.split(",");
  if (segments.length === 0) {
    throw new Error(`Empty field "${fieldName}"`);
  }

  const valueSet = new Set<number>();
  for (const segment of segments) {
    const trimmed = segment.trim();
    if (trimmed === "") {
      throw new Error(`Empty segment in field "${fieldName}"`);
    }
    for (const v of parseSegment(trimmed, config, fieldName)) {
      valueSet.add(v);
    }
  }

  return Array.from(valueSet).sort((a, b) => a - b);
}

function parseCron(expression: string): CronFields {
  if (typeof expression !== "string") {
    throw new Error("Cron expression must be a string");
  }

  const parts = expression.trim().split(/\s+/);
  if (parts.length !== 5) {
    throw new Error(
      `Cron expression must have exactly 5 fields, got ${parts.length}: "${expression}"`
    );
  }

  const [minuteExpr, hourExpr, domExpr, monthExpr, dowExpr] = parts;

  return {
    minute:     parseField(minuteExpr, FIELD_CONFIGS.minute,     "minute"),
    hour:       parseField(hourExpr,   FIELD_CONFIGS.hour,       "hour"),
    dayOfMonth: parseField(domExpr,    FIELD_CONFIGS.dayOfMonth, "dayOfMonth"),
    month:      parseField(monthExpr,  FIELD_CONFIGS.month,      "month"),
    dayOfWeek:  parseField(dowExpr,    FIELD_CONFIGS.dayOfWeek,  "dayOfWeek"),
  };
}

export default parseCron;

interface CronResult {
  minute: number[];
  hour: number[];
  dayOfMonth: number[];
  month: number[];
  dayOfWeek: number[];
}

interface FieldBounds {
  min: number;
  max: number;
}

const FIELD_BOUNDS: Record<keyof CronResult, FieldBounds> = {
  minute:     { min: 0,  max: 59 },
  hour:       { min: 0,  max: 23 },
  dayOfMonth: { min: 1,  max: 31 },
  month:      { min: 1,  max: 12 },
  dayOfWeek:  { min: 0,  max: 6  },
};

const FIELD_ORDER: Array<keyof CronResult> = [
  "minute", "hour", "dayOfMonth", "month", "dayOfWeek",
];

function assertInBounds(value: number, min: number, max: number, context: string): void {
  if (!Number.isInteger(value) || value < min || value > max) {
    throw new RangeError(
      `Value ${value} out of valid range [${min}, ${max}] in "${context}"`
    );
  }
}

function expandRange(start: number, end: number, step: number, min: number, max: number, raw: string): number[] {
  if (step <= 0) {
    throw new RangeError(`Step must be a positive integer in "${raw}"`);
  }
  assertInBounds(start, min, max, raw);
  assertInBounds(end, min, max, raw);
  if (start > end) {
    throw new RangeError(`Range start ${start} exceeds end ${end} in "${raw}"`);
  }
  const result: number[] = [];
  for (let i = start; i <= end; i += step) {
    result.push(i);
  }
  return result;
}

function parseSegment(segment: string, min: number, max: number): number[] {
  // Step: */N or START-END/N
  if (segment.includes("/")) {
    const slashIndex = segment.lastIndexOf("/");
    const left = segment.slice(0, slashIndex);
    const stepStr = segment.slice(slashIndex + 1);
    const step = parseInt(stepStr, 10);

    if (isNaN(step) || String(step) !== stepStr.trim()) {
      throw new SyntaxError(`Invalid step value "${stepStr}" in "${segment}"`);
    }

    if (left === "*") {
      return expandRange(min, max, step, min, max, segment);
    }

    if (left.includes("-")) {
      const dashIndex = left.indexOf("-");
      const startStr = left.slice(0, dashIndex);
      const endStr = left.slice(dashIndex + 1);
      const start = parseInt(startStr, 10);
      const end = parseInt(endStr, 10);
      if (isNaN(start) || isNaN(end)) {
        throw new SyntaxError(`Invalid range "${left}" in "${segment}"`);
      }
      return expandRange(start, end, step, min, max, segment);
    }

    // NUMBER/STEP — interpreted as NUMBER to max with step
    const start = parseInt(left, 10);
    if (isNaN(start)) {
      throw new SyntaxError(`Unexpected token "${left}" in "${segment}"`);
    }
    return expandRange(start, max, step, min, max, segment);
  }

  // Wildcard: *
  if (segment === "*") {
    return expandRange(min, max, 1, min, max, segment);
  }

  // Range: N-M
  if (segment.includes("-")) {
    const dashIndex = segment.indexOf("-");
    const startStr = segment.slice(0, dashIndex);
    const endStr = segment.slice(dashIndex + 1);
    const start = parseInt(startStr, 10);
    const end = parseInt(endStr, 10);
    if (isNaN(start) || String(start) !== startStr.trim() || isNaN(end) || String(end) !== endStr.trim()) {
      throw new SyntaxError(`Invalid range "${segment}"`);
    }
    return expandRange(start, end, 1, min, max, segment);
  }

  // Literal number
  const num = parseInt(segment, 10);
  if (isNaN(num) || String(num) !== segment.trim()) {
    throw new SyntaxError(`Invalid token "${segment}"`);
  }
  assertInBounds(num, min, max, segment);
  return [num];
}

function parseField(expression: string, bounds: FieldBounds): number[] {
  const { min, max } = bounds;
  const segments = expression.split(",");

  if (segments.length === 0 || segments.some((s) => s.trim() === "")) {
    throw new SyntaxError(`Empty or malformed field expression "${expression}"`);
  }

  const valueSet = new Set<number>();
  for (const segment of segments) {
    const trimmed = segment.trim();
    if (trimmed === "") {
      throw new SyntaxError(`Empty segment in "${expression}"`);
    }
    for (const v of parseSegment(trimmed, min, max)) {
      valueSet.add(v);
    }
  }

  return Array.from(valueSet).sort((a, b) => a - b);
}

function parseCron(expression: string): CronResult {
  if (typeof expression !== "string" || expression.trim() === "") {
    throw new TypeError("Cron expression must be a non-empty string");
  }

  const parts = expression.trim().split(/\s+/);

  if (parts.length !== 5) {
    throw new RangeError(
      `Cron expression must have exactly 5 fields; got ${parts.length} in "${expression}"`
    );
  }

  const result = {} as CronResult;
  for (let i = 0; i < FIELD_ORDER.length; i++) {
    const field = FIELD_ORDER[i];
    result[field] = parseField(parts[i], FIELD_BOUNDS[field]);
  }

  return result;
}

export default parseCron;

interface CronFields {
  minute: number[];
  hour: number[];
  dayOfMonth: number[];
  month: number[];
  dayOfWeek: number[];
}

const FIELD_RANGES: Record<keyof CronFields, [number, number]> = {
  minute: [0, 59],
  hour: [0, 23],
  dayOfMonth: [1, 31],
  month: [1, 12],
  dayOfWeek: [0, 6],
};

function range(start: number, end: number): number[] {
  const result: number[] = [];
  for (let i = start; i <= end; i++) result.push(i);
  return result;
}

function parseField(expr: string, min: number, max: number): number[] {
  const fullRange = range(min, max);

  if (expr === "*") return fullRange;

  // Step: */n or start-end/n
  if (expr.includes("/")) {
    const [rangePart, stepStr] = expr.split("/");
    const step = parseInt(stepStr, 10);
    if (isNaN(step) || step <= 0) throw new Error(`Invalid step value: "${stepStr}"`);

    let base: number[];
    if (rangePart === "*") {
      base = fullRange;
    } else if (rangePart.includes("-")) {
      const [startStr, endStr] = rangePart.split("-");
      const start = parseInt(startStr, 10);
      const end = parseInt(endStr, 10);
      if (isNaN(start) || isNaN(end)) throw new Error(`Invalid range: "${rangePart}"`);
      if (start < min || end > max || start > end)
        throw new Error(`Range "${rangePart}" out of bounds [${min}, ${max}]`);
      base = range(start, end);
    } else {
      const start = parseInt(rangePart, 10);
      if (isNaN(start)) throw new Error(`Invalid step base: "${rangePart}"`);
      if (start < min || start > max)
        throw new Error(`Value ${start} out of bounds [${min}, ${max}]`);
      base = range(start, max);
    }

    return base.filter((v) => (v - base[0]) % step === 0);
  }

  // Comma-separated list
  if (expr.includes(",")) {
    const parts = expr.split(",");
    const values = new Set<number>();
    for (const part of parts) {
      for (const v of parseField(part.trim(), min, max)) {
        values.add(v);
      }
    }
    return Array.from(values).sort((a, b) => a - b);
  }

  // Range: start-end
  if (expr.includes("-")) {
    const [startStr, endStr] = expr.split("-");
    const start = parseInt(startStr, 10);
    const end = parseInt(endStr, 10);
    if (isNaN(start) || isNaN(end)) throw new Error(`Invalid range: "${expr}"`);
    if (start < min || end > max || start > end)
      throw new Error(`Range "${expr}" out of bounds [${min}, ${max}]`);
    return range(start, end);
  }

  // Single number
  const value = parseInt(expr, 10);
  if (isNaN(value)) throw new Error(`Invalid cron field value: "${expr}"`);
  if (value < min || value > max)
    throw new Error(`Value ${value} out of bounds [${min}, ${max}]`);
  return [value];
}

function parseCron(expression: string): CronFields {
  const trimmed = expression.trim().replace(/\s+/g, " ");
  const parts = trimmed.split(" ");

  if (parts.length !== 5) {
    throw new Error(
      `Invalid cron expression: expected 5 fields, got ${parts.length}`
    );
  }

  const fieldNames = Object.keys(FIELD_RANGES) as (keyof CronFields)[];

  const result = {} as CronFields;
  for (let i = 0; i < fieldNames.length; i++) {
    const name = fieldNames[i];
    const [min, max] = FIELD_RANGES[name];
    result[name] = parseField(parts[i], min, max);
  }

  return result;
}

export default parseCron;

interface RateLimiterOptions {
  maxTokens: number;
  refillRate: number;
  refillIntervalMs: number;
}

class RateLimiter {
  private readonly maxTokens: number;
  private readonly refillRate: number;
  private readonly refillIntervalMs: number;
  private currentTokens: number;
  private lastRefillTime: number;

  constructor(options: RateLimiterOptions) {
    if (options.maxTokens <= 0) throw new RangeError("maxTokens must be > 0");
    if (options.refillRate <= 0) throw new RangeError("refillRate must be > 0");
    if (options.refillIntervalMs <= 0) throw new RangeError("refillIntervalMs must be > 0");

    this.maxTokens = options.maxTokens;
    this.refillRate = options.refillRate;
    this.refillIntervalMs = options.refillIntervalMs;
    this.currentTokens = options.maxTokens;
    this.lastRefillTime = Date.now();
  }

  private refill(): void {
    const now = Date.now();
    const elapsed = now - this.lastRefillTime;
    const intervals = Math.floor(elapsed / this.refillIntervalMs);

    if (intervals > 0) {
      const tokensToAdd = intervals * this.refillRate;
      this.currentTokens = Math.min(this.maxTokens, this.currentTokens + tokensToAdd);
      this.lastRefillTime += intervals * this.refillIntervalMs;
    }
  }

  tryConsume(tokens: number = 1): boolean {
    if (tokens <= 0) throw new RangeError("tokens must be > 0");
    if (tokens > this.maxTokens) return false;

    this.refill();

    if (this.currentTokens >= tokens) {
      this.currentTokens -= tokens;
      return true;
    }

    return false;
  }

  getTokens(): number {
    this.refill();
    return this.currentTokens;
  }

  reset(): void {
    this.currentTokens = this.maxTokens;
    this.lastRefillTime = Date.now();
  }

  waitForTokens(tokens: number = 1): Promise<void> {
    if (tokens <= 0) return Promise.reject(new RangeError("tokens must be > 0"));
    if (tokens > this.maxTokens) return Promise.reject(new RangeError("tokens exceeds maxTokens capacity"));

    return new Promise((resolve) => {
      const attempt = (): void => {
        if (this.tryConsume(tokens)) {
          resolve();
          return;
        }

        this.refill();
        const deficit = tokens - this.currentTokens;
        const intervalsNeeded = Math.ceil(deficit / this.refillRate);
        const delay = Math.max(1, intervalsNeeded * this.refillIntervalMs);

        setTimeout(attempt, delay);
      };

      attempt();
    });
  }
}

export default RateLimiter;

interface CronFields {
  minute: number[];
  hour: number[];
  dayOfMonth: number[];
  month: number[];
  dayOfWeek: number[];
}

interface FieldConfig {
  readonly min: number;
  readonly max: number;
}

const FIELD_CONFIGS: Readonly<Record<keyof CronFields, FieldConfig>> = {
  minute:     { min: 0,  max: 59 },
  hour:       { min: 0,  max: 23 },
  dayOfMonth: { min: 1,  max: 31 },
  month:      { min: 1,  max: 12 },
  dayOfWeek:  { min: 0,  max: 6  },
};

const FIELD_ORDER: ReadonlyArray<keyof CronFields> = [
  "minute", "hour", "dayOfMonth", "month", "dayOfWeek",
];

function assertInteger(raw: string, fieldName: string): number {
  const n = Number(raw);
  if (!Number.isInteger(n) || raw.trim() === "") {
    throw new SyntaxError(
      `Field "${fieldName}": "${raw}" is not a valid integer`
    );
  }
  return n;
}

function assertInRange(n: number, cfg: FieldConfig, fieldName: string): void {
  if (n < cfg.min || n > cfg.max) {
    throw new RangeError(
      `Field "${fieldName}": value ${n} is outside valid range [${cfg.min}, ${cfg.max}]`
    );
  }
}

function expandWildcard(cfg: FieldConfig): number[] {
  return Array.from({ length: cfg.max - cfg.min + 1 }, (_, i) => cfg.min + i);
}

function expandRange(expr: string, cfg: FieldConfig, fieldName: string): number[] {
  const parts = expr.split("-");
  if (parts.length !== 2) {
    throw new SyntaxError(
      `Field "${fieldName}": invalid range expression "${expr}"`
    );
  }
  const start = assertInteger(parts[0], fieldName);
  const end   = assertInteger(parts[1], fieldName);
  assertInRange(start, cfg, fieldName);
  assertInRange(end,   cfg, fieldName);
  if (start > end) {
    throw new RangeError(
      `Field "${fieldName}": range start ${start} exceeds end ${end}`
    );
  }
  return Array.from({ length: end - start + 1 }, (_, i) => start + i);
}

function expandStep(expr: string, cfg: FieldConfig, fieldName: string): number[] {
  const slashIdx = expr.indexOf("/");
  const baseExpr = expr.slice(0, slashIdx);
  const stepStr  = expr.slice(slashIdx + 1);
  if (stepStr === "" || stepStr.includes("/")) {
    throw new SyntaxError(
      `Field "${fieldName}": malformed step expression "${expr}"`
    );
  }
  const step = assertInteger(stepStr, fieldName);
  if (step <= 0) {
    throw new RangeError(
      `Field "${fieldName}": step value must be a positive integer, got ${step}`
    );
  }

  let rangeStart: number;
  let rangeEnd: number;

  if (baseExpr === "*") {
    rangeStart = cfg.min;
    rangeEnd   = cfg.max;
  } else if (baseExpr.includes("-")) {
    const base = expandRange(baseExpr, cfg, fieldName);
    rangeStart = base[0];
    rangeEnd   = base[base.length - 1];
  } else {
    rangeStart = assertInteger(baseExpr, fieldName);
    assertInRange(rangeStart, cfg, fieldName);
    rangeEnd = cfg.max;
  }

  const values: number[] = [];
  for (let v = rangeStart; v <= rangeEnd; v += step) {
    values.push(v);
  }
  if (values.length === 0) {
    throw new RangeError(
      `Field "${fieldName}": step expression "${expr}" produces no values`
    );
  }
  return values;
}

function expandAtom(token: string, cfg: FieldConfig, fieldName: string): number[] {
  if (token === "") {
    throw new SyntaxError(`Field "${fieldName}": empty token`);
  }
  if (token === "*")          return expandWildcard(token as "*", cfg);
  if (token.includes("/"))    return expandStep(token, cfg, fieldName);
  if (token.includes("-"))    return expandRange(token, cfg, fieldName);
  const n = assertInteger(token, fieldName);
  assertInRange(n, cfg, fieldName);
  return [n];
}

// Overload to satisfy TypeScript narrowing on the "*" literal
function expandWildcard(_token: "*", cfg: FieldConfig): number[] {
  return Array.from({ length: cfg.max - cfg.min + 1 }, (_, i) => cfg.min + i);
}

function parseField(expr: string, cfg: FieldConfig, fieldName: string): number[] {
  const trimmed = expr.trim();
  if (trimmed === "") {
    throw new SyntaxError(`Field "${fieldName}": expression is empty`);
  }

  const tokens = trimmed.split(",");
  const seen   = new Set<number>();

  for (const token of tokens) {
    if (token === "") {
      throw new SyntaxError(
        `Field "${fieldName}": trailing/leading comma or consecutive commas in "${trimmed}"`
      );
    }
    for (const v of expandAtom(token.trim(), cfg, fieldName)) {
      seen.add(v);
    }
  }

  return Array.from(seen).sort((a, b) => a - b);
}

export function parseCron(expression: string): CronFields {
  if (typeof expression !== "string") {
    throw new TypeError(
      `parseCron expects a string, got ${typeof expression}`
    );
  }

  const tokens = expression.trim().split(/\s+/);

  if (tokens.length !== 5) {
    throw new SyntaxError(
      `Cron expression must have exactly 5 space-separated fields; got ${tokens.length} in: "${expression}"`
    );
  }

  return {
    minute:     parseField(tokens[0], FIELD_CONFIGS.minute,     "minute"),
    hour:       parseField(tokens[1], FIELD_CONFIGS.hour,       "hour"),
    dayOfMonth: parseField(tokens[2], FIELD_CONFIGS.dayOfMonth, "dayOfMonth"),
    month:      parseField(tokens[3], FIELD_CONFIGS.month,      "month"),
    dayOfWeek:  parseField(tokens[4], FIELD_CONFIGS.dayOfWeek,  "dayOfWeek"),
  };
}

export default parseCron;

type CronFields = {
  minute: number[];
  hour: number[];
  dayOfMonth: number[];
  month: number[];
  dayOfWeek: number[];
};

type FieldConfig = {
  min: number;
  max: number;
};

const FIELD_CONFIGS: Record<keyof CronFields, FieldConfig> = {
  minute:     { min: 0,  max: 59 },
  hour:       { min: 0,  max: 23 },
  dayOfMonth: { min: 1,  max: 31 },
  month:      { min: 1,  max: 12 },
  dayOfWeek:  { min: 0,  max: 6  },
};

const FIELD_ORDER: (keyof CronFields)[] = [
  "minute",
  "hour",
  "dayOfMonth",
  "month",
  "dayOfWeek",
];

function clamp(value: number, min: number, max: number): number {
  if (value < min || value > max) {
    throw new RangeError(`Value ${value} is out of range [${min}, ${max}]`);
  }
  return value;
}

function range(from: number, to: number): number[] {
  if (from > to) throw new RangeError(`Invalid range: ${from}-${to}`);
  return Array.from({ length: to - from + 1 }, (_, i) => from + i);
}

function parseSegment(segment: string, config: FieldConfig): number[] {
  const { min, max } = config;

  // Wildcard: *
  if (segment === "*") {
    return range(min, max);
  }

  // Step value: */n or start-end/n
  if (segment.includes("/")) {
    const [rangePart, stepStr] = segment.split("/");
    const step = parseInt(stepStr, 10);

    if (isNaN(step) || step <= 0) {
      throw new Error(`Invalid step value: ${stepStr}`);
    }

    let base: number[];
    if (rangePart === "*") {
      base = range(min, max);
    } else if (rangePart.includes("-")) {
      const [fromStr, toStr] = rangePart.split("-");
      const from = clamp(parseInt(fromStr, 10), min, max);
      const to   = clamp(parseInt(toStr,   10), min, max);
      base = range(from, to);
    } else {
      const start = clamp(parseInt(rangePart, 10), min, max);
      base = range(start, max);
    }

    return base.filter((_, i) => i % step === 0);
  }

  // Range: a-b
  if (segment.includes("-")) {
    const [fromStr, toStr] = segment.split("-");
    const from = clamp(parseInt(fromStr, 10), min, max);
    const to   = clamp(parseInt(toStr,   10), min, max);
    return range(from, to);
  }

  // Single number
  const value = parseInt(segment, 10);
  if (isNaN(value)) {
    throw new Error(`Invalid cron segment: ${segment}`);
  }
  return [clamp(value, min, max)];
}

function parseField(field: string, config: FieldConfig): number[] {
  const segments = field.split(",");
  const values = new Set<number>();

  for (const segment of segments) {
    for (const v of parseSegment(segment.trim(), config)) {
      values.add(v);
    }
  }

  return Array.from(values).sort((a, b) => a - b);
}

export default function parseCron(expression: string): CronFields {
  const parts = expression.trim().split(/\s+/);

  if (parts.length !== 5) {
    throw new Error(
      `Invalid cron expression: expected 5 fields, got ${parts.length}`
    );
  }

  return Object.fromEntries(
    FIELD_ORDER.map((fieldName, index) => [
      fieldName,
      parseField(parts[index], FIELD_CONFIGS[fieldName]),
    ])
  ) as CronFields;
}

export interface CronExpression {
  minute: number[];
  hour: number[];
  dayOfMonth: number[];
  month: number[];
  dayOfWeek: number[];
}

type FieldName = keyof CronExpression;

interface FieldBounds {
  min: number;
  max: number;
}

const FIELD_ORDER: FieldName[] = [
  "minute",
  "hour",
  "dayOfMonth",
  "month",
  "dayOfWeek",
];

const FIELD_BOUNDS: Record<FieldName, FieldBounds> = {
  minute:     { min: 0,  max: 59 },
  hour:       { min: 0,  max: 23 },
  dayOfMonth: { min: 1,  max: 31 },
  month:      { min: 1,  max: 12 },
  dayOfWeek:  { min: 0,  max: 6  },
};

function assertInBounds(value: number, bounds: FieldBounds, context: string): void {
  if (!Number.isInteger(value) || value < bounds.min || value > bounds.max) {
    throw new RangeError(
      `Value ${value} is out of valid range [${bounds.min}, ${bounds.max}] in "${context}"`
    );
  }
}

function parseInteger(raw: string, context: string): number {
  // Reject anything that isn't purely digits (no floats, no signs, no hex)
  if (!/^\d+$/.test(raw.trim())) {
    throw new SyntaxError(`Expected an integer but got "${raw}" in "${context}"`);
  }
  return parseInt(raw.trim(), 10);
}

function expandRange(start: number, end: number, step: number, bounds: FieldBounds, raw: string): number[] {
  if (start > end) {
    throw new RangeError(`Range start ${start} > end ${end} in "${raw}"`);
  }
  if (step < 1) {
    throw new RangeError(`Step must be >= 1 but got ${step} in "${raw}"`);
  }
  assertInBounds(start, bounds, raw);
  assertInBounds(end,   bounds, raw);

  const values: number[] = [];
  for (let i = start; i <= end; i += step) {
    values.push(i);
  }
  return values;
}

function parseSinglePart(part: string, bounds: FieldBounds): number[] {
  const trimmed = part.trim();

  if (trimmed === "") {
    throw new SyntaxError(`Empty field part encountered`);
  }

  // Step expression: <range-or-wildcard>/<step>
  if (trimmed.includes("/")) {
    const slashIdx = trimmed.indexOf("/");
    const lhs  = trimmed.slice(0, slashIdx);
    const rhs  = trimmed.slice(slashIdx + 1);

    const step = parseInteger(rhs, trimmed);

    if (lhs === "*") {
      return expandRange(bounds.min, bounds.max, step, bounds, trimmed);
    }

    if (lhs.includes("-")) {
      const dashIdx = lhs.indexOf("-");
      const start   = parseInteger(lhs.slice(0, dashIdx), trimmed);
      const end     = parseInteger(lhs.slice(dashIdx + 1), trimmed);
      return expandRange(start, end, step, bounds, trimmed);
    }

    // Single number as LHS: treat as start of range to max
    const start = parseInteger(lhs, trimmed);
    return expandRange(start, bounds.max, step, bounds, trimmed);
  }

  // Wildcard
  if (trimmed === "*") {
    return expandRange(bounds.min, bounds.max, 1, bounds, trimmed);
  }

  // Range: <start>-<end>
  if (trimmed.includes("-")) {
    const dashIdx = trimmed.indexOf("-");
    const start   = parseInteger(trimmed.slice(0, dashIdx), trimmed);
    const end     = parseInteger(trimmed.slice(dashIdx + 1), trimmed);
    return expandRange(start, end, 1, bounds, trimmed);
  }

  // Plain number
  const value = parseInteger(trimmed, trimmed);
  assertInBounds(value, bounds, trimmed);
  return [value];
}

function parseField(raw: string, bounds: FieldBounds): number[] {
  if (raw.trim() === "") {
    throw new SyntaxError(`Cron field is empty`);
  }

  // Comma-separated list — each element is parsed independently then merged
  const parts = raw.split(",");
  const seen  = new Set<number>();

  for (const part of parts) {
    for (const value of parseSinglePart(part, bounds)) {
      seen.add(value);
    }
  }

  return Array.from(seen).sort((a, b) => a - b);
}

export default function parseCron(expression: string): CronExpression {
  if (typeof expression !== "string") {
    throw new TypeError(`parseCron expects a string, received ${typeof expression}`);
  }

  // Collapse any internal runs of whitespace to single space, then split
  const fields = expression.trim().replace(/\s+/g, " ").split(" ");

  if (fields.length !== 5) {
    throw new SyntaxError(
      `Cron expression must have exactly 5 fields, got ${fields.length}: "${expression}"`
    );
  }

  const result = {} as CronExpression;

  for (let i = 0; i < FIELD_ORDER.length; i++) {
    const name   = FIELD_ORDER[i];
    const bounds = FIELD_BOUNDS[name];
    result[name] = parseField(fields[i], bounds);
  }

  return result;
}

interface RateLimiterOptions {
  maxTokens: number;
  refillRate: number;
  refillIntervalMs: number;
}

class RateLimiter {
  private readonly maxTokens: number;
  private readonly refillRate: number;
  private readonly refillIntervalMs: number;
  private currentTokens: number;
  private lastRefillTime: number;

  constructor(options: RateLimiterOptions) {
    if (options.maxTokens <= 0) throw new RangeError("maxTokens must be > 0");
    if (options.refillRate <= 0) throw new RangeError("refillRate must be > 0");
    if (options.refillIntervalMs <= 0) throw new RangeError("refillIntervalMs must be > 0");

    this.maxTokens = options.maxTokens;
    this.refillRate = options.refillRate;
    this.refillIntervalMs = options.refillIntervalMs;
    this.currentTokens = options.maxTokens;
    this.lastRefillTime = Date.now();
  }

  private refill(): void {
    const now = Date.now();
    const elapsed = now - this.lastRefillTime;
    const intervals = Math.floor(elapsed / this.refillIntervalMs);

    if (intervals > 0) {
      this.currentTokens = Math.min(
        this.maxTokens,
        this.currentTokens + intervals * this.refillRate
      );
      this.lastRefillTime += intervals * this.refillIntervalMs;
    }
  }

  tryConsume(tokens: number = 1): boolean {
    if (tokens <= 0) throw new RangeError("tokens must be > 0");
    if (tokens > this.maxTokens) return false;

    this.refill();

    if (this.currentTokens >= tokens) {
