export type ParsedCron = {
  minute: number[];
  hour: number[];
  dayOfMonth: number[];
  month: number[];
  dayOfWeek: number[];
};

type FieldMeta = {
  name: keyof ParsedCron;
  min: number;
  max: number;
};

const FIELDS: FieldMeta[] = [
  { name: "minute",     min: 0,  max: 59 },
  { name: "hour",       min: 0,  max: 23 },
  { name: "dayOfMonth", min: 1,  max: 31 },
  { name: "month",      min: 1,  max: 12 },
  { name: "dayOfWeek",  min: 0,  max: 6  },
];

function assertInRange(value: number, min: number, max: number, context: string): void {
  if (!Number.isInteger(value) || value < min || value > max) {
    throw new RangeError(
      `Value ${value} is out of bounds [${min}, ${max}] in segment "${context}"`
    );
  }
}

function parseSegment(segment: string, min: number, max: number): number[] {
  if (segment.trim() === "") {
    throw new SyntaxError("Empty segment is not allowed");
  }

  // Comma-separated list — each element parsed independently, then merged
  if (segment.includes(",")) {
    const seen = new Set<number>();
    for (const part of segment.split(",")) {
      const trimmed = part.trim();
      if (trimmed === "") throw new SyntaxError(`Empty element in list: "${segment}"`);
      for (const v of parseSegment(trimmed, min, max)) {
        seen.add(v);
      }
    }
    return Array.from(seen).sort((a, b) => a - b);
  }

  // Step value: */step  or  start-end/step  or  start/step
  if (segment.includes("/")) {
    const slashCount = (segment.match(/\//g) ?? []).length;
    if (slashCount > 1) {
      throw new SyntaxError(`Multiple slashes are not allowed in segment "${segment}"`);
    }

    const [rangeExpr, stepStr] = segment.split("/");
    const step = Number(stepStr);

    if (!Number.isInteger(step) || step <= 0) {
      throw new RangeError(`Step must be a positive integer, got "${stepStr}"`);
    }

    let rangeMin = min;
    let rangeMax = max;

    if (rangeExpr !== "*") {
      if (rangeExpr.includes("-")) {
        const [lo, hi] = rangeExpr.split("-").map(Number);
        assertInRange(lo, min, max, segment);
        assertInRange(hi, min, max, segment);
        if (lo > hi) throw new RangeError(`Range start ${lo} > end ${hi} in "${segment}"`);
        rangeMin = lo;
        rangeMax = hi;
      } else {
        const start = Number(rangeExpr);
        assertInRange(start, min, max, segment);
        rangeMin = start;
      }
    }

    const result: number[] = [];
    for (let v = rangeMin; v <= rangeMax; v += step) {
      result.push(v);
    }
    return result;
  }

  // Range: start-end
  if (segment.includes("-")) {
    const parts = segment.split("-");
    if (parts.length !== 2) {
      throw new SyntaxError(`Invalid range format: "${segment}"`);
    }
    const lo = Number(parts[0]);
    const hi = Number(parts[1]);

    if (!Number.isFinite(lo) || !Number.isFinite(hi)) {
      throw new SyntaxError(`Non-numeric bounds in range "${segment}"`);
    }

    assertInRange(lo, min, max, segment);
    assertInRange(hi, min, max, segment);

    if (lo > hi) {
      throw new RangeError(`Range start ${lo} > end ${hi} in "${segment}"`);
    }

    const result: number[] = [];
    for (let v = lo; v <= hi; v++) {
      result.push(v);
    }
    return result;
  }

  // Wildcard
  if (segment === "*") {
    const result: number[] = [];
    for (let v = min; v <= max; v++) {
      result.push(v);
    }
    return result;
  }

  // Single numeric value
  const num = Number(segment);
  if (!Number.isFinite(num) || segment.trim() === "") {
    throw new SyntaxError(`Unrecognised token "${segment}"`);
  }

  assertInRange(num, min, max, segment);
  return [num];
}

export default function parseCron(expression: string): ParsedCron {
  if (typeof expression !== "string") {
    throw new TypeError("Cron expression must be a string");
  }

  const parts = expression.trim().split(/\s+/);

  if (parts.length !== 5) {
    throw new SyntaxError(
      `Cron expression must have exactly 5 fields, got ${parts.length}: "${expression}"`
    );
  }

  const result = {} as ParsedCron;

  for (let i = 0; i < FIELDS.length; i++) {
    const { name, min, max } = FIELDS[i]!;
    try {
      result[name] = parseSegment(parts[i]!, min, max);
    } catch (err) {
      const base = err instanceof Error ? err.message : String(err);
      throw new (err instanceof TypeError ? TypeError : err instanceof RangeError ? RangeError : SyntaxError)(
        `Field "${name}" (position ${i + 1}): ${base}`
      );
    }
  }

  return result;
}

