export class RateLimiter {
  private readonly maxTokens: number;
  private readonly refillRate: number;
  private readonly refillIntervalMs: number;
  private currentTokens: number;
  private lastRefillTime: number;
  private readonly waitQueue: WaitEntry[];
  private scheduleHandle: ReturnType<typeof setTimeout> | null;

  constructor(options: RateLimiterOptions) {
    const { maxTokens, refillRate, refillIntervalMs } = options;

    if (!Number.isFinite(maxTokens) || maxTokens <= 0)
      throw new RangeError("maxTokens must be a finite positive number");
    if (!Number.isFinite(refillRate) || refillRate < 0)
      throw new RangeError("refillRate must be a finite non-negative number");
    if (!Number.isFinite(refillIntervalMs) || refillIntervalMs <= 0)
      throw new RangeError("refillIntervalMs must be a finite positive number");

    this.maxTokens = maxTokens;
    this.refillRate = refillRate;
    this.refillIntervalMs = refillIntervalMs;
    this.currentTokens = maxTokens;
    this.lastRefillTime = Date.now();
    this.waitQueue = [];
    this.scheduleHandle = null;
  }

  private applyRefill(): void {
    const now = Date.now();
    const elapsed = now - this.lastRefillTime;
    this.lastRefillTime = now;

    if (elapsed > 0 && this.refillRate > 0) {
      const added = (elapsed / this.refillIntervalMs) * this.refillRate;
      this.currentTokens = Math.min(this.maxTokens, this.currentTokens + added);
    }
  }

  tryConsume(tokens: number = 1): boolean {
    if (!Number.isFinite(tokens) || tokens < 0)
      throw new RangeError("tokens must be a finite non-negative number");
    // A request that can never be satisfied should not silently succeed
    if (tokens > this.maxTokens) return false;

    this.applyRefill();

    if (this.currentTokens >= tokens) {
      this.currentTokens -= tokens;
      return true;
    }
    return false;
  }

  getTokens(): number {
    this.applyRefill();
    return this.currentTokens;
  }

  reset(): void {
    if (this.scheduleHandle !== null) {
      clearTimeout(this.scheduleHandle);
      this.scheduleHandle = null;
    }
    this.currentTokens = this.maxTokens;
    this.lastRefillTime = Date.now();
    // Give waiting callers a chance to consume from the refilled bucket
    this.drainQueue();
  }

  waitForTokens(tokens: number = 1): Promise<void> {
    if (!Number.isFinite(tokens) || tokens < 0)
      return Promise.reject(
        new RangeError("tokens must be a finite non-negative number")
      );
    if (tokens > this.maxTokens)
      return Promise.reject(
        new RangeError(
          `Requested ${tokens} tokens exceeds bucket capacity of ${this.maxTokens}; ` +
            `this request can never be satisfied`
        )
      );

    // Fast path: no queue ahead of us, enough tokens available right now
    if (this.waitQueue.length === 0) {
      this.applyRefill();
      if (this.currentTokens >= tokens) {
        this.currentTokens -= tokens;
        return Promise.resolve();
      }
    }

    // Slow path: enqueue and wait
    return new Promise<void>((resolve, reject) => {
      this.waitQueue.push({ tokens, resolve, reject });
      this.scheduleNextDrain();
    });
  }

  private drainQueue(): void {
    this.applyRefill();

    while (this.waitQueue.length > 0) {
      const entry = this.waitQueue[0];
      if (this.currentTokens >= entry.tokens) {
        this.currentTokens -= entry.tokens;
        this.waitQueue.shift();
        // Resolve after the dequeue so the callback can't mutate the queue
        // before we finish iterating this burst
        entry.resolve();
      } else {
        break;
      }
    }

    if (this.waitQueue.length > 0) {
      this.scheduleNextDrain();
    }
  }

  private scheduleNextDrain(): void {
    // Only one pending timer at a time
    if (this.scheduleHandle !== null) return;
    if (this.waitQueue.length === 0) return;

    const entry = this.waitQueue[0];

    // If refillRate is zero we will never accumulate more tokens.
    // Reject every queued waiter rather than hanging indefinitely.
    if (this.refillRate <= 0) {
      const pending = this.waitQueue.splice(0);
      for (const e of pending) {
        e.reject(
          new Error(
            `Tokens will never be available: refillRate is 0 and ` +
              `current tokens (${this.currentTokens}) are insufficient`
          )
        );
      }
      return;
    }

    this.applyRefill();
    const deficit = entry.tokens - this.currentTokens;

    const delayMs =
      deficit <= 0
        ? 0 // Already have enough; yield to event loop then drain
        : Math.ceil((deficit / this.refillRate) * this.refillIntervalMs);

    this.scheduleHandle = setTimeout(() => {
      this.scheduleHandle = null;
      this.drainQueue();
    }, delayMs);
  }
}

export default RateLimiter;

type CronField = "minute" | "hour" | "dayOfMonth" | "month" | "dayOfWeek";

interface ParsedCron {
  minute: number[];
  hour: number[];
  dayOfMonth: number[];
  month: number[];
  dayOfWeek: number[];
}

const FIELD_RANGES: Record<CronField, { min: number; max: number }> = {
  minute:     { min: 0,  max: 59 },
  hour:       { min: 0,  max: 23 },
  dayOfMonth: { min: 1,  max: 31 },
  month:      { min: 1,  max: 12 },
  dayOfWeek:  { min: 0,  max: 6  },
};

function rangeArray(min: number, max: number, step = 1): number[] {
  const result: number[] = [];
  for (let i = min; i <= max; i += step) {
    result.push(i);
  }
  return result;
}

function parseSegment(segment: string, field: CronField): number[] {
  const { min, max } = FIELD_RANGES[field];

  const assertInRange = (value: number): number => {
    if (value < min || value > max) {
      throw new RangeError(
        `Value ${value} out of range [${min}, ${max}] for field "${field}"`
      );
    }
    return value;
  };

  // Wildcard: *
  if (segment === "*") {
    return rangeArray(min, max);
  }

  // Step: */n or range/n
  if (segment.includes("/")) {
    const [rangePart, stepPart] = segment.split("/");
    const step = parseInt(stepPart, 10);
    if (isNaN(step) || step < 1) {
      throw new SyntaxError(`Invalid step value "${stepPart}" in field "${field}"`);
    }

    let rangeMin = min;
    let rangeMax = max;

    if (rangePart !== "*") {
      if (rangePart.includes("-")) {
        const [lo, hi] = rangePart.split("-").map(Number);
        rangeMin = assertInRange(lo);
        rangeMax = assertInRange(hi);
        if (rangeMin > rangeMax) {
          throw new RangeError(`Invalid range "${rangePart}" in field "${field}"`);
        }
      } else {
        rangeMin = assertInRange(parseInt(rangePart, 10));
        rangeMax = max;
      }
    }

    return rangeArray(rangeMin, rangeMax, step);
  }

  // Range: n-m
  if (segment.includes("-")) {
    const [lo, hi] = segment.split("-").map(Number);
    if (isNaN(lo) || isNaN(hi)) {
      throw new SyntaxError(`Invalid range "${segment}" in field "${field}"`);
    }
    const rangeMin = assertInRange(lo);
    const rangeMax = assertInRange(hi);
    if (rangeMin > rangeMax) {
      throw new RangeError(`Invalid range "${segment}" in field "${field}"`);
    }
    return rangeArray(rangeMin, rangeMax);
  }

  // Comma-separated list: recurse on each item
  if (segment.includes(",")) {
    const values = segment
      .split(",")
      .flatMap((part) => parseSegment(part.trim(), field));
    return [...new Set(values)].sort((a, b) => a - b);
  }

  // Single number
  const value = parseInt(segment, 10);
  if (isNaN(value)) {
    throw new SyntaxError(`Invalid value "${segment}" in field "${field}"`);
  }
  return [assertInRange(value)];
}

export function parseCron(expression: string): ParsedCron {
  if (typeof expression !== "string" || !expression.trim()) {
    throw new SyntaxError("Cron expression must be a non-empty string");
  }

  const fields = expression.trim().split(/\s+/);
  if (fields.length !== 5) {
    throw new SyntaxError(
      `Expected 5 fields, got ${fields.length}: "${expression}"`
    );
  }

  const [minuteRaw, hourRaw, domRaw, monthRaw, dowRaw] = fields;

  return {
    minute:     parseSegment(minuteRaw,  "minute"),
    hour:       parseSegment(hourRaw,    "hour"),
    dayOfMonth: parseSegment(domRaw,     "dayOfMonth"),
    month:      parseSegment(monthRaw,   "month"),
    dayOfWeek:  parseSegment(dowRaw,     "dayOfWeek"),
  };
}

export default parseCron;

interface CronExpression {
  minute: number[];
  hour: number[];
  dayOfMonth: number[];
  month: number[];
  dayOfWeek: number[];
}

interface FieldConfig {
  name: keyof CronExpression;
  min: number;
  max: number;
}

const FIELD_CONFIGS: readonly FieldConfig[] = [
  { name: "minute",     min: 0,  max: 59 },
  { name: "hour",       min: 0,  max: 23 },
  { name: "dayOfMonth", min: 1,  max: 31 },
  { name: "month",      min: 1,  max: 12 },
  { name: "dayOfWeek",  min: 0,  max: 6  },
] as const;

function assertInteger(raw: string, fieldName: string, context: string): number {
  // Reject floats, leading zeros, signs, empty, and non-numeric chars
  if (!/^\d+$/.test(raw)) {
    throw new Error(
      `Invalid numeric token "${raw}" in ${context} for field "${fieldName}": must be a non-negative integer with no leading zeros or extraneous characters`
    );
  }
  const n = Number(raw);
  if (!Number.isSafeInteger(n)) {
    throw new Error(`Numeric overflow: "${raw}" in ${context} for field "${fieldName}"`);
  }
  return n;
}

function assertInRange(value: number, min: number, max: number, fieldName: string, context: string): void {
  if (value < min || value > max) {
    throw new RangeError(
      `Value ${value} in ${context} for field "${fieldName}" is out of valid range [${min}–${max}]`
    );
  }
}

function parseSegment(segment: string, min: number, max: number, fieldName: string): number[] {
  if (segment === "") {
    throw new Error(`Empty segment in field "${fieldName}": check for stray commas or whitespace`);
  }

  // ── Step: */n  or  start-end/n ────────────────────────────────────────────
  if (segment.includes("/")) {
    const slashParts = segment.split("/");
    if (slashParts.length !== 2) {
      throw new Error(`Multiple "/" in segment "${segment}" for field "${fieldName}"`);
    }
    const [rangeToken, stepToken] = slashParts;

    const step = assertInteger(stepToken, fieldName, `step expression "${segment}"`);
    if (step === 0) {
      throw new Error(`Step value of 0 is invalid in "${segment}" for field "${fieldName}": would produce an infinite loop`);
    }

    let rangeMin = min;
    let rangeMax = max;

    if (rangeToken !== "*") {
      const dashParts = rangeToken.split("-");
      if (dashParts.length !== 2) {
        throw new Error(
          `Expected a range or "*" before "/" in "${segment}" for field "${fieldName}", got "${rangeToken}"`
        );
      }
      rangeMin = assertInteger(dashParts[0], fieldName, `range in "${segment}"`);
      rangeMax = assertInteger(dashParts[1], fieldName, `range in "${segment}"`);
    }

    assertInRange(rangeMin, min, max, fieldName, `step expression "${segment}"`);
    assertInRange(rangeMax, min, max, fieldName, `step expression "${segment}"`);

    if (rangeMin > rangeMax) {
      throw new Error(
        `Range start ${rangeMin} exceeds range end ${rangeMax} in "${segment}" for field "${fieldName}"`
      );
    }

    const values: number[] = [];
    for (let i = rangeMin; i <= rangeMax; i += step) {
      values.push(i);
    }
    return values;
  }

  // ── Wildcard ──────────────────────────────────────────────────────────────
  if (segment === "*") {
    const values: number[] = [];
    for (let i = min; i <= max; i++) {
      values.push(i);
    }
    return values;
  }

  // ── Range: start-end ──────────────────────────────────────────────────────
  if (segment.includes("-")) {
    const dashParts = segment.split("-");
    if (dashParts.length !== 2) {
      throw new Error(`Multiple "-" in range "${segment}" for field "${fieldName}": only simple ranges are supported`);
    }
    const start = assertInteger(dashParts[0], fieldName, `range "${segment}"`);
    const end   = assertInteger(dashParts[1], fieldName, `range "${segment}"`);

    assertInRange(start, min, max, fieldName, `range "${segment}"`);
    assertInRange(end,   min, max, fieldName, `range "${segment}"`);

    if (start > end) {
      throw new Error(
        `Range start ${start} exceeds range end ${end} in "${segment}" for field "${fieldName}": descending ranges are not supported`
      );
    }

    const values: number[] = [];
    for (let i = start; i <= end; i++) {
      values.push(i);
    }
    return values;
  }

  // ── Plain number ──────────────────────────────────────────────────────────
  const n = assertInteger(segment, fieldName, `literal value`);
  assertInRange(n, min, max, fieldName, `literal value "${segment}"`);
  return [n];
}

function parseField(token: string, min: number, max: number, fieldName: string): number[] {
  if (token === "" || token.trim() !== token) {
    // The split-on-whitespace above should prevent this, but be paranoid
    throw new Error(
      `Unexpected empty or whitespace-padded token for field "${fieldName}": received ${JSON.stringify(token)}`
    );
  }

  const segments = token.split(",");
  const seen = new Set<number>();

  for (const segment of segments) {
    for (const value of parseSegment(segment, min, max, fieldName)) {
      seen.add(value);
    }
  }

  return Array.from(seen).sort((a, b) => a - b);
}

export default function parseCron(expression: string): CronExpression {
  if (typeof expression !== "string") {
    throw new TypeError(
      `parseCron expects a string argument, received ${expression === null ? "null" : typeof expression}`
    );
  }

  const trimmed = expression.trim();
  if (trimmed === "") {
    throw new Error("parseCron received an empty or whitespace-only expression");
  }

  // Split on any run of whitespace; this normalises tabs, double-spaces, etc.
  const tokens = trimmed.split(/\s+/);

  if (tokens.length !== 5) {
    throw new Error(
      `Cron expression must have exactly 5 space-separated fields ` +
      `(minute hour dayOfMonth month dayOfWeek), but received ${tokens.length} field(s): ${JSON.stringify(expression)}`
    );
  }

  const result = {} as CronExpression;

  for (let i = 0; i < FIELD_CONFIGS.length; i++) {
    const { name, min, max } = FIELD_CONFIGS[i];
    result[name] = parseField(tokens[i], min, max, name);
  }

  return result;
}

interface RateLimiterOptions {
  maxTokens: number;
  refillRate: number;
  refillIntervalMs: number;
}

interface Waiter {
  tokens: number;
  resolve: () => void;
  reject: (err: Error) => void;
}

export class RateLimiter {
  private readonly maxTokens: number;
  private readonly refillRate: number;
  private readonly refillIntervalMs: number;
  private currentTokens: number;
  private lastRefillTime: number;
  private readonly waitQueue: Waiter[] = [];
  private pendingSchedule = false;

  constructor(options: RateLimiterOptions) {
    if (!Number.isFinite(options.maxTokens) || options.maxTokens <= 0) {
      throw new RangeError("maxTokens must be a positive finite number");
    }
    if (!Number.isFinite(options.refillRate) || options.refillRate <= 0) {
      throw new RangeError("refillRate must be a positive finite number");
    }
    if (!Number.isFinite(options.refillIntervalMs) || options.refillIntervalMs <= 0) {
      throw new RangeError("refillIntervalMs must be a positive finite number");
    }

    this.maxTokens = options.maxTokens;
    this.refillRate = options.refillRate;
    this.refillIntervalMs = options.refillIntervalMs;
    this.currentTokens = options.maxTokens;
    this.lastRefillTime = Date.now();
  }

  private applyRefill(): void {
    const now = Date.now();
    const elapsed = Math.max(0, now - this.lastRefillTime);
    if (elapsed === 0) return;

    const tokensToAdd = (elapsed / this.refillIntervalMs) * this.refillRate;
    this.currentTokens = Math.min(this.maxTokens, this.currentTokens + tokensToAdd);
    this.lastRefillTime = now;
  }

  private msUntilTokens(tokens: number): number {
    if (this.currentTokens >= tokens) return 0;
    const deficit = tokens - this.currentTokens;
    return Math.ceil((deficit / this.refillRate) * this.refillIntervalMs);
  }

  private drainQueue(): void {
    while (this.waitQueue.length > 0) {
      this.applyRefill();
      const waiter = this.waitQueue[0];
      if (this.currentTokens >= waiter.tokens) {
        this.currentTokens -= waiter.tokens;
        this.waitQueue.shift();
        waiter.resolve();
      } else {
        break;
      }
    }
  }

  private scheduleNext(): void {
    if (this.waitQueue.length === 0 || this.pendingSchedule) return;

    this.applyRefill();
    this.drainQueue();

    if (this.waitQueue.length === 0) return;

    const waiter = this.waitQueue[0];
    const delay = this.msUntilTokens(waiter.tokens);

    this.pendingSchedule = true;
    setTimeout(() => {
      this.pendingSchedule = false;
      this.drainQueue();
      this.scheduleNext();
    }, delay);
  }

  tryConsume(tokens = 1): boolean {
    if (!Number.isFinite(tokens) || tokens <= 0) {
      throw new RangeError("tokens must be a positive finite number");
    }
    if (tokens > this.maxTokens) return false;

    this.applyRefill();

    if (this.currentTokens >= tokens) {
      this.currentTokens -= tokens;
      return true;
    }
    return false;
  }

  getTokens(): number {
    this.applyRefill();
    return this.currentTokens;
  }

  reset(): void {
    this.currentTokens = this.maxTokens;
    this.lastRefillTime = Date.now();
    this.drainQueue();
    this.scheduleNext();
  }

  waitForTokens(tokens = 1): Promise<void> {
    if (!Number.isFinite(tokens) || tokens <= 0) {
      return Promise.reject(new RangeError("tokens must be a positive finite number"));
    }
    if (tokens > this.maxTokens) {
      return Promise.reject(
        new RangeError(
          `Requested ${tokens} tokens exceeds bucket capacity of ${this.maxTokens}`
        )
      );
    }

    // Fast path: no waiters ahead and enough tokens available right now
    if (this.waitQueue.length === 0) {
      this.applyRefill();
      if (this.currentTokens >= tokens) {
        this.currentTokens -= tokens;
        return Promise.resolve();
      }
    }

    return new Promise<void>((resolve, reject) => {
      this.waitQueue.push({ tokens, resolve, reject });
      this.scheduleNext();
    });
  }
}

export default RateLimiter;

export class RateLimiter {
  private readonly maxTokens: number;
  private readonly refillRate: number;
  private readonly refillIntervalMs: number;
  private currentTokens: number;
  private lastRefillTime: number;
  private readonly waitQueue: Array<{ tokens: number; resolve: () => void }>;
  private checkScheduled: boolean;

  constructor(options: {
    maxTokens: number;
    refillRate: number;
    refillIntervalMs: number;
  }) {
    if (!Number.isFinite(options.maxTokens) || options.maxTokens <= 0) {
      throw new RangeError("maxTokens must be a finite positive number");
    }
    if (!Number.isFinite(options.refillRate) || options.refillRate < 0) {
      throw new RangeError("refillRate must be a finite non-negative number");
    }
    if (!Number.isFinite(options.refillIntervalMs) || options.refillIntervalMs <= 0) {
      throw new RangeError("refillIntervalMs must be a finite positive number");
    }

    this.maxTokens = options.maxTokens;
    this.refillRate = options.refillRate;
    this.refillIntervalMs = options.refillIntervalMs;
    this.currentTokens = options.maxTokens;
    this.lastRefillTime = Date.now();
    this.waitQueue = [];
    this.checkScheduled = false;
  }

  private refill(): void {
    if (this.refillRate === 0) return;

    const now = Date.now();
    const elapsed = now - this.lastRefillTime;
    if (elapsed <= 0) return;

    const tokensToAdd = (elapsed / this.refillIntervalMs) * this.refillRate;
    this.currentTokens = Math.min(this.maxTokens, this.currentTokens + tokensToAdd);
    this.lastRefillTime = now;
  }

  private drainQueue(): void {
    while (this.waitQueue.length > 0) {
      const waiter = this.waitQueue[0];
      if (this.currentTokens >= waiter.tokens) {
        this.currentTokens -= waiter.tokens;
        this.waitQueue.shift();
        waiter.resolve();
      } else {
        break;
      }
    }
  }

  private scheduleNextCheck(): void {
    if (this.checkScheduled || this.waitQueue.length === 0 || this.refillRate === 0) {
      return;
    }

    const waiter = this.waitQueue[0];
    const deficit = waiter.tokens - this.currentTokens;

    if (deficit <= 0) {
      this.drainQueue();
      if (this.waitQueue.length > 0) this.scheduleNextCheck();
      return;
    }

    const msUntilReady = Math.ceil((deficit / this.refillRate) * this.refillIntervalMs);
    this.checkScheduled = true;

    setTimeout(() => {
      this.checkScheduled = false;
      this.refill();
      this.drainQueue();
      if (this.waitQueue.length > 0) this.scheduleNextCheck();
    }, msUntilReady);
  }

  tryConsume(tokens: number = 1): boolean {
    if (!Number.isFinite(tokens) || tokens < 0) {
      throw new RangeError("tokens must be a finite non-negative number");
    }
    if (tokens > this.maxTokens) return false;

    this.refill();

    if (this.currentTokens >= tokens) {
      this.currentTokens -= tokens;
      return true;
    }

    return false;
  }

  getTokens(): number {
    this.refill();
    return this.currentTokens;
  }

  reset(): void {
    this.currentTokens = this.maxTokens;
    this.lastRefillTime = Date.now();
    this.drainQueue();
    if (this.waitQueue.length > 0) this.scheduleNextCheck();
  }

  waitForTokens(tokens: number = 1): Promise<void> {
    if (!Number.isFinite(tokens) || tokens < 0) {
      return Promise.reject(new RangeError("tokens must be a finite non-negative number"));
    }
    if (tokens > this.maxTokens) {
      return Promise.reject(
        new RangeError(
          `Requested ${tokens} tokens exceeds bucket capacity of ${this.maxTokens}`
        )
      );
    }

    this.refill();

    // Only bypass the queue if it's empty — preserves FIFO ordering for waiting callers
    if (this.waitQueue.length === 0 && this.currentTokens >= tokens) {
      this.currentTokens -= tokens;
      return Promise.resolve();
    }

    return new Promise<void>((resolve) => {
      this.waitQueue.push({ tokens, resolve });
      this.scheduleNextCheck();
    });
  }
}

export default RateLimiter;

interface RateLimiterOptions {
  maxTokens: number;
  refillRate: number;
  refillIntervalMs: number;
}

class RateLimiter {
  private readonly maxTokens: number;
  private readonly refillRate: number;
  private readonly refillIntervalMs: number;
  private currentTokens: number;
  private lastRefillTime: number;

  constructor({ maxTokens, refillRate, refillIntervalMs }: RateLimiterOptions) {
    if (maxTokens <= 0) throw new RangeError("maxTokens must be greater than 0");
    if (refillRate <= 0) throw new RangeError("refillRate must be greater than 0");
    if (refillIntervalMs <= 0) throw new RangeError("refillIntervalMs must be greater than 0");

    this.maxTokens = maxTokens;
    this.refillRate = refillRate;
    this.refillIntervalMs = refillIntervalMs;
    this.currentTokens = maxTokens;
    this.lastRefillTime = Date.now();
  }

  private refill(): void {
    const now = Date.now();
    const elapsed = now - this.lastRefillTime;
    const intervals = Math.floor(elapsed / this.refillIntervalMs);

    if (intervals > 0) {
      this.currentTokens = Math.min(
        this.maxTokens,
        this.currentTokens + intervals * this.refillRate
      );
      this.lastRefillTime += intervals * this.refillIntervalMs;
    }
  }

  tryConsume(tokens: number = 1): boolean {
    if (tokens <= 0) throw new RangeError("tokens must be greater than 0");
    if (tokens > this.maxTokens) return false;

    this.refill();

    if (this.currentTokens >= tokens) {
      this.currentTokens -= tokens;
      return true;
    }

    return false;
  }

  getTokens(): number {
    this.refill();
    return this.currentTokens;
  }

  reset(): void {
    this.currentTokens = this.maxTokens;
    this.lastRefillTime = Date.now();
  }

  waitForTokens(tokens: number = 1): Promise<void> {
    if (tokens <= 0) return Promise.reject(new RangeError("tokens must be greater than 0"));
    if (tokens > this.maxTokens) return Promise.reject(new RangeError("tokens exceeds maxTokens capacity"));

    return new Promise((resolve) => {
      const attempt = (): void => {
        if (this.tryConsume(tokens)) {
          resolve();
          return;
        }

        this.refill();
        const deficit = tokens - this.currentTokens;
        const intervalsNeeded = Math.ceil(deficit / this.refillRate);
        const waitMs = intervalsNeeded * this.refillIntervalMs;
        const clampedWait = Math.max(waitMs, 1);

        setTimeout(attempt, clampedWait);
      };

      attempt();
    });
  }
}

export default RateLimiter;

interface RateLimiterOptions {
  maxTokens: number;
  refillRate: number;
  refillIntervalMs: number;
}

export default class RateLimiter {
  private readonly maxTokens: number;
  private readonly refillRate: number;
  private readonly refillIntervalMs: number;
  private currentTokens: number;
  private lastRefillTime: number;
  private readonly waitQueue: Array<{ tokens: number; resolve: () => void }>;
  private queueTimer: ReturnType<typeof setTimeout> | null;

  constructor(options: RateLimiterOptions) {
    const { maxTokens, refillRate, refillIntervalMs } = options;

    if (!Number.isFinite(maxTokens) || maxTokens <= 0) {
      throw new RangeError(
        `maxTokens must be a positive finite number, got ${maxTokens}`
      );
    }
    if (!Number.isFinite(refillRate) || refillRate <= 0) {
      throw new RangeError(
        `refillRate must be a positive finite number, got ${refillRate}`
      );
    }
    if (!Number.isFinite(refillIntervalMs) || refillIntervalMs <= 0) {
      throw new RangeError(
        `refillIntervalMs must be a positive finite number, got ${refillIntervalMs}`
      );
    }

    this.maxTokens = maxTokens;
    this.refillRate = refillRate;
    this.refillIntervalMs = refillIntervalMs;
    this.currentTokens = maxTokens;
    this.lastRefillTime = Date.now();
    this.waitQueue = [];
    this.queueTimer = null;
  }

  private applyRefill(): void {
    const now = Date.now();
    const elapsed = now - this.lastRefillTime;
    if (elapsed <= 0) return;

    const tokensToAdd = (elapsed / this.refillIntervalMs) * this.refillRate;
    this.currentTokens = Math.min(this.maxTokens, this.currentTokens + tokensToAdd);
    this.lastRefillTime = now;
  }

  private validateTokenArg(tokens: number, label = "tokens"): void {
    if (!Number.isFinite(tokens) || tokens < 0) {
      throw new RangeError(
        `${label} must be a non-negative finite number, got ${tokens}`
      );
    }
  }

  tryConsume(tokens = 1): boolean {
    this.validateTokenArg(tokens);
    if (tokens === 0) return true;
    // A request exceeding capacity can never be satisfied.
    if (tokens > this.maxTokens) return false;

    this.applyRefill();

    if (this.currentTokens >= tokens) {
      this.currentTokens -= tokens;
      return true;
    }

    return false;
  }

  getTokens(): number {
    this.applyRefill();
    return this.currentTokens;
  }

  reset(): void {
    this.currentTokens = this.maxTokens;
    this.lastRefillTime = Date.now();
    // Immediately satisfy any queued waiters that can now be served.
    this.drainQueue();
  }

  waitForTokens(tokens = 1): Promise<void> {
    if (!Number.isFinite(tokens) || tokens < 0) {
      return Promise.reject(
        new RangeError(
          `tokens must be a non-negative finite number, got ${tokens}`
        )
      );
    }
    if (tokens === 0) return Promise.resolve();
    if (tokens > this.maxTokens) {
      return Promise.reject(
        new RangeError(
          `Requested ${tokens} tokens exceeds bucket capacity of ${this.maxTokens}; can never be satisfied`
        )
      );
    }

    return new Promise<void>((resolve) => {
      this.waitQueue.push({ tokens, resolve });
      // Only attempt to drain immediately if this is the only waiter;
      // otherwise a scheduled drain is already in flight.
      if (this.waitQueue.length === 1) {
        this.drainQueue();
      }
    });
  }

  private drainQueue(): void {
    if (this.queueTimer !== null) {
      clearTimeout(this.queueTimer);
      this.queueTimer = null;
    }

    this.applyRefill();

    // Serve as many head-of-queue waiters as the current balance allows,
    // in strict FIFO order to prevent starvation.
    while (this.waitQueue.length > 0) {
      const head = this.waitQueue[0];
      if (this.currentTokens >= head.tokens) {
        this.currentTokens -= head.tokens;
        this.waitQueue.shift();
        // Resolve after shifting so reentrant calls to tryConsume
        // inside resolve() see the already-updated queue state.
        head.resolve();
      } else {
        break;
      }
    }

    if (this.waitQueue.length > 0) {
      this.scheduleNextDrain();
    }
  }

  private scheduleNextDrain(): void {
    // currentTokens is already up-to-date from the drainQueue call above.
    const head = this.waitQueue[0];
    const tokensNeeded = head.tokens - this.currentTokens;
    const msPerToken = this.refillIntervalMs / this.refillRate;
    // Add 1ms buffer to avoid a rounding-induced empty wake-up.
    const delayMs = Math.ceil(tokensNeeded * msPerToken) + 1;

    this.queueTimer = setTimeout(() => {
      this.queueTimer = null;
      this.drainQueue();
    }, delayMs);
  }
}

interface RateLimiterOptions {
  maxTokens: number;
  refillRate: number;
  refillIntervalMs: number;
}

class RateLimiter {
  private readonly maxTokens: number;
  private readonly refillRate: number;
  private readonly refillIntervalMs: number;
  private currentTokens: number;
  private lastRefillTime: number;

  constructor(options: RateLimiterOptions) {
    if (options.maxTokens <= 0) throw new RangeError("maxTokens must be > 0");
    if (options.refillRate <= 0) throw new RangeError("refillRate must be > 0");
    if (options.refillIntervalMs <= 0) throw new RangeError("refillIntervalMs must be > 0");

    this.maxTokens = options.maxTokens;
    this.refillRate = options.refillRate;
    this.refillIntervalMs = options.refillIntervalMs;
    this.currentTokens = options.maxTokens;
    this.lastRefillTime = Date.now();
  }

  private refill(): void {
    const now = Date.now();
    const elapsed = now - this.lastRefillTime;
    const intervals = Math.floor(elapsed / this.refillIntervalMs);

    if (intervals > 0) {
      const tokensToAdd = intervals * this.refillRate;
      this.currentTokens = Math.min(this.maxTokens, this.currentTokens + tokensToAdd);
      this.lastRefillTime += intervals * this.refillIntervalMs;
    }
  }

  tryConsume(tokens: number = 1): boolean {
    if (tokens <= 0) throw new RangeError("tokens must be > 0");
    if (tokens > this.maxTokens) return false;

    this.refill();

    if (this.currentTokens >= tokens) {
      this.currentTokens -= tokens;
      return true;
    }

    return false;
  }

  getTokens(): number {
    this.refill();
    return this.currentTokens;
  }

  reset(): void {
    this.currentTokens = this.maxTokens;
    this.lastRefillTime = Date.now();
  }

  async waitForTokens(tokens: number = 1): Promise<void> {
    if (tokens <= 0) throw new RangeError("tokens must be > 0");
    if (tokens > this.maxTokens) {
      throw new RangeError(`Requested tokens (${tokens}) exceed maxTokens (${this.maxTokens})`);
    }

    while (!this.tryConsume(tokens)) {
      const deficit = tokens - this.currentTokens;
      const intervalsNeeded = Math.ceil(deficit / this.refillRate);
      const elapsed = Date.now() - this.lastRefillTime;
      const waitMs = Math.max(1, intervalsNeeded * this.refillIntervalMs - elapsed);
      await new Promise<void>((resolve) => setTimeout(resolve, waitMs));
    }
  }
}

export default RateLimiter;

type CronResult = {
  minute: number[];
  hour: number[];
  dayOfMonth: number[];
  month: number[];
  dayOfWeek: number[];
};

const FIELD_RANGES: Record<keyof CronResult, [number, number]> = {
  minute: [0, 59],
  hour: [0, 23],
  dayOfMonth: [1, 31],
  month: [1, 12],
  dayOfWeek: [0, 6],
};

function range(from: number, to: number): number[] {
  if (from > to) throw new RangeError(`Invalid range: ${from}-${to}`);
  return Array.from({ length: to - from + 1 }, (_, i) => from + i);
}

function assertInRange(value: number, min: number, max: number, context: string): void {
  if (value < min || value > max) {
    throw new RangeError(`Value ${value} out of range [${min}, ${max}] in field "${context}"`);
  }
}

function parseSegment(segment: string, min: number, max: number, fieldName: string): number[] {
  // Step: */n or a-b/n
  if (segment.includes("/")) {
    const [rangePart, stepStr] = segment.split("/");
    const step = parseInt(stepStr, 10);
    if (isNaN(step) || step < 1) {
      throw new RangeError(`Invalid step value "${stepStr}" in field "${fieldName}"`);
    }

    let base: number[];
    if (rangePart === "*") {
      base = range(min, max);
    } else if (rangePart.includes("-")) {
      const [fromStr, toStr] = rangePart.split("-");
      const from = parseInt(fromStr, 10);
      const to = parseInt(toStr, 10);
      assertInRange(from, min, max, fieldName);
      assertInRange(to, min, max, fieldName);
      base = range(from, to);
    } else {
      const start = parseInt(rangePart, 10);
      assertInRange(start, min, max, fieldName);
      base = range(start, max);
    }

    return base.filter((_, i) => i % step === 0);
  }

  // Range: a-b
  if (segment.includes("-")) {
    const [fromStr, toStr] = segment.split("-");
    const from = parseInt(fromStr, 10);
    const to = parseInt(toStr, 10);
    if (isNaN(from) || isNaN(to)) {
      throw new TypeError(`Invalid range "${segment}" in field "${fieldName}"`);
    }
    assertInRange(from, min, max, fieldName);
    assertInRange(to, min, max, fieldName);
    return range(from, to);
  }

  // Wildcard
  if (segment === "*") {
    return range(min, max);
  }

  // Literal number
  const value = parseInt(segment, 10);
  if (isNaN(value)) {
    throw new TypeError(`Invalid value "${segment}" in field "${fieldName}"`);
  }
  assertInRange(value, min, max, fieldName);
  return [value];
}

function parseField(expression: string, min: number, max: number, fieldName: string): number[] {
  const parts = expression.split(",");
  const values = new Set<number>();

  for (const part of parts) {
    const parsed = parseSegment(part.trim(), min, max, fieldName);
    for (const v of parsed) values.add(v);
  }

  return Array.from(values).sort((a, b) => a - b);
}

function parseCron(expression: string): CronResult {
  if (typeof expression !== "string") {
    throw new TypeError("Cron expression must be a string");
  }

  const fields = expression.trim().split(/\s+/);
  if (fields.length !== 5) {
    throw new Error(`Expected 5 fields, got ${fields.length}`);
  }

  const [minuteExpr, hourExpr, dayOfMonthExpr, monthExpr, dayOfWeekExpr] = fields;

  return {
    minute: parseField(minuteExpr, ...FIELD_RANGES.minute, "minute"),
    hour: parseField(hourExpr, ...FIELD_RANGES.hour, "hour"),
    dayOfMonth: parseField(dayOfMonthExpr, ...FIELD_RANGES.dayOfMonth, "dayOfMonth"),
    month: parseField(monthExpr, ...FIELD_RANGES.month, "month"),
    dayOfWeek: parseField(dayOfWeekExpr, ...FIELD_RANGES.dayOfWeek, "dayOfWeek"),
  };
}

export default parseCron;

export interface RateLimiterOptions {
  maxTokens: number;
  refillRate: number;
  refillIntervalMs: number;
}

export class RateLimiter {
  private readonly maxTokens: number;
  private readonly refillRate: number;
  private readonly refillIntervalMs: number;
  private currentTokens: number;
  private lastRefillTime: number;
  private readonly waitQueue: Array<{ tokens: number; resolve: () => void }>;

  constructor(options: RateLimiterOptions) {
    const { maxTokens, refillRate, refillIntervalMs } = options;

    if (!Number.isFinite(maxTokens) || maxTokens <= 0) {
      throw new RangeError(`maxTokens must be a finite positive number, got ${maxTokens}`);
    }
    if (!Number.isFinite(refillRate) || refillRate <= 0) {
      throw new RangeError(`refillRate must be a finite positive number, got ${refillRate}`);
    }
    if (!Number.isFinite(refillIntervalMs) || refillIntervalMs <= 0) {
      throw new RangeError(`refillIntervalMs must be a finite positive number, got ${refillIntervalMs}`);
    }

    this.maxTokens = maxTokens;
    this.refillRate = refillRate;
    this.refillIntervalMs = refillIntervalMs;
    this.currentTokens = maxTokens;
    this.lastRefillTime = Date.now();
    this.waitQueue = [];
  }

  private applyRefill(): void {
    const now = Date.now();
    const elapsed = now - this.lastRefillTime;

    if (elapsed > 0) {
      const tokensToAdd = (elapsed / this.refillIntervalMs) * this.refillRate;
      this.currentTokens = Math.min(this.maxTokens, this.currentTokens + tokensToAdd);
      this.lastRefillTime = now;
    }
  }

  private validateTokenCount(tokens: number, label: string): void {
    if (!Number.isFinite(tokens) || tokens < 0) {
      throw new RangeError(`${label} must be a finite non-negative number, got ${tokens}`);
    }
  }

  private msUntilAvailable(tokens: number): number {
    const deficit = tokens - this.currentTokens;
    if (deficit <= 0) return 0;
    return Math.ceil((deficit / this.refillRate) * this.refillIntervalMs);
  }

  private drainQueue(): void {
    while (this.waitQueue.length > 0) {
      this.applyRefill();

      const next = this.waitQueue[0]!;

      if (this.currentTokens >= next.tokens) {
        this.currentTokens -= next.tokens;
        this.waitQueue.shift();
        next.resolve();
      } else {
        const delay = Math.max(1, this.msUntilAvailable(next.tokens));
        setTimeout(() => this.drainQueue(), delay);
        break;
      }
    }
  }

  tryConsume(tokens: number = 1): boolean {
    this.validateTokenCount(tokens, "tokens");

    if (tokens > this.maxTokens) return false;
    if (tokens === 0) return true;

    this.applyRefill();

    if (this.currentTokens >= tokens) {
      this.currentTokens -= tokens;
      return true;
    }

    return false;
  }

  getTokens(): number {
    this.applyRefill();
    return this.currentTokens;
  }

  reset(): void {
    this.currentTokens = this.maxTokens;
    this.lastRefillTime = Date.now();

    this.drainQueue();
  }

  waitForTokens(tokens: number = 1): Promise<void> {
    this.validateTokenCount(tokens, "tokens");

    if (tokens > this.maxTokens) {
      return Promise.reject(
        new RangeError(
          `Requested ${tokens} tokens exceeds bucket capacity of ${this.maxTokens}; would wait forever`
        )
      );
    }

    if (tokens === 0) return Promise.resolve();

    this.applyRefill();

    if (this.waitQueue.length === 0 && this.currentTokens >= tokens) {
      this.currentTokens -= tokens;
      return Promise.resolve();
    }

    return new Promise<void>((resolve) => {
      const entry = { tokens, resolve };
      this.waitQueue.push(entry);

      if (this.waitQueue.length === 1) {
        const delay = Math.max(1, this.msUntilAvailable(tokens));
        setTimeout(() => this.drainQueue(), delay);
      }
    });
  }
}

export default RateLimiter;

interface CronResult {
  minute: number[];
  hour: number[];
  dayOfMonth: number[];
  month: number[];
  dayOfWeek: number[];
}

const FIELD_RANGES: Record<keyof CronResult, [number, number]> = {
  minute: [0, 59],
  hour: [0, 23],
  dayOfMonth: [1, 31],
  month: [1, 12],
  dayOfWeek: [0, 6],
};

function rangeArray(from: number, to: number, step = 1): number[] {
  const result: number[] = [];
  for (let i = from; i <= to; i += step) {
    result.push(i);
  }
  return result;
}

function parseField(field: string, min: number, max: number): number[] {
  // Handle comma-separated list
  if (field.includes(",")) {
    const values = field
      .split(",")
      .flatMap((part) => parseField(part.trim(), min, max));
    return [...new Set(values)].sort((a, b) => a - b);
  }

  // Handle wildcard
  if (field === "*") {
    return rangeArray(min, max);
  }

  // Handle step values (*/step or range/step)
  if (field.includes("/")) {
    const [rangePart, stepPart] = field.split("/");
    const step = parseInt(stepPart, 10);

    if (isNaN(step) || step <= 0) {
      throw new Error(`Invalid step value: ${stepPart}`);
    }

    let from = min;
    let to = max;

    if (rangePart !== "*") {
      if (rangePart.includes("-")) {
        const [rangeFrom, rangeTo] = rangePart.split("-").map(Number);
        from = rangeFrom;
        to = rangeTo;
      } else {
        from = parseInt(rangePart, 10);
      }
    }

    if (isNaN(from) || isNaN(to)) {
      throw new Error(`Invalid range in field: ${field}`);
    }

    validateRange(from, min, max, field);
    validateRange(to, min, max, field);

    return rangeArray(from, to, step);
  }

  // Handle range (e.g., "1-5")
  if (field.includes("-")) {
    const [fromStr, toStr] = field.split("-");
    const from = parseInt(fromStr, 10);
    const to = parseInt(toStr, 10);

    if (isNaN(from) || isNaN(to)) {
      throw new Error(`Invalid range: ${field}`);
    }

    if (from > to) {
      throw new Error(`Range start ${from} is greater than end ${to}`);
    }

    validateRange(from, min, max, field);
    validateRange(to, min, max, field);

    return rangeArray(from, to);
  }

  // Handle plain number
  const num = parseInt(field, 10);

  if (isNaN(num)) {
    throw new Error(`Invalid field value: ${field}`);
  }

  validateRange(num, min, max, field);

  return [num];
}

function validateRange(value: number, min: number, max: number, field: string): void {
  if (value < min || value > max) {
    throw new Error(
      `Value ${value} in field "${field}" is out of range [${min}, ${max}]`
    );
  }
}

function parseCron(expression: string): CronResult {
  if (typeof expression !== "string" || !expression.trim()) {
    throw new Error("Cron expression must be a non-empty string");
  }

  const fields = expression.trim().split(/\s+/);

  if (fields.length !== 5) {
    throw new Error(
      `Expected 5 fields, got ${fields.length}: "${expression}"`
    );
  }

  const [minuteField, hourField, domField, monthField, dowField] = fields;
  const fieldKeys = Object.keys(FIELD_RANGES) as (keyof CronResult)[];

  const parsed = [minuteField, hourField, domField, monthField, dowField].map(
    (field, i) => {
      const key = fieldKeys[i];
      const [min, max] = FIELD_RANGES[key];
      return parseField(field, min, max);
    }
  );

  return {
    minute: parsed[0],
    hour: parsed[1],
    dayOfMonth: parsed[2],
    month: parsed[3],
    dayOfWeek: parsed[4],
  };
}

export default parseCron;

interface CronFields {
  minute: number[];
  hour: number[];
  dayOfMonth: number[];
  month: number[];
  dayOfWeek: number[];
}

const FIELD_RANGES = {
  minute:     { min: 0,  max: 59 },
  hour:       { min: 0,  max: 23 },
  dayOfMonth: { min: 1,  max: 31 },
  month:      { min: 1,  max: 12 },
  dayOfWeek:  { min: 0,  max: 7  },
} as const;

type FieldName = keyof typeof FIELD_RANGES;

function assertInRange(value: number, min: number, max: number, context: string): void {
  if (!Number.isInteger(value) || value < min || value > max) {
    throw new RangeError(`Value ${value} is out of valid range [${min}, ${max}] in: "${context}"`);
  }
}

function buildRange(start: number, end: number): number[] {
  if (start > end) {
    throw new RangeError(`Range start ${start} exceeds end ${end}`);
  }
  const out: number[] = [];
  for (let i = start; i <= end; i++) out.push(i);
  return out;
}

function parseSegment(segment: string, min: number, max: number, fieldLabel: string): number[] {
  // Reject empty segments immediately
  if (!segment || segment.trim() === "") {
    throw new SyntaxError(`Empty segment in field "${fieldLabel}"`);
  }

  // Comma-separated list — split and recurse; dedup + sort at the end
  if (segment.includes(",")) {
    const seen = new Set<number>();
    for (const part of segment.split(",")) {
      const trimmed = part.trim();
      if (!trimmed) throw new SyntaxError(`Empty item in list for field "${fieldLabel}"`);
      for (const v of parseSegment(trimmed, min, max, fieldLabel)) seen.add(v);
    }
    return Array.from(seen).sort((a, b) => a - b);
  }

  // Step value: */n  or  start-end/n  or  start/n
  if (segment.includes("/")) {
    const slashIdx = segment.lastIndexOf("/");
    const baseStr  = segment.slice(0, slashIdx);
    const stepStr  = segment.slice(slashIdx + 1);

    const step = Number(stepStr);
    if (!Number.isInteger(step) || step < 1) {
      throw new RangeError(`Step value "${stepStr}" must be a positive integer in field "${fieldLabel}"`);
    }

    let rangeStart: number;
    let rangeEnd:   number;

    if (baseStr === "*") {
      rangeStart = min;
      rangeEnd   = max;
    } else if (baseStr.includes("-")) {
      const [s, e] = baseStr.split("-").map(Number);
      if (!Number.isInteger(s) || !Number.isInteger(e)) {
        throw new SyntaxError(`Invalid range base "${baseStr}" in field "${fieldLabel}"`);
      }
      assertInRange(s, min, max, segment);
      assertInRange(e, min, max, segment);
      rangeStart = s;
      rangeEnd   = e;
    } else {
      const s = Number(baseStr);
      if (!Number.isInteger(s)) {
        throw new SyntaxError(`Invalid step base "${baseStr}" in field "${fieldLabel}"`);
      }
      assertInRange(s, min, max, segment);
      rangeStart = s;
      rangeEnd   = max;
    }

    if (rangeStart > rangeEnd) {
      throw new RangeError(`Range start ${rangeStart} exceeds end ${rangeEnd} in field "${fieldLabel}"`);
    }

    const values: number[] = [];
    for (let i = rangeStart; i <= rangeEnd; i += step) values.push(i);
    return values;
  }

  // Wildcard
  if (segment === "*") {
    return buildRange(min, max);
  }

  // Range: start-end
  if (segment.includes("-")) {
    const dashCount = segment.split("-").length - 1;
    if (dashCount !== 1) {
      throw new SyntaxError(`Malformed range "${segment}" in field "${fieldLabel}"`);
    }
    const [startStr, endStr] = segment.split("-");
    const start = Number(startStr);
    const end   = Number(endStr);
    if (!Number.isInteger(start) || !Number.isInteger(end)) {
      throw new SyntaxError(`Non-integer bounds in range "${segment}" for field "${fieldLabel}"`);
    }
    assertInRange(start, min, max, segment);
    assertInRange(end,   min, max, segment);
    return buildRange(start, end);
  }

  // Single numeric value
  const value = Number(segment);
  if (!Number.isInteger(value)) {
    throw new SyntaxError(`Unrecognised token "${segment}" in field "${fieldLabel}"`);
  }
  assertInRange(value, min, max, segment);
  return [value];
}

export default function parseCron(expression: string): CronFields {
  if (typeof expression !== "string") {
    throw new TypeError(`parseCron expects a string, got ${typeof expression}`);
  }

  const parts = expression.trim().split(/\s+/);

  if (parts.length !== 5) {
    throw new SyntaxError(
      `Cron expression must have exactly 5 fields (got ${parts.length}): "${expression}"`
    );
  }

  const [minutePart, hourPart, domPart, monthPart, dowPart] = parts;
  const r = FIELD_RANGES;

  return {
    minute:     parseSegment(minutePart, r.minute.min,     r.minute.max,     "minute"),
    hour:       parseSegment(hourPart,   r.hour.min,       r.hour.max,       "hour"),
    dayOfMonth: parseSegment(domPart,    r.dayOfMonth.min, r.dayOfMonth.max, "dayOfMonth"),
    month:      parseSegment(monthPart,  r.month.min,      r.month.max,      "month"),
    dayOfWeek:  parseSegment(dowPart,    r.dayOfWeek.min,  r.dayOfWeek.max,  "dayOfWeek"),
  };
}

interface RateLimiterOptions {
  maxTokens: number;
  refillRate: number;
  refillIntervalMs: number;
}

interface WaitEntry {
  tokens: number;
  resolve: () => void;
  reject: (err: Error) => void;
}

export default class RateLimiter {
  private readonly maxTokens: number;
  private readonly refillRate: number;
  private readonly refillIntervalMs: number;
  private currentTokens: number;
  private lastRefillTime: number;
  private readonly waitQueue: WaitEntry[] = [];
  private pendingCheck: ReturnType<typeof setTimeout> | null = null;

  constructor(options: RateLimiterOptions) {
    const { maxTokens, refillRate, refillIntervalMs } = options;

    if (!Number.isFinite(maxTokens) || maxTokens <= 0) {
      throw new RangeError(`maxTokens must be a positive finite number, got ${maxTokens}`);
    }
    if (!Number.isFinite(refillRate) || refillRate < 0) {
      throw new RangeError(`refillRate must be a non-negative finite number, got ${refillRate}`);
    }
    if (!Number.isFinite(refillIntervalMs) || refillIntervalMs <= 0) {
      throw new RangeError(`refillIntervalMs must be a positive finite number, got ${refillIntervalMs}`);
    }

    this.maxTokens = maxTokens;
    this.refillRate = refillRate;
    this.refillIntervalMs = refillIntervalMs;
    this.currentTokens = maxTokens;
    this.lastRefillTime = Date.now();
  }

  private applyRefill(): void {
    const now = Date.now();
    // Guard against clock skew going backwards
    const elapsed = Math.max(0, now - this.lastRefillTime);
    const intervals = Math.floor(elapsed / this.refillIntervalMs);

    if (intervals > 0 && this.refillRate > 0) {
      const added = intervals * this.refillRate;
      this.currentTokens = Math.min(this.maxTokens, this.currentTokens + added);
      // Advance lastRefillTime by whole intervals only — preserves sub-interval remainder
      this.lastRefillTime += intervals * this.refillIntervalMs;
    }
  }

  tryConsume(tokens: number = 1): boolean {
    if (!Number.isFinite(tokens) || tokens < 0) {
      throw new RangeError(`tokens must be a non-negative finite number, got ${tokens}`);
    }
    if (tokens === 0) return true;

    this.applyRefill();

    if (this.currentTokens >= tokens) {
      this.currentTokens -= tokens;
      return true;
    }

    return false;
  }

  getTokens(): number {
    this.applyRefill();
    return this.currentTokens;
  }

  reset(): void {
    this.currentTokens = this.maxTokens;
    this.lastRefillTime = Date.now();
    this.drainQueue();
  }

  waitForTokens(tokens: number = 1): Promise<void> {
    if (!Number.isFinite(tokens) || tokens < 0) {
      return Promise.reject(
        new RangeError(`tokens must be a non-negative finite number, got ${tokens}`)
      );
    }
    if (tokens === 0) return Promise.resolve();
    if (tokens > this.maxTokens) {
      return Promise.reject(
        new RangeError(
          `Requested ${tokens} tokens exceeds maxTokens capacity of ${this.maxTokens}; ` +
            `this promise would never resolve`
        )
      );
    }

    // Only attempt immediate consume if the queue is empty — preserves FIFO ordering
    if (this.waitQueue.length === 0 && this.tryConsume(tokens)) {
      return Promise.resolve();
    }

    return new Promise<void>((resolve, reject) => {
      this.waitQueue.push({ tokens, resolve, reject });
      this.scheduleCheck();
    });
  }

  private msUntilTokensAvailable(needed: number): number {
    const deficit = needed - this.currentTokens;
    if (deficit <= 0) return 0;
    if (this.refillRate <= 0) return Infinity;

    const intervalsNeeded = Math.ceil(deficit / this.refillRate);
    const msUntilNextInterval = this.refillIntervalMs - (Date.now() - this.lastRefillTime);

    // First interval brings us partway; subsequent intervals bring refillRate each
    return Math.max(0, msUntilNextInterval) + (intervalsNeeded - 1) * this.refillIntervalMs;
  }

  private scheduleCheck(): void {
    if (this.waitQueue.length === 0 || this.pendingCheck !== null) return;

    this.applyRefill();
    const head = this.waitQueue[0];
    const delay = this.msUntilTokensAvailable(head.tokens);

    if (!Number.isFinite(delay)) {
      // refillRate is 0 and we never will have enough — warn but leave the promise pending
      // so callers that later call reset() can still resolve waiters
      return;
    }

    // +1 ms buffer to ensure the interval has actually elapsed when we fire
    this.pendingCheck = setTimeout(() => {
      this.pendingCheck = null;
      this.drainQueue();
    }, delay + 1);
  }

  private drainQueue(): void {
    this.applyRefill();

    while (this.waitQueue.length > 0) {
      const head = this.waitQueue[0];

      if (this.currentTokens >= head.tokens) {
        this.waitQueue.shift();
        this.currentTokens -= head.tokens;
        head.resolve();
      } else {
        // Not enough tokens for the head of the queue yet; schedule next wake-up
        this.scheduleCheck();
        break;
      }
    }
  }
}

export interface CronExpression {
  minute: number[];
  hour: number[];
  dayOfMonth: number[];
  month: number[];
  dayOfWeek: number[];
}

interface FieldConfig {
  min: number;
  max: number;
  name: string;
}

const FIELD_ORDER: Array<keyof CronExpression> = [
  "minute",
  "hour",
  "dayOfMonth",
  "month",
  "dayOfWeek",
];

const FIELD_CONFIGS: Record<keyof CronExpression, FieldConfig> = {
  minute:     { min: 0,  max: 59, name: "minute"     },
  hour:       { min: 0,  max: 23, name: "hour"        },
  dayOfMonth: { min: 1,  max: 31, name: "dayOfMonth"  },
  month:      { min: 1,  max: 12, name: "month"       },
  dayOfWeek:  { min: 0,  max: 7,  name: "dayOfWeek"   }, // 7 = Sunday alias
};

const MAX_EXPRESSION_LENGTH = 256;

function parseInteger(raw: string, fieldName: string): number {
  if (!/^-?\d+$/.test(raw)) {
    throw new Error(`[${fieldName}] Non-integer token: "${raw}"`);
  }
  return Number(raw);
}

function assertInRange(value: number, cfg: FieldConfig): void {
  if (value < cfg.min || value > cfg.max) {
    throw new RangeError(
      `[${cfg.name}] Value ${value} is outside valid range [${cfg.min}–${cfg.max}]`
    );
  }
}

function expandRange(
  start: number,
  end: number,
  step: number,
  cfg: FieldConfig
): number[] {
  if (start > end) {
    throw new Error(
      `[${cfg.name}] Range start (${start}) exceeds end (${end})`
    );
  }
  if (step < 1) {
    throw new Error(`[${cfg.name}] Step must be ≥ 1, got ${step}`);
  }
  assertInRange(start, cfg);
  assertInRange(end, cfg);

  const values: number[] = [];
  for (let i = start; i <= end; i += step) {
    values.push(i);
  }
  return values;
}

function parseSegment(token: string, cfg: FieldConfig): number[] {
  // Step expression: */n  |  start/n  |  start-end/n
  if (token.includes("/")) {
    const slashParts = token.split("/");
    if (slashParts.length !== 2) {
      throw new Error(`[${cfg.name}] Invalid step expression: "${token}"`);
    }
    const [rangePart, stepPart] = slashParts;
    const step = parseInteger(stepPart, cfg.name);
    if (step < 1) {
      throw new Error(`[${cfg.name}] Step must be ≥ 1, got ${step}`);
    }

    if (rangePart === "*") {
      return expandRange(cfg.min, cfg.max, step, cfg);
    }

    if (rangePart.includes("-")) {
      const dashParts = rangePart.split("-");
      if (dashParts.length !== 2) {
        throw new Error(`[${cfg.name}] Invalid range in step: "${rangePart}"`);
      }
      const start = parseInteger(dashParts[0], cfg.name);
      const end   = parseInteger(dashParts[1], cfg.name);
      return expandRange(start, end, step, cfg);
    }

    // single-start/step: treat as start–max/step
    const start = parseInteger(rangePart, cfg.name);
    return expandRange(start, cfg.max, step, cfg);
  }

  // Wildcard
  if (token === "*") {
    return expandRange(cfg.min, cfg.max, 1, cfg);
  }

  // Range: start-end
  if (token.includes("-")) {
    const dashParts = token.split("-");
    if (dashParts.length !== 2) {
      throw new Error(`[${cfg.name}] Invalid range: "${token}"`);
    }
    const start = parseInteger(dashParts[0], cfg.name);
    const end   = parseInteger(dashParts[1], cfg.name);
    return expandRange(start, end, 1, cfg);
  }

  // Plain integer
  const value = parseInteger(token, cfg.name);
  assertInRange(value, cfg);
  return [value];
}

function normalizeDayOfWeek(values: number[]): number[] {
  // POSIX allows 7 as an alias for Sunday (0); collapse to 0
  return Array.from(
    new Set(values.map((v) => (v === 7 ? 0 : v)))
  ).sort((a, b) => a - b);
}

function parseField(raw: string, cfg: FieldConfig): number[] {
  if (!raw || raw.trim() === "") {
    throw new Error(`[${cfg.name}] Empty field`);
  }

  const tokens = raw.split(",");
  const seen = new Set<number>();

  for (const token of tokens) {
    const trimmed = token.trim();
    if (trimmed === "") {
      throw new Error(`[${cfg.name}] Empty token in comma list: "${raw}"`);
    }
    for (const v of parseSegment(trimmed, cfg)) {
      seen.add(v);
    }
  }

  return Array.from(seen).sort((a, b) => a - b);
}

export default function parseCron(expression: string): CronExpression {
  if (typeof expression !== "string") {
    throw new TypeError("Cron expression must be a string");
  }
  if (expression.length > MAX_EXPRESSION_LENGTH) {
    throw new Error(
      `Cron expression exceeds maximum length of ${MAX_EXPRESSION_LENGTH} characters`
    );
  }

  const fields = expression.trim().split(/\s+/);

  if (fields.length !== 5) {
    throw new Error(
      `Cron expression must have exactly 5 fields; got ${fields.length}: "${expression}"`
    );
  }

  const result = {} as CronExpression;

  for (let i = 0; i < FIELD_ORDER.length; i++) {
    const key = FIELD_ORDER[i];
    const cfg = FIELD_CONFIGS[key];
    let values = parseField(fields[i], cfg);

    if (key === "dayOfWeek") {
      values = normalizeDayOfWeek(values);
    }

    result[key] = values;
  }

  return result;
}

interface RateLimiterOptions {
  maxTokens: number;
  refillRate: number;
  refillIntervalMs: number;
}

class RateLimiter {
  private readonly maxTokens: number;
  private readonly refillRate: number;
  private readonly refillIntervalMs: number;
  private currentTokens: number;
  private lastRefillTime: number;

  constructor(options: RateLimiterOptions) {
    if (options.maxTokens <= 0) throw new RangeError("maxTokens must be > 0");
    if (options.refillRate <= 0) throw new RangeError("refillRate must be > 0");
    if (options.refillIntervalMs <= 0) throw new RangeError("refillIntervalMs must be > 0");

    this.maxTokens = options.maxTokens;
    this.refillRate = options.refillRate;
    this.refillIntervalMs = options.refillIntervalMs;
    this.currentTokens = options.maxTokens;
    this.lastRefillTime = Date.now();
  }

  private refill(): void {
    const now = Date.now();
    const elapsed = now - this.lastRefillTime;
    const intervals = Math.floor(elapsed / this.refillIntervalMs);

    if (intervals > 0) {
      const tokensToAdd = intervals * this.refillRate;
      this.currentTokens = Math.min(this.maxTokens, this.currentTokens + tokensToAdd);
      this.lastRefillTime += intervals * this.refillIntervalMs;
    }
  }

  tryConsume(tokens: number = 1): boolean {
    if (tokens <= 0) throw new RangeError("tokens must be > 0");
    if (tokens > this.maxTokens) return false;

    this.refill();

    if (this.currentTokens >= tokens) {
      this.currentTokens -= tokens;
      return true;
    }

    return false;
  }

  getTokens(): number {
    this.refill();
    return this.currentTokens;
  }

  reset(): void {
    this.currentTokens = this.maxTokens;
    this.lastRefillTime = Date.now();
  }

  async waitForTokens(tokens: number = 1): Promise<void> {
    if (tokens <= 0) throw new RangeError("tokens must be > 0");
    if (tokens > this.maxTokens) {
      throw new RangeError(`Requested tokens (${tokens}) exceeds maxTokens (${this.maxTokens})`);
    }

    while (!this.tryConsume(tokens)) {
      const deficit = tokens - this.currentTokens;
      const intervalsNeeded = Math.ceil(deficit / this.refillRate);
      const elapsed = Date.now() - this.lastRefillTime;
      const waitMs = Math.max(1, intervalsNeeded * this.refillIntervalMs - elapsed);
      await new Promise<void>((resolve) => setTimeout(resolve, waitMs));
    }
  }
}

export default RateLimiter;

