export default RateLimiter;

interface CronSchedule {
  minute: number[];
  hour: number[];
  dayOfMonth: number[];
  month: number[];
  dayOfWeek: number[];
}

type FieldName = keyof CronSchedule;

const FIELD_RANGES: Record<FieldName, readonly [number, number]> = {
  minute:     [0,  59],
  hour:       [0,  23],
  dayOfMonth: [1,  31],
  month:      [1,  12],
  dayOfWeek:  [0,   6],
} as const;

function assertInRange(value: number, min: number, max: number, context: string): void {
  if (!Number.isInteger(value) || value < min || value > max) {
    throw new RangeError(
      `Value ${value} is out of valid range [${min}–${max}] in expression segment "${context}"`
    );
  }
}

function parseSegment(segment: string, min: number, max: number): number[] {
  if (segment.trim() === "") {
    throw new SyntaxError(`Empty segment encountered`);
  }

  // Step: */N or start/N or start-end/N
  if (segment.includes("/")) {
    const parts = segment.split("/");
    if (parts.length !== 2) {
      throw new SyntaxError(`Invalid step expression: "${segment}"`);
    }
    const [rangeExpr, stepStr] = parts;
    const step = Number(stepStr);
    if (!Number.isInteger(step) || step <= 0) {
      throw new RangeError(`Step must be a positive integer in "${segment}"`);
    }

    let start = min;
    let end = max;

    if (rangeExpr !== "*") {
      if (rangeExpr.includes("-")) {
        const bounds = rangeExpr.split("-");
        if (bounds.length !== 2) {
          throw new SyntaxError(`Invalid range in step expression: "${segment}"`);
        }
        start = Number(bounds[0]);
        end   = Number(bounds[1]);
        if (!Number.isInteger(start) || !Number.isInteger(end)) {
          throw new SyntaxError(`Non-integer bounds in step expression: "${segment}"`);
        }
      } else {
        start = Number(rangeExpr);
        if (!Number.isInteger(start)) {
          throw new SyntaxError(`Non-integer start in step expression: "${segment}"`);
        }
      }
    }

    assertInRange(start, min, max, segment);
    assertInRange(end,   min, max, segment);
    if (start > end) {
      throw new RangeError(`Start ${start} exceeds end ${end} in "${segment}"`);
    }

    const values: number[] = [];
    for (let i = start; i <= end; i += step) {
      values.push(i);
    }
    return values;
  }

  // Wildcard
  if (segment === "*") {
    return Array.from({ length: max - min + 1 }, (_, i) => i + min);
  }

  // Range: start-end
  if (segment.includes("-")) {
    const parts = segment.split("-");
    if (parts.length !== 2) {
      throw new SyntaxError(`Invalid range expression: "${segment}"`);
    }
    const start = Number(parts[0]);
    const end   = Number(parts[1]);
    if (!Number.isInteger(start) || !Number.isInteger(end)) {
      throw new SyntaxError(`Non-integer bounds in range: "${segment}"`);
    }
    assertInRange(start, min, max, segment);
    assertInRange(end,   min, max, segment);
    if (start > end) {
      throw new RangeError(`Start ${start} exceeds end ${end} in "${segment}"`);
    }
    return Array.from({ length: end - start + 1 }, (_, i) => i + start);
  }

  // Single integer
  const num = Number(segment);
  if (!Number.isInteger(num)) {
    throw new SyntaxError(`Unrecognised cron field value: "${segment}"`);
  }
  assertInRange(num, min, max, segment);
  return [num];
}

function parseField(field: string, min: number, max: number): number[] {
  if (field.trim() === "") {
    throw new SyntaxError(`Cron field must not be empty`);
  }

  // Comma-separated list — each item is a number, range, step, or wildcard
  const segments = field.split(",");
  if (segments.length > 1) {
    const seen = new Set<number>();
    for (const segment of segments) {
      const trimmed = segment.trim();
      if (trimmed === "") {
        throw new SyntaxError(`Empty item in comma-separated list: "${field}"`);
      }
      for (const v of parseSegment(trimmed, min, max)) {
        seen.add(v);
      }
    }
    return Array.from(seen).sort((a, b) => a - b);
  }

  return parseSegment(field.trim(), min, max);
}

export default function parseCron(expression: string): CronSchedule {
  if (typeof expression !== "string") {
    throw new TypeError(`parseCron expects a string, got ${typeof expression}`);
  }

  const trimmed = expression.trim();
  if (trimmed === "") {
    throw new SyntaxError(`Cron expression must not be empty`);
  }

  const fields = trimmed.split(/\s+/);
  if (fields.length !== 5) {
    throw new SyntaxError(
      `Cron expression must have exactly 5 fields (got ${fields.length}): "${expression}"`
    );
  }

  const fieldNames: FieldName[] = ["minute", "hour", "dayOfMonth", "month", "dayOfWeek"];

  const result = {} as CronSchedule;
  for (let i = 0; i < fieldNames.length; i++) {
    const name = fieldNames[i];
    const [min, max] = FIELD_RANGES[name];
    try {
      result[name] = parseField(fields[i], min, max);
    } catch (err) {
      const message = err instanceof Error ? err.message : String(err);
      throw new (err instanceof RangeError ? RangeError : SyntaxError)(
        `Invalid ${name} field ("${fields[i]}"): ${message}`
      );
    }
  }

  return result;
}

export interface CronFields {
  minute: number[];
  hour: number[];
  dayOfMonth: number[];
  month: number[];
  dayOfWeek: number[];
}

type FieldName = keyof CronFields;

interface FieldConfig {
  readonly min: number;
  readonly max: number;
}

const FIELD_CONFIGS: Record<FieldName, FieldConfig> = {
  minute:     { min: 0,  max: 59 },
  hour:       { min: 0,  max: 23 },
  dayOfMonth: { min: 1,  max: 31 },
  month:      { min: 1,  max: 12 },
  dayOfWeek:  { min: 0,  max: 7  }, // 7 is treated as alias for Sunday (0)
};

const FIELD_NAMES: readonly FieldName[] = [
  "minute", "hour", "dayOfMonth", "month", "dayOfWeek",
];

function makeRange(start: number, end: number): number[] {
  if (start > end) {
    throw new RangeError(`Range start (${start}) must not exceed end (${end})`);
  }
  const result: number[] = [];
  for (let i = start; i <= end; i++) result.push(i);
  return result;
}

function assertInBounds(value: number, min: number, max: number, context: string): void {
  if (!Number.isInteger(value) || value < min || value > max) {
    throw new RangeError(
      `Value ${value} is out of bounds [${min}, ${max}] in expression "${context}"`
    );
  }
}

function parseSegment(expr: string, min: number, max: number): number[] {
  // Step: */n  |  x/n  |  x-y/n
  if (expr.includes("/")) {
    const slashIndex = expr.indexOf("/");
    const left = expr.slice(0, slashIndex);
    const right = expr.slice(slashIndex + 1);

    const step = Number(right);
    if (!Number.isInteger(step) || step < 1) {
      throw new SyntaxError(`Invalid step value "${right}" in "${expr}"`);
    }

    let rangeStart: number;
    let rangeEnd: number;

    if (left === "*") {
      rangeStart = min;
      rangeEnd = max;
    } else if (left.includes("-")) {
      const dashIndex = left.indexOf("-");
      rangeStart = Number(left.slice(0, dashIndex));
      rangeEnd   = Number(left.slice(dashIndex + 1));
      if (!Number.isInteger(rangeStart) || !Number.isInteger(rangeEnd)) {
        throw new SyntaxError(`Invalid range in "${expr}"`);
      }
      assertInBounds(rangeStart, min, max, expr);
      assertInBounds(rangeEnd,   min, max, expr);
      if (rangeStart > rangeEnd) {
        throw new RangeError(`Range start exceeds end in "${expr}"`);
      }
    } else {
      rangeStart = Number(left);
      if (!Number.isInteger(rangeStart)) {
        throw new SyntaxError(`Invalid start value "${left}" in "${expr}"`);
      }
      assertInBounds(rangeStart, min, max, expr);
      rangeEnd = max;
    }

    const stepped: number[] = [];
    for (let i = rangeStart; i <= rangeEnd; i += step) stepped.push(i);
    return stepped;
  }

  // Range: x-y
  if (expr.includes("-")) {
    const dashIndex = expr.indexOf("-");
    const start = Number(expr.slice(0, dashIndex));
    const end   = Number(expr.slice(dashIndex + 1));
    if (!Number.isInteger(start) || !Number.isInteger(end)) {
      throw new SyntaxError(`Invalid range expression "${expr}"`);
    }
    assertInBounds(start, min, max, expr);
    assertInBounds(end,   min, max, expr);
    return makeRange(start, end);
  }

  // Wildcard
  if (expr === "*") {
    return makeRange(min, max);
  }

  // Single integer
  const value = Number(expr);
  if (!Number.isInteger(value)) {
    throw new SyntaxError(`Non-integer value "${expr}"`);
  }
  assertInBounds(value, min, max, expr);
  return [value];
}

function parseField(expr: string, field: FieldName): number[] {
  const { min, max } = FIELD_CONFIGS[field];
  const trimmed = expr.trim();

  if (trimmed.length === 0) {
    throw new SyntaxError(`Empty expression for field "${field}"`);
  }

  // Comma-separated list — split then recurse on each segment
  const parts = trimmed.split(",");
  const seen = new Set<number>();

  for (const part of parts) {
    const cleaned = part.trim();
    if (cleaned.length === 0) {
      throw new SyntaxError(`Empty list element in "${trimmed}" for field "${field}"`);
    }
    for (const v of parseSegment(cleaned, min, max)) {
      seen.add(v);
    }
  }

  // Normalize dayOfWeek: 7 → 0 (both represent Sunday)
  if (field === "dayOfWeek" && seen.has(7)) {
    seen.delete(7);
    seen.add(0);
  }

  return Array.from(seen).sort((a, b) => a - b);
}

export default function parseCron(expression: string): CronFields {
  if (typeof expression !== "string") {
    throw new TypeError(`Expected a string, got ${typeof expression}`);
  }

  const fields = expression.trim().split(/\s+/);

  if (fields.length !== 5) {
    throw new SyntaxError(
      `Cron expression must have exactly 5 fields, got ${fields.length}: "${expression}"`
    );
  }

  const result = {} as CronFields;

  for (let i = 0; i < FIELD_NAMES.length; i++) {
    const name = FIELD_NAMES[i];
    result[name] = parseField(fields[i], name);
  }

  return result;
}

interface CronFields {
  minute: number[];
  hour: number[];
  dayOfMonth: number[];
  month: number[];
  dayOfWeek: number[];
}

const FIELD_RANGES: Record<keyof CronFields, [number, number]> = {
  minute: [0, 59],
  hour: [0, 23],
  dayOfMonth: [1, 31],
  month: [1, 12],
  dayOfWeek: [0, 6],
};

function rangeArray(start: number, end: number): number[] {
  if (start > end) throw new RangeError(`Invalid range: ${start}-${end}`);
  return Array.from({ length: end - start + 1 }, (_, i) => start + i);
}

function assertInRange(value: number, min: number, max: number, context: string): void {
  if (value < min || value > max) {
    throw new RangeError(`Value ${value} out of range [${min}, ${max}] in field "${context}"`);
  }
}

function parseField(expr: string, fieldName: keyof CronFields): number[] {
  const [min, max] = FIELD_RANGES[fieldName];

  // Comma-separated list — split and recurse
  if (expr.includes(",")) {
    const values = expr
      .split(",")
      .flatMap((part) => parseField(part.trim(), fieldName));
    return [...new Set(values)].sort((a, b) => a - b);
  }

  // Wildcard
  if (expr === "*") {
    return rangeArray(min, max);
  }

  // Step: */n or start-end/n
  if (expr.includes("/")) {
    const [rangeExpr, stepStr] = expr.split("/");
    const step = parseInt(stepStr, 10);
    if (isNaN(step) || step < 1) {
      throw new SyntaxError(`Invalid step value "${stepStr}" in field "${fieldName}"`);
    }

    let start: number;
    let end: number;

    if (rangeExpr === "*") {
      start = min;
      end = max;
    } else if (rangeExpr.includes("-")) {
      const [s, e] = rangeExpr.split("-").map((v) => parseInt(v, 10));
      if (isNaN(s) || isNaN(e)) {
        throw new SyntaxError(`Invalid range "${rangeExpr}" in field "${fieldName}"`);
      }
      assertInRange(s, min, max, fieldName);
      assertInRange(e, min, max, fieldName);
      start = s;
      end = e;
    } else {
      const base = parseInt(rangeExpr, 10);
      if (isNaN(base)) {
        throw new SyntaxError(`Invalid step expression "${expr}" in field "${fieldName}"`);
      }
      assertInRange(base, min, max, fieldName);
      start = base;
      end = max;
    }

    const result: number[] = [];
    for (let i = start; i <= end; i += step) {
      result.push(i);
    }
    return result;
  }

  // Range: start-end
  if (expr.includes("-")) {
    const [startStr, endStr] = expr.split("-");
    const start = parseInt(startStr, 10);
    const end = parseInt(endStr, 10);
    if (isNaN(start) || isNaN(end)) {
      throw new SyntaxError(`Invalid range "${expr}" in field "${fieldName}"`);
    }
    assertInRange(start, min, max, fieldName);
    assertInRange(end, min, max, fieldName);
    return rangeArray(start, end);
  }

  // Single number
  const value = parseInt(expr, 10);
  if (isNaN(value)) {
    throw new SyntaxError(`Invalid value "${expr}" in field "${fieldName}"`);
  }
  assertInRange(value, min, max, fieldName);
  return [value];
}

export function parseCron(expression: string): CronFields {
  if (typeof expression !== "string") {
    throw new TypeError("Cron expression must be a string");
  }

  const parts = expression.trim().split(/\s+/);
  if (parts.length !== 5) {
    throw new SyntaxError(
      `Expected 5 fields, got ${parts.length}. Format: "minute hour dayOfMonth month dayOfWeek"`
    );
  }

  const [minuteExpr, hourExpr, domExpr, monthExpr, dowExpr] = parts;

  return {
    minute: parseField(minuteExpr, "minute"),
    hour: parseField(hourExpr, "hour"),
    dayOfMonth: parseField(domExpr, "dayOfMonth"),
    month: parseField(monthExpr, "month"),
    dayOfWeek: parseField(dowExpr, "dayOfWeek"),
  };
}

export default parseCron;

interface CronResult {
  minute: number[];
  hour: number[];
  dayOfMonth: number[];
  month: number[];
  dayOfWeek: number[];
}

const FIELD_RANGES: Record<keyof CronResult, [number, number]> = {
  minute: [0, 59],
  hour: [0, 23],
  dayOfMonth: [1, 31],
  month: [1, 12],
  dayOfWeek: [0, 6],
};

function parseField(field: string, min: number, max: number): number[] {
  const values = new Set<number>();

  const parts = field.split(",");

  for (const part of parts) {
    const trimmed = part.trim();

    // Step value: */n or a-b/n
    if (trimmed.includes("/")) {
      const [rangePart, stepStr] = trimmed.split("/");
      const step = parseInt(stepStr, 10);

      if (isNaN(step) || step <= 0) {
        throw new Error(`Invalid step value: "${stepStr}"`);
      }

      let rangeMin = min;
      let rangeMax = max;

      if (rangePart !== "*") {
        if (rangePart.includes("-")) {
          const [lo, hi] = rangePart.split("-").map((n) => parseInt(n, 10));
          if (isNaN(lo) || isNaN(hi)) {
            throw new Error(`Invalid range in step expression: "${rangePart}"`);
          }
          rangeMin = lo;
          rangeMax = hi;
        } else {
          const start = parseInt(rangePart, 10);
          if (isNaN(start)) {
            throw new Error(`Invalid start value in step expression: "${rangePart}"`);
          }
          rangeMin = start;
        }
      }

      validateRange(rangeMin, min, max, trimmed);
      validateRange(rangeMax, min, max, trimmed);

      for (let i = rangeMin; i <= rangeMax; i += step) {
        values.add(i);
      }
      continue;
    }

    // Wildcard
    if (trimmed === "*") {
      for (let i = min; i <= max; i++) {
        values.add(i);
      }
      continue;
    }

    // Range: a-b
    if (trimmed.includes("-")) {
      const [loStr, hiStr] = trimmed.split("-");
      const lo = parseInt(loStr, 10);
      const hi = parseInt(hiStr, 10);

      if (isNaN(lo) || isNaN(hi)) {
        throw new Error(`Invalid range: "${trimmed}"`);
      }

      validateRange(lo, min, max, trimmed);
      validateRange(hi, min, max, trimmed);

      if (lo > hi) {
        throw new Error(`Range start exceeds end: "${trimmed}"`);
      }

      for (let i = lo; i <= hi; i++) {
        values.add(i);
      }
      continue;
    }

    // Single number
    const num = parseInt(trimmed, 10);
    if (isNaN(num)) {
      throw new Error(`Invalid cron field value: "${trimmed}"`);
    }

    validateRange(num, min, max, trimmed);
    values.add(num);
  }

  return Array.from(values).sort((a, b) => a - b);
}

function validateRange(value: number, min: number, max: number, context: string): void {
  if (value < min || value > max) {
    throw new Error(
      `Value ${value} out of range [${min}, ${max}] in expression: "${context}"`
    );
  }
}

function parseCron(expression: string): CronResult {
  if (typeof expression !== "string") {
    throw new Error("Cron expression must be a string");
  }

  const fields = expression.trim().split(/\s+/);

  if (fields.length !== 5) {
    throw new Error(
      `Expected 5 cron fields, got ${fields.length}: "${expression}"`
    );
  }

  const [minuteField, hourField, dayOfMonthField, monthField, dayOfWeekField] = fields;

  const fieldNames = Object.keys(FIELD_RANGES) as Array<keyof CronResult>;
  const fieldValues = [minuteField, hourField, dayOfMonthField, monthField, dayOfWeekField];

  const result = {} as CronResult;

  for (let i = 0; i < fieldNames.length; i++) {
    const name = fieldNames[i];
    const [min, max] = FIELD_RANGES[name];
    result[name] = parseField(fieldValues[i], min, max);
  }

  return result;
}

export default parseCron;

interface RateLimiterOptions {
  maxTokens: number;
  refillRate: number;
  refillIntervalMs: number;
}

class RateLimiter {
  private readonly maxTokens: number;
  private readonly refillRate: number;
  private readonly refillIntervalMs: number;
  private currentTokens: number;
  private lastRefillTime: number;

  constructor(options: RateLimiterOptions) {
    if (options.maxTokens <= 0) throw new RangeError("maxTokens must be > 0");
    if (options.refillRate <= 0) throw new RangeError("refillRate must be > 0");
    if (options.refillIntervalMs <= 0) throw new RangeError("refillIntervalMs must be > 0");

    this.maxTokens = options.maxTokens;
    this.refillRate = options.refillRate;
    this.refillIntervalMs = options.refillIntervalMs;
    this.currentTokens = options.maxTokens;
    this.lastRefillTime = Date.now();
  }

  private refill(): void {
    const now = Date.now();
    const elapsed = now - this.lastRefillTime;
    const intervalsElapsed = Math.floor(elapsed / this.refillIntervalMs);

    if (intervalsElapsed > 0) {
      const tokensToAdd = intervalsElapsed * this.refillRate;
      this.currentTokens = Math.min(this.maxTokens, this.currentTokens + tokensToAdd);
      this.lastRefillTime += intervalsElapsed * this.refillIntervalMs;
    }
  }

  tryConsume(tokens: number = 1): boolean {
    if (tokens <= 0) throw new RangeError("tokens must be > 0");
    if (tokens > this.maxTokens) return false;

    this.refill();

    if (this.currentTokens >= tokens) {
      this.currentTokens -= tokens;
      return true;
    }

    return false;
  }

  getTokens(): number {
    this.refill();
    return this.currentTokens;
  }

  reset(): void {
    this.currentTokens = this.maxTokens;
    this.lastRefillTime = Date.now();
  }

  async waitForTokens(tokens: number = 1): Promise<void> {
    if (tokens <= 0) throw new RangeError("tokens must be > 0");
    if (tokens > this.maxTokens) {
      throw new RangeError(`Requested tokens (${tokens}) exceeds maxTokens (${this.maxTokens})`);
    }

    while (!this.tryConsume(tokens)) {
      const tokensNeeded = tokens - this.currentTokens;
      const intervalsNeeded = Math.ceil(tokensNeeded / this.refillRate);
      const msUntilRefill = this.refillIntervalMs - (Date.now() - this.lastRefillTime);
      const waitMs = Math.max(0, msUntilRefill) + (intervalsNeeded - 1) * this.refillIntervalMs;

      await new Promise<void>((resolve) => setTimeout(resolve, waitMs));
    }
  }
}

export default RateLimiter;

type CronResult = {
  minute: number[];
  hour: number[];
  dayOfMonth: number[];
  month: number[];
  dayOfWeek: number[];
};

type FieldConfig = {
  min: number;
  max: number;
};

const FIELD_CONFIGS: Record<keyof CronResult, FieldConfig> = {
  minute:     { min: 0,  max: 59 },
  hour:       { min: 0,  max: 23 },
  dayOfMonth: { min: 1,  max: 31 },
  month:      { min: 1,  max: 12 },
  dayOfWeek:  { min: 0,  max: 6  },
};

const range = (from: number, to: number, step = 1): number[] => {
  if (step <= 0) throw new Error(`Step must be positive, got ${step}`);
  const result: number[] = [];
  for (let i = from; i <= to; i += step) result.push(i);
  return result;
};

const parseSegment = (segment: string, config: FieldConfig): number[] => {
  const { min, max } = config;

  // Step value: */n or a-b/n
  if (segment.includes("/")) {
    const [rangePart, stepStr] = segment.split("/");
    const step = parseInt(stepStr, 10);
    if (isNaN(step) || step <= 0) throw new Error(`Invalid step value: "${stepStr}"`);

    if (rangePart === "*") {
      return range(min, max, step);
    }

    if (rangePart.includes("-")) {
      const [startStr, endStr] = rangePart.split("-");
      const start = parseInt(startStr, 10);
      const end = parseInt(endStr, 10);
      if (isNaN(start) || isNaN(end)) throw new Error(`Invalid range: "${rangePart}"`);
      if (start < min || end > max || start > end)
        throw new Error(`Range "${rangePart}" out of bounds [${min}-${max}]`);
      return range(start, end, step);
    }

    throw new Error(`Invalid step expression: "${segment}"`);
  }

  // Wildcard
  if (segment === "*") return range(min, max);

  // Range: a-b
  if (segment.includes("-")) {
    const [startStr, endStr] = segment.split("-");
    const start = parseInt(startStr, 10);
    const end = parseInt(endStr, 10);
    if (isNaN(start) || isNaN(end)) throw new Error(`Invalid range: "${segment}"`);
    if (start < min || end > max || start > end)
      throw new Error(`Range "${segment}" out of bounds [${min}-${max}]`);
    return range(start, end);
  }

  // Single number
  const value = parseInt(segment, 10);
  if (isNaN(value)) throw new Error(`Invalid value: "${segment}"`);
  if (value < min || value > max)
    throw new Error(`Value ${value} out of bounds [${min}-${max}]`);
  return [value];
};

const parseField = (field: string, config: FieldConfig): number[] => {
  const segments = field.split(",");
  const values = new Set<number>();

  for (const segment of segments) {
    const parsed = parseSegment(segment.trim(), config);
    for (const v of parsed) values.add(v);
  }

  return Array.from(values).sort((a, b) => a - b);
};

export const parseCron = (expression: string): CronResult => {
  if (typeof expression !== "string" || expression.trim() === "") {
    throw new Error("Cron expression must be a non-empty string");
  }

  const fields = expression.trim().split(/\s+/);
  if (fields.length !== 5) {
    throw new Error(`Expected 5 fields, got ${fields.length}: "${expression}"`);
  }

  const [minuteField, hourField, dayOfMonthField, monthField, dayOfWeekField] = fields;
  const keys = Object.keys(FIELD_CONFIGS) as (keyof CronResult)[];
  const rawFields = [minuteField, hourField, dayOfMonthField, monthField, dayOfWeekField];

  const result = {} as CronResult;
  for (let i = 0; i < keys.length; i++) {
    const key = keys[i];
    result[key] = parseField(rawFields[i], FIELD_CONFIGS[key]);
  }

  return result;
};

export default parseCron;

interface RateLimiterOptions {
  maxTokens: number;
  refillRate: number;
  refillIntervalMs: number;
}

class RateLimiter {
  private readonly maxTokens: number;
  private readonly refillRate: number;
  private readonly refillIntervalMs: number;
  private currentTokens: number;
  private lastRefillTime: number;

  constructor(options: RateLimiterOptions) {
    if (options.maxTokens <= 0) throw new RangeError("maxTokens must be > 0");
    if (options.refillRate <= 0) throw new RangeError("refillRate must be > 0");
    if (options.refillIntervalMs <= 0) throw new RangeError("refillIntervalMs must be > 0");

    this.maxTokens = options.maxTokens;
    this.refillRate = options.refillRate;
    this.refillIntervalMs = options.refillIntervalMs;
    this.currentTokens = options.maxTokens;
    this.lastRefillTime = Date.now();
  }

  private refill(): void {
    const now = Date.now();
    const elapsed = now - this.lastRefillTime;
    const intervals = Math.floor(elapsed / this.refillIntervalMs);

    if (intervals > 0) {
      const tokensToAdd = intervals * this.refillRate;
      this.currentTokens = Math.min(this.maxTokens, this.currentTokens + tokensToAdd);
      this.lastRefillTime += intervals * this.refillIntervalMs;
    }
  }

  tryConsume(tokens: number = 1): boolean {
    if (tokens <= 0) throw new RangeError("tokens must be > 0");
    if (tokens > this.maxTokens) return false;

    this.refill();

    if (this.currentTokens >= tokens) {
      this.currentTokens -= tokens;
      return true;
    }

    return false;
  }

  getTokens(): number {
    this.refill();
    return this.currentTokens;
  }

  reset(): void {
    this.currentTokens = this.maxTokens;
    this.lastRefillTime = Date.now();
  }

  waitForTokens(tokens: number = 1): Promise<void> {
    if (tokens <= 0) return Promise.reject(new RangeError("tokens must be > 0"));
    if (tokens > this.maxTokens) return Promise.reject(new RangeError("tokens exceeds maxTokens"));

    return new Promise((resolve) => {
      const attempt = (): void => {
        if (this.tryConsume(tokens)) {
          resolve();
          return;
        }

        this.refill();
        const deficit = tokens - this.currentTokens;
        const intervalsNeeded = Math.ceil(deficit / this.refillRate);
        const delay = Math.max(1, intervalsNeeded * this.refillIntervalMs);

        setTimeout(attempt, delay);
      };

      attempt();
    });
  }
}

export default RateLimiter;

export interface RateLimiterOptions {
  maxTokens: number;
  refillRate: number;
  refillIntervalMs: number;
}

interface WaitEntry {
  tokens: number;
  resolve: () => void;
  reject: (err: Error) => void;
}

class RateLimiter {
  private readonly maxTokens: number;
  private readonly refillRate: number;
  private readonly refillIntervalMs: number;
  private currentTokens: number;
  private lastRefillTime: number;
  private readonly waitQueue: WaitEntry[];
  private scheduledCheck: ReturnType<typeof setTimeout> | null;

  constructor(options: RateLimiterOptions) {
    if (!Number.isFinite(options.maxTokens) || options.maxTokens <= 0) {
      throw new RangeError("maxTokens must be a positive finite number");
    }
    if (!Number.isFinite(options.refillRate) || options.refillRate < 0) {
      throw new RangeError("refillRate must be a non-negative finite number");
    }
    if (!Number.isFinite(options.refillIntervalMs) || options.refillIntervalMs <= 0) {
      throw new RangeError("refillIntervalMs must be a positive finite number");
    }

    this.maxTokens = options.maxTokens;
    this.refillRate = options.refillRate;
    this.refillIntervalMs = options.refillIntervalMs;
    this.currentTokens = options.maxTokens;
    this.lastRefillTime = Date.now();
    this.waitQueue = [];
    this.scheduledCheck = null;
  }

  private lazyRefill(): void {
    if (this.refillRate === 0 || this.currentTokens >= this.maxTokens) return;

    const elapsed = Date.now() - this.lastRefillTime;
    if (elapsed < this.refillIntervalMs) return;

    const intervalsElapsed = Math.floor(elapsed / this.refillIntervalMs);
    this.currentTokens = Math.min(
      this.maxTokens,
      this.currentTokens + intervalsElapsed * this.refillRate
    );
    // Advance only by consumed intervals so the remainder carries forward
    this.lastRefillTime += intervalsElapsed * this.refillIntervalMs;
  }

  private msUntilAvailable(tokensNeeded: number): number {
    if (tokensNeeded <= 0) return 0;
    if (this.refillRate === 0) return Infinity;

    const elapsedSinceRefill = Date.now() - this.lastRefillTime;
    const intervalsNeeded = Math.ceil(tokensNeeded / this.refillRate);
    return Math.max(0, intervalsNeeded * this.refillIntervalMs - elapsedSinceRefill);
  }

  private drainQueue(): void {
    if (this.scheduledCheck !== null) {
      clearTimeout(this.scheduledCheck);
      this.scheduledCheck = null;
    }

    while (this.waitQueue.length > 0) {
      this.lazyRefill();

      const head = this.waitQueue[0];

      // Permanently unfulfillable: refillRate is 0 and no tokens coming
      if (this.refillRate === 0 && this.currentTokens < head.tokens) {
        this.waitQueue.shift();
        head.reject(
          new Error(
            `waitForTokens(${head.tokens}) can never be fulfilled: refillRate is 0 ` +
              `and only ${this.currentTokens} token(s) are available`
          )
        );
        continue;
      }

      if (this.currentTokens >= head.tokens) {
        this.currentTokens -= head.tokens;
        this.waitQueue.shift();
        head.resolve();
      } else {
        const waitMs = this.msUntilAvailable(head.tokens - this.currentTokens);
        this.scheduledCheck = setTimeout(() => {
          this.scheduledCheck = null;
          this.drainQueue();
        }, waitMs);
        break;
      }
    }
  }

  tryConsume(tokens: number = 1): boolean {
    if (!Number.isFinite(tokens) || tokens <= 0) {
      throw new RangeError("tokens must be a positive finite number");
    }

    this.lazyRefill();

    if (tokens > this.currentTokens) return false;

    this.currentTokens -= tokens;
    return true;
  }

  getTokens(): number {
    this.lazyRefill();
    return this.currentTokens;
  }

  reset(): void {
    this.currentTokens = this.maxTokens;
    this.lastRefillTime = Date.now();
    // Opportunistically serve any waiting consumers
    if (this.waitQueue.length > 0) {
      this.drainQueue();
    }
  }

  waitForTokens(tokens: number = 1): Promise<void> {
    if (!Number.isFinite(tokens) || tokens <= 0) {
      return Promise.reject(new RangeError("tokens must be a positive finite number"));
    }
    if (tokens > this.maxTokens) {
      return Promise.reject(
        new RangeError(
          `Requested ${tokens} token(s) exceeds the maximum bucket capacity of ${this.maxTokens}`
        )
      );
    }

    return new Promise<void>((resolve, reject) => {
      this.waitQueue.push({ tokens, resolve, reject });
      // Only kick off a drain cycle when nothing is already scheduled;
      // an in-flight timeout will pick up the new entry automatically.
      if (this.scheduledCheck === null) {
        this.drainQueue();
      }
    });
  }
}

export default RateLimiter;

interface CronFields {
  minute: number[];
  hour: number[];
  dayOfMonth: number[];
  month: number[];
  dayOfWeek: number[];
}

const FIELD_RANGES: Record<keyof CronFields, [number, number]> = {
  minute: [0, 59],
  hour: [0, 23],
  dayOfMonth: [1, 31],
  month: [1, 12],
  dayOfWeek: [0, 7],
};

function generateRange(start: number, end: number): number[] {
  if (start > end) throw new RangeError(`Invalid range: ${start}-${end}`);
  return Array.from({ length: end - start + 1 }, (_, i) => start + i);
}

function validateValue(value: number, min: number, max: number, field: string): number {
  if (!Number.isInteger(value) || value < min || value > max) {
    throw new RangeError(`Value ${value} out of range [${min}, ${max}] for field "${field}"`);
  }
  return value;
}

function parseField(expr: string, field: keyof CronFields): number[] {
  const [min, max] = FIELD_RANGES[field];

  if (expr.includes(",")) {
    const values = expr
      .split(",")
      .flatMap((part) => parseField(part.trim(), field));
    return [...new Set(values)].sort((a, b) => a - b);
  }

  if (expr === "*") {
    return generateRange(min, max);
  }

  if (expr.startsWith("*/")) {
    const step = parseInt(expr.slice(2), 10);
    if (isNaN(step) || step <= 0) {
      throw new SyntaxError(`Invalid step value in "${expr}" for field "${field}"`);
    }
    return generateRange(min, max).filter((v) => (v - min) % step === 0);
  }

  if (expr.includes("/")) {
    const [rangePart, stepPart] = expr.split("/");
    const step = parseInt(stepPart, 10);
    if (isNaN(step) || step <= 0) {
      throw new SyntaxError(`Invalid step value in "${expr}" for field "${field}"`);
    }
    const base = parseField(rangePart, field);
    const start = base[0];
    return base.filter((v) => (v - start) % step === 0);
  }

  if (expr.includes("-")) {
    const [startStr, endStr] = expr.split("-");
    const start = parseInt(startStr, 10);
    const end = parseInt(endStr, 10);
    if (isNaN(start) || isNaN(end)) {
      throw new SyntaxError(`Invalid range "${expr}" for field "${field}"`);
    }
    validateValue(start, min, max, field);
    validateValue(end, min, max, field);
    return generateRange(start, end);
  }

  const num = parseInt(expr, 10);
  if (isNaN(num)) {
    throw new SyntaxError(`Invalid expression "${expr}" for field "${field}"`);
  }
  validateValue(num, min, max, field);

  // Normalize dayOfWeek: treat 7 as 0 (Sunday)
  if (field === "dayOfWeek" && num === 7) return [0];
  return [num];
}

function parseCron(expression: string): CronFields {
  if (typeof expression !== "string" || !expression.trim()) {
    throw new SyntaxError("Cron expression must be a non-empty string");
  }

  const parts = expression.trim().split(/\s+/);
  if (parts.length !== 5) {
    throw new SyntaxError(
      `Expected 5 fields, got ${parts.length}: "${expression}"`
    );
  }

  const [minuteExpr, hourExpr, domExpr, monthExpr, dowExpr] = parts;
  const fields = Object.keys(FIELD_RANGES) as (keyof CronFields)[];
  const exprs = [minuteExpr, hourExpr, domExpr, monthExpr, dowExpr];

  const result = {} as CronFields;
  for (let i = 0; i < fields.length; i++) {
    result[fields[i]] = parseField(exprs[i], fields[i]);
  }

  return result;
}

export default parseCron;

interface CronFields {
  minute: number[];
  hour: number[];
  dayOfMonth: number[];
  month: number[];
  dayOfWeek: number[];
}

const FIELD_RANGES: Record<keyof CronFields, [number, number]> = {
