    let end: number;

    if (rangePart === "*") {
      start = min;
      end = max;
    } else if (rangePart.includes("-")) {
      const [s, e] = rangePart.split("-").map(Number);
      if (isNaN(s) || isNaN(e)) throw new SyntaxError(`Invalid range "${rangePart}" in field "${fieldName}"`);
      assertInRange(s, min, max, fieldName);
      assertInRange(e, min, max, fieldName);
      if (s > e) throw new RangeError(`Range start ${s} exceeds end ${e} in field "${fieldName}"`);
      start = s;
      end = e;
    } else {
      start = parseInt(rangePart, 10);
      if (isNaN(start)) throw new SyntaxError(`Invalid step base "${rangePart}" in field "${fieldName}"`);
      assertInRange(start, min, max, fieldName);
      end = max;
    }

    const values: number[] = [];
    for (let i = start; i <= end; i += step) values.push(i);
    return values;
  }

  // Range: start-end
  if (segment.includes("-")) {
    const parts = segment.split("-");
    if (parts.length !== 2) throw new SyntaxError(`Invalid range "${segment}" in field "${fieldName}"`);
    const start = parseInt(parts[0], 10);
    const end = parseInt(parts[1], 10);
    if (isNaN(start) || isNaN(end)) throw new SyntaxError(`Invalid range "${segment}" in field "${fieldName}"`);
    assertInRange(start, min, max, fieldName);
    assertInRange(end, min, max, fieldName);
    if (start > end) throw new RangeError(`Range start ${start} exceeds end ${end} in field "${fieldName}"`);
    return range(start, end);
  }

  // Single number
  const value = parseInt(segment, 10);
  if (isNaN(value)) throw new SyntaxError(`Invalid value "${segment}" in field "${fieldName}"`);
  assertInRange(value, min, max, fieldName);
  return [value];
}

function parseField(expression: string, min: number, max: number, fieldName: string): number[] {
  const segments = expression.split(",");
  const values = segments.flatMap((seg) => parseSegment(seg.trim(), min, max, fieldName));
  return unique(values);
}

function parseCron(expression: string): CronFields {
  if (typeof expression !== "string") {
    throw new TypeError("Cron expression must be a string");
  }

  const fields = expression.trim().split(/\s+/);
  if (fields.length !== 5) {
    throw new SyntaxError(`Expected 5 fields, got ${fields.length}`);
  }

  const [minuteExpr, hourExpr, domExpr, monthExpr, dowExpr] = fields;

  const result: CronFields = {
    minute: parseField(minuteExpr, ...FIELD_RANGES.minute, "minute"),
    hour: parseField(hourExpr, ...FIELD_RANGES.hour, "hour"),
    dayOfMonth: parseField(domExpr, ...FIELD_RANGES.dayOfMonth, "dayOfMonth"),
    month: parseField(monthExpr, ...FIELD_RANGES.month, "month"),
    dayOfWeek: parseField(dowExpr, ...FIELD_RANGES.dayOfWeek, "dayOfWeek"),
  };

  // Normalize dayOfWeek: treat 7 as Sunday (0)
  if (result.dayOfWeek.includes(7)) {
    result.dayOfWeek = unique([...result.dayOfWeek.filter((d) => d !== 7), 0]);
  }

  return result;
}

export default parseCron;

export interface CronExpression {
  minute: number[];
  hour: number[];
  dayOfMonth: number[];
  month: number[];
  dayOfWeek: number[];
}

type FieldName = keyof CronExpression;

interface FieldConfig {
  min: number;
  max: number;
}

const FIELD_ORDER: FieldName[] = [
  "minute",
  "hour",
  "dayOfMonth",
  "month",
  "dayOfWeek",
];

const FIELD_CONFIGS: Record<FieldName, FieldConfig> = {
  minute: { min: 0, max: 59 },
  hour: { min: 0, max: 23 },
  dayOfMonth: { min: 1, max: 31 },
  month: { min: 1, max: 12 },
  dayOfWeek: { min: 0, max: 6 },
};

function generateRange(start: number, end: number): number[] {
  const result: number[] = [];
  for (let i = start; i <= end; i++) result.push(i);
  return result;
}

function validateBounds(
  value: number,
  min: number,
  max: number,
  context: string
): void {
  if (!Number.isInteger(value) || value < min || value > max) {
    throw new RangeError(
      `Value ${value} is out of valid range [${min}, ${max}] in expression segment "${context}"`
    );
  }
}

function parseSegment(segment: string, min: number, max: number): number[] {
  // Wildcard: *
  if (segment === "*") {
    return generateRange(min, max);
  }

  // Step: */N or X-Y/N or X/N
  if (segment.includes("/")) {
    const slashIdx = segment.lastIndexOf("/");
    const left = segment.slice(0, slashIdx);
    const stepStr = segment.slice(slashIdx + 1);
    const step = Number(stepStr);

    if (!Number.isInteger(step) || step <= 0 || String(step) !== stepStr) {
      throw new RangeError(
        `Invalid step value "${stepStr}" in segment "${segment}"`
      );
    }

    let start: number;
    let end: number;

    if (left === "*") {
      start = min;
      end = max;
    } else if (left.includes("-")) {
      const dashIdx = left.indexOf("-");
      const startStr = left.slice(0, dashIdx);
      const endStr = left.slice(dashIdx + 1);
      start = Number(startStr);
      end = Number(endStr);
      if (
        !Number.isInteger(start) ||
        String(start) !== startStr ||
        !Number.isInteger(end) ||
        String(end) !== endStr
      ) {
        throw new RangeError(
          `Invalid range "${left}" in step expression "${segment}"`
        );
      }
    } else {
      start = Number(left);
      if (!Number.isInteger(start) || String(start) !== left) {
        throw new RangeError(
          `Invalid start value "${left}" in step expression "${segment}"`
        );
      }
      end = max;
    }

    validateBounds(start, min, max, segment);
    validateBounds(end, min, max, segment);

    if (start > end) {
      throw new RangeError(
        `Range start ${start} exceeds end ${end} in segment "${segment}"`
      );
    }

    const result: number[] = [];
    for (let i = start; i <= end; i += step) result.push(i);
    return result;
  }

  // Range: X-Y
  if (segment.includes("-")) {
    const dashIdx = segment.indexOf("-");
    const startStr = segment.slice(0, dashIdx);
    const endStr = segment.slice(dashIdx + 1);
    const start = Number(startStr);
    const end = Number(endStr);

    if (
      !Number.isInteger(start) ||
      String(start) !== startStr ||
      !Number.isInteger(end) ||
      String(end) !== endStr
    ) {
      throw new RangeError(`Invalid range expression "${segment}"`);
    }

    validateBounds(start, min, max, segment);
    validateBounds(end, min, max, segment);

    if (start > end) {
      throw new RangeError(
        `Range start ${start} exceeds end ${end} in segment "${segment}"`
      );
    }

    return generateRange(start, end);
  }

  // Plain integer
  const num = Number(segment);
  if (!Number.isInteger(num) || String(num) !== segment) {
    throw new RangeError(`Invalid value "${segment}": not a valid integer`);
  }

  validateBounds(num, min, max, segment);
  return [num];
}

function parseField(raw: string, config: FieldConfig): number[] {
  const { min, max } = config;
  const parts = raw.split(",");

  if (parts.length > 1) {
    const seen = new Set<number>();
    for (const part of parts) {
      const trimmed = part.trim();
      if (trimmed.length === 0) {
        throw new RangeError(
          `Empty element in comma-separated list "${raw}"`
        );
      }
      for (const v of parseSegment(trimmed, min, max)) seen.add(v);
    }
    return [...seen].sort((a, b) => a - b);
  }

  return parseSegment(raw.trim(), min, max).sort((a, b) => a - b);
}

export default function parseCron(expression: string): CronExpression {
  if (typeof expression !== "string") {
    throw new TypeError(
      `parseCron expects a string, received ${typeof expression}`
    );
  }

  const trimmed = expression.trim();

  if (trimmed.length === 0) {
    throw new RangeError("Cron expression must not be empty");
  }

  const fields = trimmed.split(/\s+/);

  if (fields.length !== 5) {
    throw new RangeError(
      `Cron expression must have exactly 5 fields (minute hour dayOfMonth month dayOfWeek), got ${fields.length}`
    );
  }

  const result = {} as CronExpression;

  for (let i = 0; i < FIELD_ORDER.length; i++) {
    const name = FIELD_ORDER[i];
    try {
      result[name] = parseField(fields[i], FIELD_CONFIGS[name]);
    } catch (err) {
      const msg = err instanceof Error ? err.message : String(err);
      throw new RangeError(`Invalid ${name} field "${fields[i]}": ${msg}`);
    }
  }

  return result;
}

interface CronFields {
  minute: number[];
  hour: number[];
  dayOfMonth: number[];
  month: number[];
  dayOfWeek: number[];
}

type FieldName = keyof CronFields;

const FIELD_RANGES: Readonly<Record<FieldName, readonly [number, number]>> = {
  minute:     [0,  59],
  hour:       [0,  23],
  dayOfMonth: [1,  31],
  month:      [1,  12],
  dayOfWeek:  [0,   6],
} as const;

const FIELD_ORDER: readonly FieldName[] = [
  "minute", "hour", "dayOfMonth", "month", "dayOfWeek",
] as const;

function parseStrictInt(raw: string, context: string): number {
  if (!/^\d+$/.test(raw)) {
    throw new RangeError(`Invalid integer "${raw}" in ${context}`);
  }
  const n = Number(raw);
  if (!Number.isSafeInteger(n)) {
    throw new RangeError(`Integer "${raw}" exceeds safe range in ${context}`);
  }
  return n;
}

function assertInRange(
  n: number,
  min: number,
  max: number,
  context: string
): void {
  if (n < min || n > max) {
    throw new RangeError(
      `Value ${n} is out of bounds [${min}–${max}] in ${context}`
    );
  }
}

function expandRange(
  start: number,
  end: number,
  step: number,
  context: string
): number[] {
  if (step <= 0) {
    throw new RangeError(`Step must be a positive integer in ${context}`);
  }
  if (start > end) {
    throw new RangeError(
      `Range start ${start} exceeds end ${end} in ${context}`
    );
  }
  const values: number[] = [];
  for (let i = start; i <= end; i += step) {
    values.push(i);
  }
  return values;
}

function parseSegment(
  segment: string,
  min: number,
  max: number,
  context: string
): number[] {
  // Step expression: */n  or  a-b/n  or  a/n (start from a to max)
  if (segment.includes("/")) {
    const slashParts = segment.split("/");
    if (slashParts.length !== 2) {
      throw new SyntaxError(`Multiple "/" in segment "${segment}" at ${context}`);
    }
    const [lhs, stepRaw] = slashParts;
    const step = parseStrictInt(stepRaw, context);

    if (lhs === "*") {
      return expandRange(min, max, step, context);
    }

    if (lhs.includes("-")) {
      const dashParts = lhs.split("-");
      if (dashParts.length !== 2) {
        throw new SyntaxError(`Invalid range "${lhs}" at ${context}`);
      }
      const start = parseStrictInt(dashParts[0], context);
      const end   = parseStrictInt(dashParts[1], context);
      assertInRange(start, min, max, context);
      assertInRange(end,   min, max, context);
      return expandRange(start, end, step, context);
    }

    // Bare number with step: "5/2" → from 5 to max, step 2
    const start = parseStrictInt(lhs, context);
    assertInRange(start, min, max, context);
    return expandRange(start, max, step, context);
  }

  // Wildcard: expand entire range
  if (segment === "*") {
    return expandRange(min, max, 1, context);
  }

  // Range: a-b
  if (segment.includes("-")) {
    const dashParts = segment.split("-");
    if (dashParts.length !== 2) {
      throw new SyntaxError(`Invalid range "${segment}" at ${context}`);
    }
    const start = parseStrictInt(dashParts[0], context);
    const end   = parseStrictInt(dashParts[1], context);
    assertInRange(start, min, max, context);
    assertInRange(end,   min, max, context);
    return expandRange(start, end, 1, context);
  }

  // Single integer
  const n = parseStrictInt(segment, context);
  assertInRange(n, min, max, context);
  return [n];
}

function parseField(raw: string, field: FieldName): number[] {
  const [min, max] = FIELD_RANGES[field];
  const context = `field "${field}"`;
  const seen = new Set<number>();

  const segments = raw.split(",");
  if (segments.length === 0 || segments.some((s) => s === "")) {
    throw new SyntaxError(`Empty segment in ${context}`);
  }

  for (const segment of segments) {
    for (const v of parseSegment(segment.trim(), min, max, context)) {
      seen.add(v);
    }
  }

  if (seen.size === 0) {
    throw new RangeError(`No valid values produced for ${context}`);
  }

  return Array.from(seen).sort((a, b) => a - b);
}

export default function parseCron(expression: string): CronFields {
  if (typeof expression !== "string") {
    throw new TypeError("Cron expression must be a string");
  }

  const trimmed = expression.trim();
  if (trimmed.length === 0) {
    throw new SyntaxError("Cron expression must not be empty");
  }

  const parts = trimmed.split(/\s+/);
  if (parts.length !== 5) {
    throw new SyntaxError(
      `Cron expression must have exactly 5 fields; got ${parts.length}`
    );
  }

  const result = {} as CronFields;
  for (let i = 0; i < FIELD_ORDER.length; i++) {
    const field = FIELD_ORDER[i];
    result[field] = parseField(parts[i], field);
  }

  return result;
}

interface CronFields {
  minute: number[];
  hour: number[];
  dayOfMonth: number[];
  month: number[];
  dayOfWeek: number[];
}

interface FieldConfig {
  readonly min: number;
  readonly max: number;
  readonly name: keyof CronFields;
}

const FIELD_CONFIGS: readonly FieldConfig[] = [
  { name: "minute", min: 0, max: 59 },
  { name: "hour", min: 0, max: 23 },
  { name: "dayOfMonth", min: 1, max: 31 },
  { name: "month", min: 1, max: 12 },
  { name: "dayOfWeek", min: 0, max: 6 },
];

function parseNonNegativeInt(raw: string, context: string): number {
  const trimmed = raw.trim();
  if (!/^\d+$/.test(trimmed)) {
    throw new Error(
      `Expected a non-negative integer in "${context}", got: "${trimmed}"`
    );
  }
  const n = parseInt(trimmed, 10);
  if (!Number.isSafeInteger(n)) {
    throw new Error(`Integer overflow in "${context}": "${trimmed}"`);
  }
  return n;
}

function assertInRange(
  value: number,
  min: number,
  max: number,
  context: string
): void {
  if (value < min || value > max) {
    throw new Error(
      `Value ${value} is out of range [${min}, ${max}] in "${context}"`
    );
  }
}

function expandSingle(expr: string, config: FieldConfig): number[] {
  const { min, max } = config;

  // ── wildcard ──────────────────────────────────────────────────────────────
  if (expr === "*") {
    return Array.from({ length: max - min + 1 }, (_, i) => min + i);
  }

  // ── step: */N  or  start-end/N  or  start/N ───────────────────────────────
  if (expr.includes("/")) {
    const slashParts = expr.split("/");
    if (slashParts.length !== 2) {
      throw new Error(
        `Step expression must contain exactly one "/": "${expr}"`
      );
    }
    const [rangePart, stepStr] = slashParts;

    if (stepStr === "") {
      throw new Error(`Step value is missing in "${expr}"`);
    }
    const step = parseNonNegativeInt(stepStr, expr);
    if (step === 0) {
      throw new Error(`Step value must be ≥ 1 in "${expr}"`);
    }

    let rangeMin: number;
    let rangeMax: number;

    if (rangePart === "*") {
      rangeMin = min;
      rangeMax = max;
    } else if (rangePart.includes("-")) {
      const dashParts = rangePart.split("-");
      if (dashParts.length !== 2) {
        throw new Error(`Invalid range in step expression: "${expr}"`);
      }
      rangeMin = parseNonNegativeInt(dashParts[0], expr);
      rangeMax = parseNonNegativeInt(dashParts[1], expr);
      if (rangeMin > rangeMax) {
        throw new Error(
          `Range start (${rangeMin}) exceeds end (${rangeMax}) in "${expr}"`
        );
      }
      assertInRange(rangeMin, min, max, expr);
      assertInRange(rangeMax, min, max, expr);
    } else {
      // start/N — step from start to field max
      rangeMin = parseNonNegativeInt(rangePart, expr);
      assertInRange(rangeMin, min, max, expr);
      rangeMax = max;
    }

    const values: number[] = [];
    for (let v = rangeMin; v <= rangeMax; v += step) {
      values.push(v);
    }
    if (values.length === 0) {
      throw new Error(`Step expression "${expr}" produced no values`);
    }
    return values;
  }

  // ── range: start-end ──────────────────────────────────────────────────────
  if (expr.includes("-")) {
    const parts = expr.split("-");
    if (parts.length !== 2) {
      throw new Error(
        `Range expression must contain exactly one "-": "${expr}"`
      );
    }
    const start = parseNonNegativeInt(parts[0], expr);
    const end = parseNonNegativeInt(parts[1], expr);
    if (start > end) {
      throw new Error(
        `Range start (${start}) exceeds end (${end}) in "${expr}"`
      );
    }
    assertInRange(start, min, max, expr);
    assertInRange(end, min, max, expr);
    return Array.from({ length: end - start + 1 }, (_, i) => start + i);
  }

  // ── single number ─────────────────────────────────────────────────────────
  const value = parseNonNegativeInt(expr, expr);
  assertInRange(value, min, max, expr);
  return [value];
}

function parseField(raw: string, config: FieldConfig): number[] {
  const trimmed = raw.trim();
  if (trimmed === "") {
    throw new Error(`Field "${config.name}" is empty`);
  }

  // Comma-separated list — each atom is parsed independently then merged.
  const atoms = trimmed.split(",");
  if (atoms.length > 1) {
    const seen = new Set<number>();
    for (const atom of atoms) {
      const trimmedAtom = atom.trim();
      if (trimmedAtom === "") {
        throw new Error(
          `Empty element in comma list for field "${config.name}": "${raw}"`
        );
      }
      for (const v of expandSingle(trimmedAtom, config)) {
        seen.add(v);
      }
    }
    return Array.from(seen).sort((a, b) => a - b);
  }

  return expandSingle(trimmed, config);
}

export default function parseCron(expression: string): CronFields {
  if (expression == null || typeof expression !== "string") {
    throw new Error("Cron expression must be a non-empty string");
  }

  const trimmed = expression.trim();
  if (trimmed === "") {
    throw new Error("Cron expression must not be blank");
  }

  // Split on any run of whitespace.
  const parts = trimmed.split(/\s+/);
  if (parts.length !== 5) {
    throw new Error(
      `Cron expression requires exactly 5 fields (minute hour dayOfMonth month dayOfWeek), ` +
        `got ${parts.length}: "${expression}"`
    );
  }

  const result = {} as CronFields;

  for (let i = 0; i < FIELD_CONFIGS.length; i++) {
    const config = FIELD_CONFIGS[i];
    try {
      result[config.name] = parseField(parts[i], config);
    } catch (err) {
      throw new Error(
        `Invalid cron field #${i + 1} ("${config.name}"): ${(err as Error).message}`
      );
    }
  }

  return result;
}

export interface CronExpression {
  minute: number[];
  hour: number[];
  dayOfMonth: number[];
  month: number[];
  dayOfWeek: number[];
}

interface FieldConfig {
  min: number;
  max: number;
}

const FIELD_CONFIGS: Record<keyof CronExpression, FieldConfig> = {
  minute:     { min: 0,  max: 59 },
  hour:       { min: 0,  max: 23 },
  dayOfMonth: { min: 1,  max: 31 },
  month:      { min: 1,  max: 12 },
  dayOfWeek:  { min: 0,  max: 6  },
};

const range = (start: number, end: number): number[] =>
  Array.from({ length: end - start + 1 }, (_, i) => start + i);

const clamp = (value: number, min: number, max: number): number =>
  Math.min(Math.max(value, min), max);

const parseSegment = (segment: string, config: FieldConfig): number[] => {
  const { min, max } = config;

  // Wildcard: *
  if (segment === "*") {
    return range(min, max);
  }

  // Step with wildcard: */n
  const stepWildcardMatch = segment.match(/^\*\/(\d+)$/);
  if (stepWildcardMatch) {
    const step = parseInt(stepWildcardMatch[1], 10);
    if (step <= 0) throw new Error(`Invalid step value: ${step}`);
    const values: number[] = [];
    for (let i = min; i <= max; i += step) values.push(i);
    return values;
  }

  // Range with optional step: n-m or n-m/s
  const rangeMatch = segment.match(/^(\d+)-(\d+)(?:\/(\d+))?$/);
  if (rangeMatch) {
    const start = parseInt(rangeMatch[1], 10);
    const end   = parseInt(rangeMatch[2], 10);
    const step  = rangeMatch[3] ? parseInt(rangeMatch[3], 10) : 1;

    if (start < min || start > max) throw new Error(`Value ${start} out of range [${min}-${max}]`);
    if (end   < min || end   > max) throw new Error(`Value ${end} out of range [${min}-${max}]`);
    if (start > end) throw new Error(`Range start ${start} exceeds end ${end}`);
    if (step  <= 0)  throw new Error(`Invalid step value: ${step}`);

    const values: number[] = [];
    for (let i = start; i <= end; i += step) values.push(i);
    return values;
  }

  // Plain number
  const numMatch = segment.match(/^(\d+)$/);
  if (numMatch) {
    const value = parseInt(numMatch[1], 10);
    if (value < min || value > max) throw new Error(`Value ${value} out of range [${min}-${max}]`);
    return [value];
  }

  throw new Error(`Invalid cron segment: "${segment}"`);
};

const parseField = (field: string, config: FieldConfig): number[] => {
  const parts = field.split(",");
  const values = new Set<number>();

  for (const part of parts) {
    const parsed = parseSegment(part.trim(), config);
    for (const v of parsed) values.add(clamp(v, config.min, config.max));
  }

  return Array.from(values).sort((a, b) => a - b);
};

const parseCron = (expression: string): CronExpression => {
  const fields = expression.trim().split(/\s+/);

  if (fields.length !== 5) {
    throw new Error(`Expected 5 fields, got ${fields.length}: "${expression}"`);
  }

  const [minuteField, hourField, domField, monthField, dowField] = fields;
  const fieldOrder = Object.keys(FIELD_CONFIGS) as (keyof CronExpression)[];

  return {
    minute:     parseField(minuteField, FIELD_CONFIGS.minute),
    hour:       parseField(hourField,   FIELD_CONFIGS.hour),
    dayOfMonth: parseField(domField,    FIELD_CONFIGS.dayOfMonth),
    month:      parseField(monthField,  FIELD_CONFIGS.month),
    dayOfWeek:  parseField(dowField,    FIELD_CONFIGS.dayOfWeek),
  };
};

export default parseCron;
